INSERT INTO `club` (`id`, `meta_title`, `meta_keywords`, `meta_description`, `tel`, `address`, `url_appstore`, `url_googleplay`, `url_windowsmarket`, `url_vk`, `url_facebook`, `url_instagram`, `url_ok`, `pdf`, `pdf2`, `pdf3`, `email`, `start_work`, `start_work_weekend`, `url_3d_tour`, `start_year`, `square`, `img`, `img2`, `title`, `content`, `main_content`, `club_content`, `content_cards`, `coordinates`, `legal`, `privacy`, `legal_title`, `privacy_title`, `contacts_title`) VALUES
(1, 'Фитнес клуб Extra Sport', '', '', '+7 (812) 207-50-07', 'Санкт-Петербург, ул. Матроса Железняка, 57А', 'https://itunes.apple.com/ru/app/extra-sport/id1462883244?mt=8', 'https://play.google.com/store/apps/details?id=air.com.extrasport', NULL, 'https://vk.com/extrasport_ru', '', '', 'https://youtu.be/x1FajeBpLRQ', NULL, 'pravila-1556296026.pdf', NULL, 'matros@extrasport.ru', 'с 07:00 до 23:00', 'с 09:00 до 22:00', '', '2019-04-09', 0, '', NULL, 'EXTRASPORT «МАТРОСА ЖЕЛЕЗНЯКА»', '<p>Extra Sport на Матроса Железняка&nbsp;расположен в Приморском районе, недалеко от метро Пионерская и Чёрная речка, а также имеет отличную транспортную доступность.&nbsp;<br />\r\n<br />\r\n<strong><a href=\"https://youtu.be/x1FajeBpLRQ\">Видео-презентация клуба</a></strong><br />\r\n<br />\r\nВ клубе работают опытные инструкторы высокой квалификации, каждый из которых является профессионалом в своей области. В залах установлено современное спортивное оборудование, благодаря чему повышаются комфорт и эффективность тренировок. Возможность посещать занятия разных направлений, совмещать групповые программы с самостоятельными тренировками в тренажерном зале, дополнять силовые упражнения с растяжкой мышц позволяет достигать максимальных результатов.</p>\r\n', '<h1><br />\r\nПредставляем вашему вниманию - <strong>НОВЫЙ</strong>&nbsp;фитнес клуб площадью 1200&nbsp;кв.метров.<br />\r\nExtra Sport на Матроса Железняка&nbsp;расположен в Приморском районе, недалеко от метро Пионерская и Чёрная речка,&nbsp;имеет отличную транспортную доступность.&nbsp;<br />\r\n<br />\r\n<a href=\"https://www.youtube.com/watch?v=x1FajeBpLRQ&amp;ab_channel=ExtraPitersport\">Видео презентация клуба</a><br />\r\n<br />\r\n&nbsp;</h1>\r\n', '<p>&nbsp; &nbsp; &nbsp; Добро пожаловать в фитнес клуб у метро Пионерская/Чёрная речка, где каждый найдет направление по душе!&nbsp;<br />\r\n&nbsp;<br />\r\n&nbsp; &nbsp; &nbsp; ExtraSport на Матроса Железняка&mdash; это не просто тренажерный зал с профессиональным оборудованием, но и кардио студия, студия сайкл , йога студия, студия TRX, аэробный зал с ежедневными групповыми уроками под чутким руководством высококвалифицированных тренеров, сетка расписания которых превышает 30 направлений и восхищает своим разнообразием, а профессиональные тренеры мотивируют вас на достижение результатов, которые еще какое-то время назад казались вам невозможными!&nbsp;<br />\r\n&nbsp;<br />\r\n&nbsp; &nbsp; &nbsp; Мы всегда рады не только взрослым, но и детям. Для них у нас есть детская комната с няней, где вашему ребенку не будет скучно, пока родители тренируются, а также и детский фитнес для юных спортсменов от полутора лет!&nbsp;<br />\r\n&nbsp;<br />\r\n&nbsp; &nbsp; &nbsp; &nbsp;После насыщенных тренировок релаксации поспособствует турецкая парная и оборудование для контрастного душа! К вашим услугам солярий, фитнес бар, салон красоты.<br />\r\n&nbsp;<br />\r\nКлуб находится в Приморском районе и расположен в непосредственной близости от станции метро Пионерская, чёрная речка и Удельная.&nbsp;<br />\r\n&nbsp;<br />\r\nБудьте с ExtraSport &mdash; стремитесь к совершенству вместе с нами!</p>\r\n', NULL, '60.000282385920386,30.31915328559853', '<p>При заполнении форм обратной связи на нашем сайте вы предоставляете свою персональную информацию такую как: имя, номер телефона и адрес электронной почты. Наша политика конфиденциальности объясняет, для чего мы используем данную информацию и какие меры безопасности принимаются для защиты ваших личных данных.</p>\r\n\r\n<p>Мы получаем персональную информацию:</p>\r\n\r\n<p>&mdash; когда вы заполняете форму обратной связи;</p>\r\n\r\n<p>&mdash; когда сохраняются файлы &laquo;cookie&raquo;. Файл &laquo;cookie&raquo; сохраняется на вашем компьютере</p>\r\n\r\n<p>В момент посещения какой-либо страницы сайта. С его помощью определяется ваш браузер, также &laquo;cookie&raquo; помогает запоминать ваши настройки.</p>\r\n\r\n<p>Мы используем персональную информацию:</p>\r\n\r\n<p>&mdash; чтобы повысить качество предоставляемых услуг;</p>\r\n\r\n<p>&mdash; чтобы установить с вами обратную связь, обработать вашу заявку;</p>\r\n\r\n<p>&mdash; чтобы улучшить функционал нашего сайта;</p>\r\n\r\n<p>&mdash; чтобы сообщить вам самые последние новости и сведения о новых акциях.</p>\r\n\r\n<p>Мы защищаем персональную информацию:</p>\r\n\r\n<p>Мы не раскрываем вашу персональную информацию третьим лицам. Персональные данные могут быть переданы лицам, не связанным с нашим сайтом, в том случае, если этого требует действующее законодательство Российской Федерации.</p>\r\n\r\n<p>Для защиты ваших данных мы стараемся принять все необходимые меры: используем безопасный сервер, доступ ко всей информации имеет ограниченное число лиц.</p>\r\n\r\n<p>Сторонние организации</p>\r\n\r\n<p>Наш сайт может содержать ссылки на сайты сторонних организаций, неподконтрольных нам и имеющих собственную политику конфиденциальности. В связи с этим, мы не несем ответственности за действия данных ресурсов.</p>\r\n\r\n<p>Согласие пользователя</p>\r\n\r\n<p>Используя наш сайт, вы выражаете согласие с действующей политикой конфиденциальности и разрешаете обработку ваших персональных данных, согласно закону &laquo;О персональных данных&raquo; № 152 ФЗ РФ.</p>\r\n', '<p>При заполнении форм обратной связи на нашем сайте вы предоставляете свою персональную информацию такую как: имя, номер телефона и адрес электронной почты. Наша политика конфиденциальности объясняет, для чего мы используем данную информацию и какие меры безопасности принимаются для защиты ваших личных данных.</p>\r\n\r\n<p>Мы получаем персональную информацию:</p>\r\n\r\n<p>&mdash; когда вы заполняете форму обратной связи;</p>\r\n\r\n<p>&mdash; когда сохраняются файлы &laquo;cookie&raquo;. Файл &laquo;cookie&raquo; сохраняется на вашем компьютере</p>\r\n\r\n<p>В момент посещения какой-либо страницы сайта. С его помощью определяется ваш браузер, также &laquo;cookie&raquo; помогает запоминать ваши настройки.</p>\r\n\r\n<p>Мы используем персональную информацию:</p>\r\n\r\n<p>&mdash; чтобы повысить качество предоставляемых услуг;</p>\r\n\r\n<p>&mdash; чтобы установить с вами обратную связь, обработать вашу заявку;</p>\r\n\r\n<p>&mdash; чтобы улучшить функционал нашего сайта;</p>\r\n\r\n<p>&mdash; чтобы сообщить вам самые последние новости и сведения о новых акциях.</p>\r\n\r\n<p>Мы защищаем персональную информацию:</p>\r\n\r\n<p>Мы не раскрываем вашу персональную информацию третьим лицам. Персональные данные могут быть переданы лицам, не связанным с нашим сайтом, в том случае, если этого требует действующее законодательство Российской Федерации.</p>\r\n\r\n<p>Для защиты ваших данных мы стараемся принять все необходимые меры: используем безопасный сервер, доступ ко всей информации имеет ограниченное число лиц.</p>\r\n\r\n<p>Сторонние организации</p>\r\n\r\n<p>Наш сайт может содержать ссылки на сайты сторонних организаций, неподконтрольных нам и имеющих собственную политику конфиденциальности. В связи с этим, мы не несем ответственности за действия данных ресурсов.</p>\r\n\r\n<p>Согласие пользователя</p>\r\n\r\n<p>Используя наш сайт, вы выражаете согласие с действующей политикой конфиденциальности и разрешаете обработку ваших персональных данных, согласно закону &laquo;О персональных данных&raquo; № 152 ФЗ РФ.</p>\r\n\r\n<p>&nbsp;</p>\r\n', 'Правовая информация', 'Политика конфиденциальности', 'Контакты');
