INSERT INTO `club_cards` (`id`, `status`, `position`, `title`, `comment`, `icon`, `img`, `content`, `color`, `code_button`, `price`, `created_at`, `updated_at`) VALUES
(1, 10, 10, 'Годовой абонемент', 'Безлимитный год тренажёрного зала 15900', '', '6m+bass-1556297643.jpg', '<p>При покупке абонемента безлимитного фитнеса с бассейном на Год вы получаете основные услуги:</p>\r\n\r\n<p>&nbsp;- Год безлимитного фитнеса</p>\r\n\r\n<p>- Неограниченное количество визитов, без ограничений по времени</p>\r\n\r\n<p>- Полный доступ во все зоны клуба* (силовая, игровая, кардио, групповые занятия, студия сайкл &nbsp;и пр)</p>\r\n\r\n<p>&nbsp;- Турецкая парная</p>\r\n\r\n<p>&nbsp;- Ринг</p>\r\n\r\n<p>&nbsp;- Бассейн</p>\r\n\r\n<p>&nbsp;- Детская комната с воспитателем</p>\r\n\r\n<p>Дополнительные услуги:</p>\r\n\r\n<p>- Тренерскую поддержку и возможность персональных занятий</p>\r\n\r\n<p>&nbsp;- Фитнес-бар</p>\r\n\r\n<p>&nbsp;- Косметологический кабинет</p>\r\n\r\n<p>&nbsp;- Солярий</p>\r\n\r\n<p>&nbsp;- Детский фитнес</p>\r\n\r\n<p>&nbsp;- Аквааэробика</p>\r\n\r\n<p>Бронируйте ваш абонемент прямо сейчас по телефону: +7 (812) 207-50-07</p>\r\n\r\n<p>Подробности акции уточняйте в отделе продаж.</p>\r\n', NULL, '', NULL, '2019-04-16 08:08:54', '2022-01-20 12:50:51'),
(2, 10, 20, '20 занятий йогой.', 'Студия йоги 20 занятий 9800', '', 'sport-fitnes-fon-vzglyad-devushka-1338996-1601020490.jpg', '<p>При покупке абонемента безлимитного фитнеса на полгода вы получаете основные услуги:</p>\r\n\r\n<p>&nbsp;- Полгода безлимитного фитнеса</p>\r\n\r\n<p>- Неограниченное количество визитов, без ограничений по времени</p>\r\n\r\n<p>- Полный доступ во все зоны клуба* (силовая, игровая, кардио, групповые занятия, студия сайкл &nbsp;и пр)</p>\r\n\r\n<p>&nbsp;- Турецкая парная</p>\r\n\r\n<p>&nbsp;- Ринг</p>\r\n\r\n<p>&nbsp;- Детская комната с воспитателем</p>\r\n\r\n<p>Дополнительные услуги:</p>\r\n\r\n<p>- Тренерскую поддержку и возможность персональных занятий</p>\r\n\r\n<p>&nbsp;- Фитнес-бар</p>\r\n\r\n<p>&nbsp;- Косметологический кабинет</p>\r\n\r\n<p>&nbsp;- Солярий</p>\r\n\r\n<p>&nbsp;- Детский фитнес</p>\r\n\r\n<p>&nbsp;- Аквааэробика</p>\r\n\r\n<p>Бронируйте ваш абонемент прямо сейчас по телефону: +7 (812) 207-50-07</p>\r\n\r\n<p>Подробности акции уточняйте в отделе продаж.</p>\r\n', NULL, '', NULL, '2019-04-16 08:11:27', '2022-01-20 12:51:03'),
(3, 0, 30, '12 месяцев', 'Год 100 виз аэробных занятий 11900', '', '1god+bass-1556297893.jpg', '<p>При покупке абонемента безлимитного фитнеса с бассейном на год вы получаете основные услуги:</p>\r\n\r\n<p>&nbsp;- Год безлимитного фитнеса</p>\r\n\r\n<p>- Неограниченное количество визитов, без ограничений по времени</p>\r\n\r\n<p>- Полный доступ во все зоны клуба* (силовая, игровая, кардио, групповые занятия, студия сайкл &nbsp;и пр)</p>\r\n\r\n<p>&nbsp;- Турецкая парная</p>\r\n\r\n<p>&nbsp;- Бассейн</p>\r\n\r\n<p>&nbsp;- Ринг</p>\r\n\r\n<p>&nbsp;- Детская комната с воспитателем</p>\r\n\r\n<p>Дополнительные услуги:</p>\r\n\r\n<p>- Тренерскую поддержку и возможность персональных занятий</p>\r\n\r\n<p>&nbsp;- Фитнес-бар</p>\r\n\r\n<p>&nbsp;- Косметологический кабинет</p>\r\n\r\n<p>&nbsp;- Солярий</p>\r\n\r\n<p>&nbsp;- Детский фитнес</p>\r\n\r\n<p>&nbsp;- Аквааэробика</p>\r\n\r\n<p>Бронируйте ваш абонемент прямо сейчас по телефону: +7 (812) 207-50-07</p>\r\n\r\n<p>Подробности акции уточняйте в отделе продаж.</p>\r\n', NULL, '', NULL, '2019-04-17 18:01:12', '2022-02-17 15:05:15'),
