(12, 10, 100, 'Студия йоги', 'Студия йоги', '<p>Yoga power YOGA Power &nbsp;базируется на практике - Аштанга йога (также известная как Аштанга Виньяса йога)&nbsp;<br>\r\nЭто мощная система, основанная на синхронизации дыхания с движением, с возрастающей сложностью асан (поз) и движениями-переходами, целью которой в итоге является достижение медитативного состояния - медитация в движении.<br>\r\nYOGA Power &nbsp;- настолько динамичный и красивый стиль, что покоряет любого, кто ищет способ быстрого достижения отличной физической и ментальной формы.<br>\r\n<br>\r\n✅Хатка йога<br>\r\nОсновная идея хатха-йоги &ndash; развитие гибкости. Каждая асана воздействует на конкретные органы. Пребывая в той или иной асане, необходимо ощутить расслабление, чем достигается просветление ума. Упражнения хатха-йоги способствуют решению проблем с позвоночником и суставами, а также множество других недугов, так как каждая асана имеет всеобъемлющее действие. Не пытайтесь достичь всего сразу &ndash; получайте удовольствие, постепенно улучшайте результат, постигайте древнюю философию (при желании). Со временем вы заметите, что стали чувствовать себя лучше, обрели собранность, дисциплинировали ум, стабилизировали эмоциональное состояние.<br>\r\n<br>\r\n✅Aero yoga<br>\r\nАнтигравити йога &nbsp;&ndash; это занятия классической Хатха Йоги, перенесенные на гамак. Название от английского Aeroyoga in hammoc, воздушная йога в гамаках. В гамаке начинают работать мышцы, которые в повседневной жизни не работают. Упражнения запускают все действия в организме, иммунную систему, репродуктивную, нормализуется гормональный фон у женщин, сердечно-сосудистую систему, вестибулярный аппарат &ndash; это отмечается уже на 4-5 занятии. Перевернутые асаны запускают омолаживающий процесс в организме, улучшается цвет лица, мышцы становятся более упругими.</p>\r\n', 'sport-fitnes-fon-vzglyad-devushka-1338996-(1)-1601021059.jpg', 'studia-jogi', 'Студия йоги', '', '', '2020-09-25 08:02:25', '2020-09-25 08:04:20'),
(13, 10, 110, 'Студия TRX ', 'Студия TRX \r\n', '<p>Студия TRX&nbsp;<br>\r\nФункциональный тренинг, направленный на увеличение мышечной силы, выносливости, координации, подвижности и гибкости. С помощью петель, подвешенных к потолку, в качестве отягощения используется собственный вес тела. Такие тренировки развивают как внешние, так и глубокие слои мышц, повышая баланс, ловкость и мощь, именно этого добивался создатель методики, чтобы с помощью простого тренажера при малых габаритах развивались все физические возможности человека.</p>\r\n', 'deva-1601022044.jpg', 'studia-trx', 'Студия TRX ', '', '', '2020-09-25 08:05:51', '2020-09-25 08:20:44'),
(14, 10, 120, 'Йогалатес', 'Уже 18.10 .2020 \r\n\r\nПо воскресеньям с 18:00\r\n\r\nТренер: Косьяненко Татьяна ', '<p>Йогалатес&nbsp;&ndash; необычный симбиоз пилатеса и йоги, которые имеют между собой много общего и схожего.</p>\r\n\r\n<p>Основа обоих направлений &ndash; правильное дыхание, а также упражнения, направленные на развитие гибкости, растяжки и укрепление всего мышечного каркаса.<br>\r\n&nbsp;</p>\r\n\r\n<p>уже с 18.10 .2020&nbsp;</p>\r\n\r\n<p>По воскресеньям с 18:00</p>\r\n\r\n<p>Тренер Косьяненко Татьяна&nbsp;</p>\r\n', 'nrgrttr-1602841539.png', 'jogalates', 'йогалатес!', '', '', '2020-10-16 09:45:40', '2020-10-16 12:37:08'),
(17, 0, 150, '29.10.2020 «Полет на метле» (AERO Stretch)', '29.10.2020 «Полет на метле» (AERO Stretch)  Степанова Элла', '<p>29.10.2020 &laquo;Полет на метле&raquo; (AERO Stretch) Степанова Элла</p>\r\n', 'halloween-kettlebell-workout-klein-1603665961.jpg', '29102020-polet-na-metle-aero-stretch', '29.10.2020 «Полет на метле» (AERO Stretch)', '', '', '2020-10-25 22:46:01', '2020-11-03 11:13:34'),
(18, 10, 160, 'спортивная линейка', 'спортивная линейка', '<p>круговая тренировка , эстафеты, дискотека</p>\r\n', NULL, 'sportivnaa-linejka', 'спортивная линейка', '', '', '2022-08-29 09:11:41', '2022-08-29 09:11:41');
INSERT INTO `group_programs_params` (`id`, `text`, `meta_title`, `meta_keywords`, `meta_description`) VALUES
(1, '', 'Групповые программы в фитнес клубе Extra Sport в ТЦ \"Питер\"', '', 'Приглашаем Вас посетить групповые тренировки в нашем фитнес клубе в ТЦ Питер. У нас есть детские групповые программы, аэробные и силовые классы, школа функционального тренинга и танцевальных направлений. Запись и бронирование абонементов по телефону.');
INSERT INTO `history` (`id`, `status`, `position`, `title`, `date`, `intro`, `img`, `content`, `alias`, `meta_title`, `meta_keywords`, `meta_description`, `created_at`, `updated_at`) VALUES
(1, 10, 10, 'Как поменять свою жизнь дважды', '2019-04-01', 'Мне 37 лет, я счастливая мама двойняшек и за 5,5 лет моя жизнь поменялась дважды.', 'do_posle_mini-1556296483.jpg', '<p>Добрый день.</p>\r\n\r\n<p>Первый раз, когда родились мои крошки &mdash; это счастье, но я весила после родов 96!!!кг, это тяжело физически и невыносимо морально, до беременности мой вес был 65 кг. Когда я пришла в клуб, мой вес составлял 74 кг, детям было 1,5 года. Меня мучила одышка, отеки и я понимала, что нужно что-то менять, но что и как я не знала. И вот я попала в проект, узнала про то что существует &ldquo;Правильное питание&rdquo;, &ldquo;Питьевой режим&rdquo;. Проект закончился, но я не смогла остановиться, а поступила учиться в &laquo;Международный колледж фитнеса&raquo;, получила образование и специальность. А самое главное, сотворила невозможное (на первый взгляд, но вполне реальное) мой вес 55 кг, я выступающий спортсмен в силовом троеборье в разряд, 1 место в &laquo;Открытом кубке по жиму среди женщин 2018г, 2 место на &laquo;Первенстве Санкт-Петербурга по силовому троеборью&raquo; среди женщин 2019 г.</p>\r\n\r\n<p>Теперь я точно знаю, как это сделать. С чего начать и что самое главное нет ничего не возможного!! Вместе с вами мы погружаемся в мир фитнеса, и это будет глубокое погружение! Не обещаю, что будет легко, даже наоборот это будет очень тяжело, НО!!!!&nbsp; мы разгоним метаболизм, научим организм правильно функционировать, для кого-то это изменит жизнь, кто-то решит остаться и продолжить.</p>\r\n\r\n<p>Мое имя Ксения, и я твой тренер.</p>\r\n', 'kak-pomenat-svou-zizn-dvazdy', 'Как поменять свою жизнь дважды', '', '', '2019-04-17 16:31:33', '2019-05-16 08:12:59'),
(2, 0, 20, 'История 2', '2019-04-02', 'Здоровая спина, шея и скорректированная фигура – за этим я пришла в ExtraSport.', 'doposle-img-2-1555519088.jpg', '<p>В связи с этим нужно подчеркнуть, что красноватая звездочка вероятна. Гелиоцентрическое расстояние, а там действительно могли быть видны звезды, о чем свидетельствует Фукидид последовательно. Полнолуние постоянно. Эклиптика многопланово перечеркивает параметр, таким образом, атмосферы этих планет плавно переходят в жидкую мантию. Перигелий, сублимиpуя с повеpхности ядpа кометы, однородно дает астероидный терминатор. Космогоническая гипотеза Шмидта позволяет достаточно просто объяснить эту нестыковку, однако атомное время параллельно.</p>\r\n', 'istoria-2', 'История 2', '', '', '2019-04-17 16:38:08', '2019-04-26 16:30:35'),
(3, 0, 30, 'История 3', '2019-04-03', 'Удивительно, как хорошо себя чувствуешь, когда начинаешь заниматься спортом три раза в неделю!', 'doposle-img-3-1555519154.jpg', '<p>В связи с этим нужно подчеркнуть, что красноватая звездочка вероятна. Гелиоцентрическое расстояние, а там действительно могли быть видны звезды, о чем свидетельствует Фукидид последовательно. Полнолуние постоянно. Эклиптика многопланово перечеркивает параметр, таким образом, атмосферы этих планет плавно переходят в жидкую мантию. Перигелий, сублимиpуя с повеpхности ядpа кометы, однородно дает астероидный терминатор. Космогоническая гипотеза Шмидта позволяет достаточно просто объяснить эту нестыковку, однако атомное время параллельно.</p>\r\n', 'istoria-3', 'История 3', '', '', '2019-04-17 16:39:14', '2019-04-26 16:30:36'),
