INSERT INTO `jobs` (`id`, `status`, `position`, `title`, `content`, `alias`, `meta_title`, `meta_keywords`, `meta_description`, `created_at`, `updated_at`) VALUES
(1, 10, 40, 'Инструктор тренажерного зала', '<p>Требуемый опыт работы: 1&ndash;3 года</p>\r\n\r\n<p>Полная занятость, сменный график</p>\r\n\r\n<p>Обязанности:</p>\r\n\r\n<p>активная работа с клиентами клуба;</p>\r\n\r\n<p>проведение персональных тренировок;</p>\r\n\r\n<p><br>\r\nТребования:</p>\r\n\r\n<p>тренер по атлетизму;</p>\r\n\r\n<p>опыт работы не менее года;</p>\r\n\r\n<p>отличное владение профессиональными навыками проведения персональных тренировок;</p>\r\n\r\n<p>презентабельный внешний вид;</p>\r\n\r\n<p>дисциплина&sbquo; организованность;</p>\r\n\r\n<p>наличие дипломов&sbquo; сертификатов;</p>\r\n\r\n<p>Условия:</p>\r\n\r\n<p>оформление по ТК РФ;</p>\r\n\r\n<p>работа в большой&sbquo; сильной компании;</p>\r\n\r\n<p>сменный график работы;</p>\r\n', 'personalnyj-trener', 'Персональный тренер', '', '', '2019-04-12 09:27:48', '2019-11-15 09:22:42'),
(2, 10, 10, 'Менеджер по продажам в фитнес-клуб', '<p>Требуемый опыт работы: 1&ndash;3 года</p>\r\n\r\n<p>Полная занятость, сменный график</p>\r\n\r\n<p>Уважаемый кандидат! Ждём от Вас резюме с фото :)</p>\r\n\r\n<p>Обязанности:</p>\r\n\r\n<p>Презентация клуба</p>\r\n\r\n<p>Заключение контрактов</p>\r\n\r\n<p>Консультации клиентов по телефону</p>\r\n\r\n<p>Работа с претензиями</p>\r\n\r\n<p>Работа с клиентской базой, которую предоставляет фитнес-клуб (не холодные звонки!)</p>\r\n\r\n<p><br>\r\nТребования:</p>\r\n\r\n<p>Опыт активных продаж в сфере услуг от 1 года (желательно)</p>\r\n\r\n<p>Опыт работы в call-центре приветствуется</p>\r\n\r\n<p>Отличное знание ПК</p>\r\n\r\n<p>Грамотная речь</p>\r\n\r\n<p>Нацеленность на результат</p>\r\n\r\n<p>Условия:</p>\r\n\r\n<p>Дружный коллектив</p>\r\n\r\n<p>Просьба обратить внимание, что окладная часть отсутствует, заработная строится от индивидуальных продаж менеджера (от процента)</p>\r\n\r\n<p>При выполнении плана з/п от 40 000р</p>\r\n\r\n<p>Карьерный рост</p>\r\n\r\n<p>Бесплатное корпоративное обучение</p>\r\n\r\n<p>Оформление по ТК РФ</p>\r\n\r\n<p>График работы 2/2 с 10:00 до 22:00</p>\r\n\r\n<p>Бесплатная клубная карта на занятие фитнесом</p>\r\n', 'massazist', 'Массажист', '', '', '2019-04-17 15:56:32', '2019-11-15 09:22:17'),
(3, 0, 50, 'Тренер по единоборствам', '<p>Требуемый опыт работы: 1&ndash;3 года</p>\r\n\r\n<p>Полная занятость, полный день</p>\r\n\r\n<p>Обязанности:</p>\r\n\r\n<p>проведение персональных тренировок по единоборству;</p>\r\n\r\n<p>проведение групповых тренировок.</p>\r\n\r\n<p>Требования:</p>\r\n\r\n<p>наличие высшего образования (спортивное/медицинское/педагогическое)</p>\r\n\r\n<p>опыт работы тренером от 1 года.</p>\r\n\r\n<p>приветствуется наличие сертификатов;</p>\r\n\r\n<p>владение методиками проведения групповых программ;</p>\r\n\r\n<p>Условия:</p>\r\n\r\n<p>график и уровень заработной платы обсуждается на собеседование</p>\r\n\r\n<p>проведение занятий по адресам: м.Московская, ул.Типанова д.21 ТРК &quot;Питер&quot;.</p>\r\n\r\n<p>бесплатная карта в фитнес клуб</p>\r\n', 'administrator', 'Администратор', '', '', '2019-04-17 17:36:48', '2019-11-15 09:22:47'),
(4, 10, 20, 'Администратор фитнес-клуба', '<p>Требуемый опыт работы: не требуется</p>\r\n\r\n<p>Полная занятость, сменный график</p>\r\n\r\n<p>Перед тем как откликнуться на вакансию, просим обратить Ваше внимание, что утренние смены начинаются с 7.00</p>\r\n\r\n<p>Обязанности:</p>\r\n\r\n<p>встреча клиентов клуба,</p>\r\n\r\n<p>распределение входящих звонков,</p>\r\n\r\n<p>продажа дополнительных услуг (не продажи абонементов)</p>\r\n\r\n<p>исходящие звонки</p>\r\n\r\n<p>презентация фитнес-клуба</p>\r\n\r\n<p>Требования:</p>\r\n\r\n<p>ответственность, внимательность, коммуникабельность,</p>\r\n\r\n<p>умение работать в команде,</p>\r\n\r\n<p>владение ПК на уровне уверенного пользователя,</p>\r\n\r\n<p>желательно знание кассовой дисциплины,</p>\r\n\r\n<p>к рассмотрению принимаются резюме с фото.</p>\r\n\r\n<p>Условия:</p>\r\n\r\n<p>график 2/2, полный рабочий день,</p>\r\n\r\n<p>работа в большой, сильной компании,</p>\r\n\r\n<p>карьерный рост</p>\r\n\r\n<p>оформление по ТК РФ,</p>\r\n\r\n<p>возможность бесплатных занятий в спортивном клубе.</p>\r\n', 'menedzer-recepcii', 'Менеджер рецепции', '', '', '2019-04-17 17:36:59', '2019-05-21 10:23:28'),
(5, 0, 60, 'Тренер по плаванию в бассейн', '<p>Требуемый опыт работы: 1&ndash;3 года</p>\r\n\r\n<p>Частичная занятость, сменный график</p>\r\n\r\n<p>Должностные обязанности:</p>\r\n\r\n<p>Проведение групповых занятий и персональных тренировок по плаванию и аквааэробике среди взрослых и детей</p>\r\n\r\n<p>Дежурство в бассейне</p>\r\n\r\n<p>Требования:</p>\r\n\r\n<p>Высшее спортивное образование (желательно специализация плаванье)</p>\r\n\r\n<p>Желателен опыт работы</p>\r\n\r\n<p>Мы предлагаем:</p>\r\n\r\n<p>Сменный график работы</p>\r\n\r\n<p>Оформление по ТК РФ</p>\r\n\r\n<p>Почасовая оплата труда 100р/час + 50% от персональных и групповых тренировок</p>\r\n\r\n<p>Работа в стабильном дружном коллективе по адресу: м. Московская, ул.Типанова д. 21, ТРК &quot;Питер&quot;</p>\r\n\r\n<p>Бесплатная карта в фитнес-клуб</p>\r\n', 'trener-po-plavaniu-v-bassejn', 'Тренер по плаванию в бассейн', '', '', '2019-04-27 11:13:13', '2019-11-15 09:22:48'),
(6, 10, 30, 'Ночной уборщик/уборщица', '<p>Требуемый опыт работы: не требуется</p>\r\n\r\n<p>Полная занятость, сменный график</p>\r\n\r\n<p>Обязанности:</p>\r\n\r\n<p>Уборка территории фитнес клуба в ночное время</p>\r\n\r\n<p>Требования:</p>\r\n\r\n<p>Аккуратность</p>\r\n\r\n<p>Ответственность</p>\r\n\r\n<p>Неконфликтность</p>\r\n\r\n<p><br>\r\nУсловия:</p>\r\n\r\n<p>Оформление по ТК РФ</p>\r\n\r\n<p>График работы 2/2 ночные смены с 21:00 до 9:00</p>\r\n\r\n<p>Возможность бесплатного посещения спортивного клуба</p>\r\n\r\n<p>Заработная плата 1200 руб. смена</p>\r\n\r\n<p>&nbsp;</p>\r\n', 'nocnoj-uborsikuborsica', 'Ночной уборщик/уборщица', '', '', '2019-04-27 11:13:50', '2019-11-15 09:22:34');
