INSERT INTO `news` (`id`, `status`, `position`, `title`, `date`, `intro`, `img`, `content`, `alias`, `meta_title`, `meta_keywords`, `meta_description`, `created_at`, `updated_at`) VALUES
(1, 0, 10, 'Аренда залов в клубе ТК \"Питер\"', '2019-09-01', 'Площадь залов: 100, 150, 50 и 20 кв.м', '', '<p>ExtraSport в ТК &quot;Питер&quot; (Типанова ул., 21) предлагает в аренду свои залы в свободное от групповых занятий время: для репетиций, тренингов, семинаров, постановки свадебных танцев, набора танцевальных групп, классов единоборств, йоги, персональных тренировок, а также массажный кабинет.&nbsp; Площадь залов: 100, 150, 50 и 20 кв.м.&nbsp;</p>\r\n\r\n<p>В каждом зале есть все необходимое для вас: зеркала, ринг (разумеется, в зале боевых искусств), музыкальная аппаратура.&nbsp;В стоимость входит пользование раздевалкой.<br>\r\n<br>\r\nПлощадь под аренду находится на территории фитнес клуба Экстра-Спорт, в 10-минутной пешей доступности от м. Московская (ТК &quot;Питер&quot;, ул. Типанова 21).<br>\r\n<br>\r\nПодробности и условия по телефону 421-85-37.</p>\r\n', 'arenda-zalov-v-klube-tk-piter', 'Аренда залов в клубе ТК \"Питер\"', '', '', '2019-04-15 08:01:46', '2019-11-15 09:24:49'),
(2, 10, 20, 'Тренировки на Cycle (велотренажер)', '2019-04-16', 'Занятия на сайкл-тренажере активно применяются для восстановления после травм.', '', '<p>Cycle - это занятие на велотренажере. Несмотря на то, что он понравится любителям велосипедных прогулок, нагрузка в сайкле довольно большая. Поэтому такой формат тренировок подходит только людям с хорошим здоровьем.</p>\r\n\r\n<p>Занятия на сайкл-тренажере активно применяются для восстановления после травм и болезней. При легкой тренировке вы улучшаете кровообращение и помогаете организму избавляться от шлаков. Интенсивное занятие - это оптимальный способ сбросить лишние килограммы.</p>\r\n\r\n<p>На занятиях, тренер выстраивает определенный порядок нагрузок, так, чтобы тренировки имели максимальную эффективность. Упражнения чередуются по команде тренера. Причем, меняются как режимы тренажера, так и положение тела спортсмена, имитируя и стандартную езду сидя, и езду с упором на ноги.</p>\r\n\r\n<p>В основном, тренировка длится от 40 минут до часа. Большинство специалистов рекомендует заниматься 2 раза в неделю, т.к. избыток тренировок негативно влияет на некоторые суставы и здоровье, в целом.</p>\r\n\r\n<p>В сайкле различают 5 уровней нагрузки:</p>\r\n\r\n<p>Cycle Intro (основа) - это занятия для начинающих.</p>\r\n\r\n<p>Cycle Endurance (выносливость) - занятия рассчитанные на более продвинутых участников. Такой урок развивает выносливость, при этом, осуществляется максимальное сжигание жира.</p>\r\n\r\n<p>Cycle Strength (сила) - данный урок имитирует подъем в гору (как в сидячем, так и в стоячем положении). В результате, происходит рост мышц и тренировка связок и сухожилий ног.</p>\r\n\r\n<p>Cycle Interval (интервал) - тренировка состоящая из интенсивных нагрузок, чередующихся с отдыхом. Interval это более сложный уровень тренировок на выносливость, как результат ваш организм станет более вынослив к усталости.</p>\r\n\r\n<p>Cycle Race Day (велогонка) - итог, после всех тренировок это велогонка. Участие в таких заездах, покажет ваши достижения после тренировок и выявит недостатки, над которыми нужно ещё поработать.</p>\r\n\r\n<p>Отдельно стоит выделить следующие плюсы Сайкла:</p>\r\n\r\n<p>- Сайкл тренировка - это самый эффективный способ сжечь лишний жир. За одно занятие сжигается порядка 550 калорий.</p>\r\n\r\n<p>- Он улучшает циркуляцию крови в организме, а значит, кровь с кислородом будет быстрее поступать к мышцам и ускоряет их рост.</p>\r\n\r\n<p>- Почти 100% времени на тренировке вы не прекращаете движения ни на минуту.</p>\r\n\r\n<p>- Сайкл-аэробика &ndash; &laquo;чемпион&raquo; по сроку достижения результатов, среди прочих аэробных направлений.</p>\r\n\r\n<p>- Занятия нормализуют давление и укрепляют сердечную мышцу.</p>\r\n\r\n<p>- При интенсивной нагрузке на бедра, сайкл помогает подтянуть мышцы и избавиться от целлюлита, при чем довольно в короткие сроки.</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/XnXLk9Mfv30?rel=0\" width=\"640\"></iframe></p>\r\n', 'trenirovki-na-cycle-velotrenazer', 'Тренировки на Cycle (велотренажер)', '', '', '2019-04-17 17:21:55', '2019-04-29 10:10:17'),
(3, 10, 30, 'ВИИТ (интервальная тренировка)', '2019-04-15', 'ВИИТ расшифровывается как “высокоинтенсивные интервальные тренировки”.', '', '<p>Как понятно из названия вас ждут сильные нагрузки с перерывами на отдых. В данной статье мы рассмотрим 3 популярных упражнения являющихся частью ВИИТ -&nbsp;Burpee (Берпи), Thruster (Трастер) и прыжки на степ-платформу.</p>\r\n\r\n<p>Burpee (Берпи)</p>\r\n\r\n<p>Это фитнес упражнение представляет из себя сочетание позиции планки, прыжка и отжимания. Оно задействует все мышцы тела (плечи, трицепсы, квадрицепсы, грудь, пресс, спина, ягодицы, бицепсы бедер), быстро увеличивает пульс до &ldquo;уровня жиросжигания&rdquo; и позволяет потратить большое количество калорий.</p>\r\n\r\n<p>Тело должно образовывать прямую линию без изгибов и прогибов. Вы должны одновременно следить за правильной формой выполнения упражнения и держать высокую скорость.</p>\r\n\r\n<p>Если рассматривать берпи по позициям, то всё очень просто:</p>\r\n\r\n<p>1. Сделайте присед, а из него прыжком займите позу планки. Ладони должны быть на уровне плеч, тело должно представлять собой прямую линию без каких-либо изгибов.</p>\r\n\r\n<p>2. Стоя в позиции планки сгибаем локти и опускаемся грудью на пол. Тело должно также оставаться прямой линией. Затем, возвращаемся в планку.</p>\r\n\r\n<p>3.&nbsp;Следующим шагом (из планки) ноги возвращаем вперед, к туловищу. Оказываемся в положении полуприседа. Из него, прыжком, выпрыгиваем вверх поднимая руки и тело вверх.</p>\r\n\r\n<p>Что касается количества повторений Бёрпи, здесь нет норматива, т.к. есть персональные особенности организма. Начните делать по 5-10 берпи ежедневно, и планомерно увеличивайте количество повторений день ото дня.</p>\r\n\r\n<p>Запрыгивание на степ платформу (Джампинг)</p>\r\n\r\n<p>Несмотря на то, что в прыжках на степ платформу нет ничего сложного, такое занятие является хорошей кардиотренировкой, а также задействует различные группы мышц.</p>\r\n\r\n<p>Постепенно, рекомендуется усложнять задачу и повышать высоту степ-платформы. Что касается числа повторений, то здесь также нужно начинать с комфортного количества, а затем усложнять задачу. Но т.к. это упражнение является элементом ВИИТа, нагрузки должны быть, действительно, интенсивные.</p>\r\n\r\n<p>Трастер</p>\r\n\r\n<p>1. Ставим ноги на ширине плеч, стопы параллельны друг другу.&nbsp;Спина прямая. Блинчик держим на уровне груди над центром стопы.&nbsp;Локти сведены ближе к телу, но не следует &ldquo;заводить&rdquo; &nbsp;внуторь.&nbsp;Взгляд перед собой.&nbsp;На выдохе начинаем выполнять присед.</p>\r\n\r\n<p>2. В приседе тазобедренный сустав должен опускаться ниже коленного.&nbsp;Спину держите прямо, удерживайте равновесие.&nbsp;Положение блинчика и локтей остается неизменным.&nbsp;Пятки не должны отрываться от пола.&nbsp;На мощном выдохе полностью распрямляемся.&nbsp;Здесь работают бицепсов бедра, квадрицепсов, ягодичных мышц, а также передней и задней части корпуса.</p>\r\n\r\n<p>3. Из положения приседа выпрямляем тело в одну прямую линию.&nbsp;Выжимаем блинчик над собой. Локти распрямляем.&nbsp;В движении активно работают дельтовидные мышцы и трицепсы.&nbsp;Затем опускаем блинчик на грудь (упражнение 1) и выполняем трастер заново.</p>\r\n', 'viit-intervalnaa-trenirovka', 'ВИИТ (интервальная тренировка)', '', '', '2019-04-17 17:22:19', '2019-04-25 15:30:10'),
(4, 10, 40, 'Занятие по Pilates (тренер Татьяна Микулинская)', '2019-04-14', 'Пилатес – это новое направление фитнеса, названная по фамилии создателя Джозефа  Пила', '', '<p>За час силовой тренировки пилатеса прорабатываются абсолютно все внутренние &nbsp;и внешние мышцы, которые выполняются естественно.</p>\r\n\r\n<p>Занятия пилатесом повышают выносливость, делает тело более гибким и подтянутым.</p>\r\n\r\n<p>Тема пилатеса включает в себя упражнения для всех частей тела, которая помогает вам научиться пользоваться грамотно и качественно свои телом.</p>\r\n\r\n<p>В пилатесе все упражнения делаются в медленном темпе, что дает хорошую нагрузку: чем медленней, тем эффективнее. Появляется осознанность движений &ndash; концентрация упражнений.</p>\r\n\r\n<p>Кроме того пилатес прекрасно улучшает координацию , походку и равновесие, а также помогает преодолеть усталость. Система &nbsp;комплексных упражнений улучшает состояние всех суставов, улучшает подвижность гибкость позвоночника. Дает ощущение свободы.</p>\r\n\r\n<p>Пилатес изначально создавался как реабилитационная методика, его считают универсальной системой оздоровления, которая подходит практически всем. У пилатеса нет возраста и пола, заниматься им можно в любым уровнем физической подготовки.</p>\r\n\r\n<p>Благодаря пилатесу вы не только укрепите свой организм и получите заряд энергии и бодрости, а еще пилатес снимает стресс, снижает вес.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>1 комбинация упражнений</p>\r\n\r\n<p>Встаем на коврик, ноги на ширине плеч, вес тела переносим на внешнюю часть стопы. Делаем вдох, опускаем подбородок и медленно, позвоночник за позвоночком, опускаемся вниз. Опустившись, ставим ладони на пол.</p>\r\n\r\n<p>Далее, медленно переступая руками вперед встаем в позу планки.</p>\r\n\r\n<p>Ладонями упираемся в пол на уровне плеч. Таз не должен провисать, поясница не должна прогибаться. В этом положении поднимаем вначале одну ногу, затем другую. Далее, опираясь на ладони и стопы, поднимаем таз вверх (поза собака мордой вниз из йоги) и плавно возвращаемся в исходное положение, переступая руками обратно к стопам.</p>\r\n\r\n<p><br />\r\n<br />\r\n2 комбинация упражнений (Баланс)</p>\r\n\r\n<p>В стоячем положении соединяем ладони на уровне груди. Переносим вес на одну ногу, а другую поднимаем. Колено на поднятой ноге должно быть согнуто на 90 градусов. Затем, повторяем это движение с другой ногой.</p>\r\n\r\n<p><br />\r\nНа вдох, поднимаем руки над головой, выдыхая, таз отводим назад, тянемся вперед в диагональ. Спина должна быть полностью натянута. Немного задерживаемся в этом положении и возвращаемся в исходное положение.</p>\r\n\r\n<p>Наконец, 3й этап &ldquo;баланса&rdquo;. Упражнение похоже на предыдущее упражнение, но теперь, подняв ногу с согнутым на 90 градусов коленом, медленно вытягиваем согнутую ногу назад, а руками тянемся вперед. Таким образом, руки, тело и одна нога будут параллельно полу. Повторяем такое же движение с участием другой гоги.</p>\r\n', 'zanatie-po-pilates-trener-tatana-mikulinskaa', 'Занятие по Pilates (тренер Татьяна Микулинская)', '', '', '2019-04-17 17:23:58', '2019-04-25 15:29:38'),
(5, 10, 50, 'Бокс для начинающих', '2019-04-13', 'В этой статье мы рассмотрим положительные и отрицательные стороны бокса.', '', '<p>Бокс - это одно из основных направлений боевых искусств. Ему характерны удары рук в голову и корпус противника, а также защитой с нырками и уклонами. Как и любой вид спорта, бокс имеет свои преимущества. Основные преимущества можно сформулировать как: укрепление тела и здоровья, а также повышение уверенности в себе.</p>\r\n\r\n<p>Если рассматривать плюсы бокса более подробно, то получается такой список:</p>\r\n\r\n<p>- Бокс это один из самых эффективных способов самообороны.</p>\r\n\r\n<p>- Люди, занимающиеся боксом не могут быть слабыми и неуверенными в себе. &nbsp;</p>\r\n\r\n<p>- В боксе работают все мышцы, т.к. этот вид спорта подразумевает постоянное движение.</p>\r\n\r\n<p>- Помимо мышц, развивается и укрепляется дыхательная и сердечно-сосудистая система.</p>\r\n\r\n<p>- Повышается выносливость организма и улучшается реакция</p>\r\n\r\n<p>Боксом можно начинать заниматься в любом возрасте, т.к. здесь нет особых ограничений. Сегодня боксом занимаются и мужчины и женщины, причем как взрослые, так и дети. После пары тренировок вы уже можете понять, насколько вам по душе этот вид спорта.</p>\r\n\r\n<p>Тем кто осмелится заняться тренировками мы дадим несколько советов:</p>\r\n\r\n<p>1. Несмотря на кажущуюся агрессивность данного вида спорта, необходимо быть спокойным, но при этом собранным.</p>\r\n\r\n<p>2. Наносите удары резко, но легко. Сохраняя силы, вы сможете выдерживать больше раундов. Кроме того, при сильных ударах новичку гораздо легче получить травму.</p>\r\n\r\n<p>3. Выпивайте хотя бы стакан воды, за часовую тренировку. При правильной нагрузке вы будете сильно потеть, и вам нужно восстанавливать количество воды в организме.</p>\r\n\r\n<p>4. Для бокса очень полезны тренировки на скакалке. Не пренебрегайте ими, как и другими тренировками, развивающими выносливость.</p>\r\n\r\n<p>5. Не тренируйтесь до помутнения сознания. Конечно, выкладываться нужно, но после нескольких слишком интенсивных тренировок, вы скорее забросите бокс, не достигнув желаемых результатов.</p>\r\n', 'boks-dla-nacinausih', 'Бокс для начинающих', '', '', '2019-04-17 17:24:14', '2019-04-25 15:31:53'),
(6, 10, 60, 'Upper Body', '2019-04-12', 'Как хочется выглядеть великолепно!', '', '<p>Так, чтобы не только знакомые, но и сам мог восхищаться своей фигурой и осанкой. Существует много видов тренировок, и одна из них - Upper Bodу.</p>\r\n\r\n<p>На занятиях большую часть времени уделяют верхней части: груди, животу, рукам, плечам, шее. Используют дополнительное оборудование для отягощения: гантели, бары. Основной задачей является повышение мышечного тонуса, укрепление, восстановление двигательной функции конечностей.&nbsp;Занятия Upper Body помогут сделать вашу фигуру фигурой мечты, а осанку - статной и грациозной.</p>\r\n\r\n<p>Упражнения Upper Body.&nbsp;Переходим непосредственно к тренировке.</p>\r\n\r\n<p>Проработка бицепсов.</p>\r\n\r\n<p>Исходное положение &ndash; стоя. Пятки вместе, носки разведены. Руки расположены вдоль тела. Берете гантели. Попеременно сгибаете правую, а затем левую руку в локтевом суставе. Упражнение делается в среднем темпе. Количество повторений &ndash; от двадцати до тридцати.</p>\r\n\r\n<p><br />\r\n<br />\r\n&nbsp;</p>\r\n\r\n<p>Мышцы предплечья и трицепсы.</p>\r\n\r\n<p>Стоите, пятки вместе, носки немного разведены, верхние конечности расположены вдоль туловища. Гантели в руках. Конечности поднимают к плечам. Затем их поднимают вверх, снова опускают к плечам и возвращают в исходное положение. Темп выполнения упражнения &ndash; средний. Количество повторов &ndash; от пятнадцати до тридцати пяти.</p>\r\n\r\n<p><br />\r\n&nbsp;</p>\r\n\r\n<p>Грудные и дельтовидные мышцы.</p>\r\n\r\n<p>Исходное положение, как и в первых двух упражнениях. Только руки с гантелями направлены вперед. Находятся они на уровне высоты плеч. Приподнимаетесь на носки и разводите верхние конечности в стороны. Количество повторов &ndash; от восьми до двенадцати раз.</p>\r\n\r\n<p><br />\r\n&nbsp;</p>\r\n\r\n<p>Прорабатываем мышцы спины. Ноги находятся на ширине плеч. Руки с гантелями подняты вверх. На выдохе наклоняетесь вперед. Ноги сгибать нельзя. На вдохе &ndash; выпрямляетесь. Темп выполнения упражнения &ndash; средний. Количество повторов &ndash; десять.</p>\r\n\r\n<p>Гимнастика для пресса.</p>\r\n\r\n<p>Не забывайте о гантелях. Сидите на стуле. Носки ног упираются в стол или диван, руки подняты к плечам. Корпус наклоняете назад и возвращаетесь в исходное положение. Темп выполнения &ndash; медленный. Повторить упражнение следует не менее десяти раз.</p>\r\n\r\n<p><br />\r\n&nbsp;</p>\r\n\r\n<p>Заключение.</p>\r\n\r\n<p>Вы уже знаете, что это - Upper Body. Но еще для вас несколько &laquo;добавочек&raquo;. Помимо физической нагрузки, во время занятий тренируется и дыхательная система. Для выполнения упражнений не требуется интенсивного движения. Они неторопливы, но очень напряженны. Весь комплекс направлен на уменьшение объема желудка, ускорение обмена веществ, сжигания калорий.</p>\r\n', 'upper-body', 'Upper Body', '', '', '2019-04-17 17:24:30', '2019-04-25 15:32:35'),
(7, 10, 70, 'Приглашаем вас на НОВОЕ занятие IRON BODY!', '2019-04-11', 'IRON BODY - cистема силовых тренировок, пришедшая к нам из Германии. ', '', '<p>В ней нет ничего лишнего, ничего случайного. Она просто работает на результат, в т.ч.: коррекцию тела и жиросжигание, таким образом улучшая Вашу фигуру!&nbsp;<br />\r\nБолее 800 ккал сжигается за час тренировки, интенсивный расход энергии продолжается еще в течение суток после занятий.&nbsp;<br />\r\nIRON BODY &ndash; идеально подойдет для женщин, которые хотят иметь стройное и рельефное тело.&nbsp;<br />\r\nIRON BODY &ndash; сегодня пользуется невероятной популярностью. Одно из объяснений этому &ndash; силовая тренировка намного эффективнее для интенсивного сжигания жира, чем кардиотренировка.<br />\r\nИдет набор в группу занятия проходят каждую субботу в 13:30. Стоимость занятия 250 рублей.</p>\r\n\r\n<p>Подробности по телефону 421-85-37&nbsp;<br />\r\nТК &quot;Питер&quot; СПб, ул. Типанова, 21</p>\r\n', 'priglasaem-vas-na-novoe-zanatie-iron-body', 'Приглашаем вас на НОВОЕ занятие IRON BODY!', '', '', '2019-04-17 17:24:45', '2019-04-25 15:33:19'),
(8, 10, 80, 'Четвёртый запуск ФИТНЕС-ПРОЕКТА Beatyform', '2019-04-10', 'Старт 23 апреля', '', '<p>Встречаем четвёртый запуск ФИТНЕС-ПРОЕКТА Beatyform старт 23 апреля.</p>\r\n\r\n<p>Направление и цели проекта:</p>\r\n\r\n<p>коррекция фигуры<br />\r\nэффективное жиросжигание<br />\r\nрасчет БЖУ, калоража.<br />\r\nрастяжка<br />\r\nГарантируем индивидуальный подход к каждому и достижения желаемого результата.<br />\r\nРуководитель проекта Жалнина Ксения</p>\r\n\r\n<p>Подробности по телефону 421-85-37 и номер Ксении +79313572037&nbsp;<br />\r\nТК &quot;Питер&quot; СПб, ул. Типанова, 21</p>\r\n', 'cetvertyj-zapusk-fitnes-proekta-beatyform', 'Четвёртый запуск ФИТНЕС-ПРОЕКТА Beatyform', '', '', '2019-04-17 17:26:26', '2019-04-25 16:03:19'),
(9, 10, 90, 'Набор на новый Beatyform в ТК \"Питер\"', '2019-04-09', 'Новогодние праздники пройдут, а лишние килограммы останутся? Неет! Всему свое время!', '', '<p>Встречайте второй запуск фитнес-проекта Beatyform в январе 2018 года.&nbsp;</p>\r\n\r\n<p><br />\r\nНаправление и цели проекта:&nbsp;</p>\r\n\r\n<p>коррекция фигуры&nbsp;</p>\r\n\r\n<p>эффективное жиросжигание&nbsp;</p>\r\n\r\n<p>расчет БЖУ, калоража.</p>\r\n\r\n<p>растяжка&nbsp;</p>\r\n\r\n<p><br />\r\nГарантируем индивидуальный подход к каждому и достижения желаемого результата.&nbsp;<br />\r\nРуководитель проекта Жалнина Ксения.</p>\r\n\r\n<p>Подробности по телефону 421-85-37 и у тренера Ксении +79313572037&nbsp;<br />\r\nТК &quot;Питер&quot; СПб, ул. Типанова, 21</p>\r\n', 'nabor-na-novyj-beatyform-v-tk-piter', 'Набор на новый Beatyform в ТК \"Питер\"', '', '', '2019-04-17 17:26:35', '2019-04-25 15:34:35'),
(10, 10, 100, 'Extra Sport поздравляет всех с наступающими праздниками', '2019-04-07', 'Также, информируем о работе клубов в праздничные дни', '', '<p>Дорогие друзья!&nbsp;<br />\r\nСеть фитнес-клубов ExtraSport поздравляет всех с наступающим Новым годом и Рождеством! Желаем вам счастья, здоровья и сил, чтобы легко добиваться поставленных целей!&nbsp;</p>\r\n\r\n<p>Также, информируем о работе клубов в праздничные дни:</p>\r\n\r\n<p>ТК &quot;Питер&quot; :&nbsp;<br />\r\n31 декабря - 9.00 - 16.00&nbsp;<br />\r\n1 и 2 января - выходной&nbsp;<br />\r\n3 - 8 января - 9.00 - 22.00</p>\r\n', 'extra-sport-pozdravlaet-vseh-s-nastupausimi-prazdnikami', 'Extra Sport поздравляет всех с наступающими праздниками', '', '', '2019-04-17 17:26:50', '2019-04-25 16:04:41'),
(11, 10, 110, 'Стартовал второй этап проекта \"BeatyForm\"', '2019-04-05', 'Вчера был дан старт второму этапу проекта \"BeatyForm\"!', '', '<p>Первый этап закончился в декабре 2017 года и имел большой успех.&nbsp;</p>\r\n\r\n<p>У девочек прошла первая тренировка . Набралась отличная команда, все девушки очень целеустремленные и мотивированны меняться.&nbsp;<br />\r\nИх ждет целый месяц интенсивных тренировок и большая работа над собой .</p>\r\n\r\n<p>Хотите тоже попасть на проект? Узнайте подробности по телефону: 421-85-37, или у тренера, Ксении +7 (931) 357-20-37.</p>\r\n', 'startoval-vtoroj-etap-proekta-beatyform', 'Стартовал второй этап проекта \"BeatyForm\"', '', '', '2019-04-17 17:27:00', '2019-04-25 15:36:51'),
(12, 10, 120, 'Занятия по йоге: сурья намаскар', '2019-04-05', 'Йога, как направление фитнеса, набирает все большую популярность.', '', '<p>Эта популярность обусловлена тем, что при простоте упражнений вы получаете удивительные результаты.</p>\r\n\r\n<p>В йоге существует большое количество поз (асан) &ndash; они различаются по степени сложности, а также имеют различные области применения.&nbsp;Для тех, кто только собирается, заниматься йогой мы расскажем один из популярных комплексов асан - сурья намаскар (приветствие солнцу).</p>\r\n\r\n<p>Пранамасана (поза молящегося)</p>\r\n\r\n<p>Руки соединяем на груди, так чтобы большой вытянутый палец мог касаться ее, ладони давят друг на друга, расправляем плечи, стопы вместе, большие пальцы ног соединены.</p>\r\n\r\n<p>Хаста Уттанасана (поза с вытянутыми вверх руками)</p>\r\n\r\n<p>Упускаем руки вниз и на вдохе поднимаем руки через стороны вверх, соединяем ладони, плечи опущены, прогибаемся в поясничном отделе, руки уводим назад.</p>\r\n\r\n<p>Уттанасана (голова к ногам)</p>\r\n\r\n<p>На выдохе опускаемся вниз, колени прямые, животом стремимся к бедрам, руки ставим возле стоп, вытягиваем корпус вдоль всего тела, голову тянем к коленям.</p>\r\n\r\n<p>Ашва санчаланасана (поза всадника)</p>\r\n\r\n<p>Правую ногу уводим назад, в левой ноге угол 90 градусов, таз тянется в пол, колено лежит на полу, поднимаем руки вверх, соединяем ладони над головой, смотрим на большие пальцы рук.</p>\r\n\r\n<p>Чатуранга Дандасана (поза планки)</p>\r\n\r\n<p>Уводим левую ногу назад в планку, лопатки сводим, спина и ноги &ndash; одна прямая, руки перпендикулярны полу.</p>\r\n\r\n<p>Аштанга Намаскара (Поза восьми точек)</p>\r\n\r\n<p>С выдохом опускаемся колени вниз, прогибаемся в области поясницы, кладем грудную клетку и подбородок на пол, локти прижаты к телу и направлены назад.</p>\r\n\r\n<p>Урдхва Мукха Шванасана Собака Мордой вверх</p>\r\n\r\n<p>Со вдохом перекат на лобковую кость, круговыми движениями расправляем плечи и локти назад, вытягиваемся подбородком наверх, прогиб в поясничном отделе.</p>\r\n\r\n<p>Адхо Мукха Шванасана (Собака мордой вниз)</p>\r\n\r\n<p>Уходим собакой мордой вниз, тянем таз вверх за копчиком, будто нас тянут в потолок, грудной отдел тянем к бедрам, руки на ширине грудного пояса, ноги на ширине тазобедренных суставов, стопы параллельны друг другу, спина и руки уходят в одну прямую, лбом касаемся пола, расслабляем шею.</p>\r\n\r\n<p>Ашва санчаланасана (поза наездника)</p>\r\n\r\n<p>Правую ногу уводим назад, в левой ноге угол 90 градусов, таз тянется в пол, колено лежит на полу, поднимаем руки вверх, соединяем ладони над головой, смотрим на большие пальцы рук.</p>\r\n\r\n<p>Уттанасана (голова к ногам)</p>\r\n\r\n<p>Левую ногу подводим к себе, касаемся лбом коленей, руками обхватываем ступни ног, выпрямляем колени, шею расслабляем, на выдохе поднимаемся позвонок за позвонком, начиная с поясницы как бусинки наверх, руки вдоль тела.</p>\r\n\r\n<p>Видео:</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/g5CsA7RE-aY?rel=0\" width=\"640\"></iframe></p>\r\n', 'zanatia-po-joge-sura-namaskar', 'Занятия по йоге: сурья намаскар', '', '', '2019-04-17 17:27:15', '2019-04-25 15:38:15'),
(13, 10, 130, 'Тренировка Pump It Up', '2019-04-04', 'Pump – это комплекс силовых тренировок с использованием штанги. ', '', '<p>Тренировки проводятся под ритмичную музыку.&nbsp;Цель таких тренировок - сжигание жира и укрепление сразу нескольких групп мышц. Памп является&nbsp;смесью интенсивных аэробных занятий и силовой нагрузки.</p>\r\n\r\n<p>Во время такой тренировки со штангой вы сможете проработать следующие группы мышц и зоны тела:</p>\r\n\r\n<p>грудь и спина</p>\r\n\r\n<p>руки (плечи, бицепсы и трицепсы).</p>\r\n\r\n<p>ноги и ягодицы</p>\r\n\r\n<p>живот (верхний и нижний пресс).</p>\r\n\r\n<p>В памп тренировках не используются большие веса. Здесь важна цикличность и ритмичность упражнений.</p>\r\n\r\n<p>Плюсы:</p>\r\n\r\n<p>За счет совмещения силовых и аэробных направлений, а также небольшого веса и динамичного темпа вы получаете красивое рельефное тело и, соответственно, теряете лишние килограммы.</p>\r\n\r\n<p>Рассчитан на работу со всеми группами мышц, в целом.</p>\r\n\r\n<p>Pump-аэробика укрепляет сердечно-сосудистую систему и ускоряет обмен веществ.</p>\r\n\r\n<p>Подходит и для мужчин и для женщин</p>\r\n\r\n<p>Разберем с иллюстрациями, как выполнять pump-тренировку.</p>\r\n\r\n<p>Приседы со штангой.</p>\r\n\r\n<p>1. Берем штангу (для начала можно использовать только гриф, без дополнительного веса), и заводим её за голову.&nbsp;Штанги лежат не на шее, а на 2-х точках трапеции.</p>\r\n\r\n<p>2. Начинаем приседания со штангой. Опускаясь вниз сохраняем прямую спину. Локти направлена не в пол, а чуть назад.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Тяга обратным хватом.</p>\r\n\r\n<p>1. Ноги ставим на ширину плеч. Руки держим на грифе штанги чуть шире плеч. Ладони смотрят &ldquo;от себя&rdquo;. Ноги немного согнуты, спина прямая.</p>\r\n\r\n<p>2. Начинаем подъемы штанги к поясу. Опуская штангу делаем выдох и расслабляем мышцы. Обратите внимание, что при подъеме локти необходимо держать вдоль тела, а не разводить в стороны.</p>\r\n', 'trenirovka-pump-it-up', 'Тренировка Pump It Up', '', '', '2019-04-17 17:27:28', '2019-04-25 15:38:55'),
(14, 10, 140, 'Занятие по flex-растяжке', '2019-04-03', 'Flex – комплексная работа над телом.', '', '<p>Вместо того чтобы качать каждую группу мышц отдельно, все тело тренируется одновременно.</p>\r\n\r\n<p>Flex повышает мышечный тонус, развивает гибкость и координацию, улучшает осанку, делает движения пластичными.</p>\r\n\r\n<p>Перед тренировкой для развития гибкости должна выполняться разминка 5-7 мин., которая позволяет осуществлять движение по удобной амплитуде и никогда не переходить за грань умеренного напряжения или растяжения мышц.</p>\r\n\r\n<p>От 5 до 7 минут суставная разминка.</p>\r\n\r\n<p>Во время занятие применяется статический стретчинг так как он более безопасен и эффективен.</p>\r\n\r\n<p>Величина удлинения мышечной фасции , которая остается после того, как прекращается воздействие силы растягивания, значительно превосходит аналогичный результат статического стретчинга с меньшей силой воздействия и большей продолжительностью выполнения (10-60 сек.).</p>\r\n\r\n<p>Статический стретчинг менее травматичен. Если цель-функциональная гибкость, то она может быть легко и эффективно достигнута с помощью статического стретчинга.</p>\r\n\r\n<p>Приступим к его выполнению:</p>\r\n\r\n<p>1.&nbsp;Садимся на коврик, одну ногу уводим под себя, другая нога вытянута, так, чтобы между ногами получился угол, примерно, 90 градусов.&nbsp;На выдохе переносим тело на вытянутую ногу и начинаем тянуться вперед,сохраняя спину прямой.&nbsp;Если вы хотите усилить растяжку, потяните руками стопу на себя, на выдохе.В этом упражнении идет акцент на заднюю мышцу бедра и поясничный отдел.</p>\r\n\r\n<p><br />\r\n2.&nbsp;Из положения 1 на выдохе, вытягиваетесь в диагональ. Продолжаете тянуться вперед, сохраняя спину прямой.&nbsp;Колено вытянутой ноги должно оставаться прямым.&nbsp;Повторите упражнение 1 и 2 &nbsp;на растяжку другой ноги.<br />\r\n&nbsp;</p>\r\n\r\n<p>3. Затем из положения 2 начинаем растягивать внутреннюю часть бедра и подколенные сухожилия.&nbsp;Максимально широко раздвигаем ноги, спина остается ровной.&nbsp;Подавайте корпус вперед к полу, помогая прямыми руками.&nbsp;Стараемся максимально положить живот на пол.</p>\r\n\r\n<p>4.&nbsp;Следующее упражнение - поза &ldquo;лягушки&rdquo;, тянем приводящие мышцы.&nbsp;Садимся коленями на пол.&nbsp;Руки вытягиваем впереди себя, медленно раздвигаем ноги, плавно наклоняем корпус к полу.&nbsp;Должно чувствоваться натяжение в паховой области.</p>\r\n\r\n<p><br />\r\n5.&nbsp;Далее тянем внутреннюю часть бедра - более сложный вариант.&nbsp;Ставим колени на пол.&nbsp;Руки ставим перед собой, чтобы на них перенести вес тела.&nbsp;Правую ногу вытягиваем вправо перпендикулярно корпусу, таз постепенно опускается на пол.&nbsp;Повторите упражнение на растяжку другой ноги.</p>\r\n\r\n<p>6.&nbsp;Тянем заднюю поверхность бедра.&nbsp;Садимся на пол, ноги вытягиваем перед собой.&nbsp;Наклоняем корпус вперед и обхватываем руками стопу левой ноги.&nbsp;Медленно начинаем поднимать ногу на себя, колени и спина прямые.&nbsp;Тянем ногу руками ко лбу.</p>\r\n\r\n<p>7.&nbsp;Оставаясь в положении 6 на выдохе &nbsp;отводим левую руку назад за спину.&nbsp;Спина, локти и колени остаются прямыми.&nbsp;Повторите упражнение 6 и 7 &nbsp;на растяжку другой ноги.</p>\r\n\r\n<p><br />\r\n8.&nbsp;Следующее упражнение - продольный шпагат.&nbsp;Встаньте на колено, передняя нога выставлена вперед под углом в 90 градусов, носок задней ноги упирается в пол. Спина прямая.&nbsp;Тазовые кости должны располагаться на одной линии и смотреть строго вперед.&nbsp;Сделайте вдох и на выдохе начните постепенно разъезжаться ногами в разные стороны, опуская таз вниз.&nbsp;Дойдите до крайнего терпимого положения и замрите.&nbsp;Как только таз опустился достаточно низко, придерживайте руками ноги: левой рукой - правую ногу, и наоборот.</p>\r\n\r\n<p><br />\r\n9.&nbsp;Из положения 8 на выдохе обхватите правой рукой левую ногу и потяните на себя.&nbsp;Спина, локти и колени остаются прямыми.&nbsp;Повторите упражнение на растяжку другой ноги.</p>\r\n\r\n<p>10.&nbsp;Из положения стоя на коленях выпрямляем правую ногу, опираясь на колено второй ноги и на выдохе делаете наклон вперед, так, чтобы вы могли упереться ладонями в пол.</p>\r\n\r\n<p><br />\r\n11.&nbsp;Занимаете положение - упор стоя на коленях. Из этой позиции делаете выпад одной ногой вперед.&nbsp;Угол в колене должен быть больше 90 градусов.&nbsp;Колено задней выпрямлено.&nbsp;Старайтесь опустить таз как можно ниже, не сгибая колено задней ноги.&nbsp;Руки ставим на колено впереди стоящей ноги и отталкиваемся от него.</p>\r\n\r\n<p><br />\r\n12.&nbsp;Из положения 11 на выдохе обхватите правой рукой левую ногу и потяните на себя.&nbsp;Спина прямая.&nbsp;Повторите упражнение 10, 11 и 12 на растяжку другой ноги.</p>\r\n', 'zanatie-po-flex-rastazke', 'Занятие по flex-растяжке', '', '', '2019-04-17 17:27:38', '2019-04-25 15:40:34'),
(15, 10, 150, 'Bums - Тренировка на ягодицы', '2019-04-02', 'Подбор специальных фитнес-упражнений на мышцы ног, таза и ягодиц в первой части.', '', '<p>BUMS (Бамс) - это комплекс упражнений для мышц брюшного пресса, мышц ягодиц, задней, передней, внутренней, внешней сторон бёдер (полный комплекс на проблемные зоны ног), а также создание красивых и рельефных форм вашего тела.</p>\r\n\r\n<p>Подбор специальных фитнес-упражнений на мышцы ног, таза и ягодиц в первой части.</p>\r\n\r\n<p>Занятие по Bums начинается с разогрева мышц - разминки. Она проходит в аэробном режиме в течение 3-5 минут, в течение которой мышцы разогреваются.</p>\r\n\r\n<p>После аэробной разминки идут предстретчинговые упражнения, растяжка, которая завершает подготовку мышц к работе, уменьшает вероятность получения травм и микротравм, улучшает кровообращение и подвижность суставов.</p>\r\n\r\n<p>И затем начинаем комплекс силовых упражнений, направленных на активную работу мышц. Ниже приведём пример одной из тренировок:</p>\r\n\r\n<p>1. Выпады. Исходное положение. Ноги вместе. Стопы параллельно друг другу, колени и носки ног направлены в одну сторону. Делаем вдох, шаг вперед, следим за тем, чтобы колено рабочей ноги не выезжало за линию носка. В коленях передней и задней ноги должен образоваться прямой угол 90 градусов. Туловище наклонено вперед, спина ровная, очень важно удерживать корпус перпендикулярно полу. На выдохе, через пятку, возвращаем ногу в исходное положение. Выпады можно выполнять как одной ногой, так и меняя их.</p>\r\n\r\n<p>Работают: четырехглавая мышца бедра, большая ягодичная мышца и бицепс бедра.</p>\r\n\r\n<p>2. Приседания. Исходное положение. Ноги на ширине плеч, стопы параллельно друг другу и плотно прижаты к полу, колени и стопы направлены в одну сторону. Опускаем таз, стараемся увести его максимально назад, как будто сзади стоит скамейка, на которую мы хотим сесть, колени не выводим за носки ног. На выдохе возвращаем таз в исходное положение, давим на пятки и сознательно сокращаем ягодицы.</p>\r\n\r\n<p>Работают: четырехглавая мышца бедра, большая ягодичная мышца, бицепс бедра.</p>\r\n\r\n<p><br />\r\n&nbsp;</p>\r\n\r\n<p>3. &ldquo;Ягодичный мостик&rdquo; или подъемы таза лежа.Исходное положение. Лежа на спине, стопы на ширине таза близко к ягодицам, руки вдоль тела. На выдохе давим пятками в пол, поднимаем таз вверх, зажимаем ягодицы, и на вдохе возвращаем таз в исходное положение. Подъем ягодиц из положения лежа на спине представляет собой вариацию такого движения, как мостик. Но, в отличие от мостика оно не нагружает позвоночник.</p>\r\n\r\n<p>Работают: большая ягодичная мышца, бицепс бедра.</p>\r\n\r\n<p>Программа упражнений Bums подходит для всех, независимо от уровня подготовки, пола и возраста.</p>\r\n\r\n<p>Во время тренировки вы всё время находитесь в движении, поэтому повышается выносливость организма и улучшается кровоснабжение.Также вы прорабатываете и укрепляете 80% мышц тела, и основная нагрузка направлена на коррекцию проблемных зон - живота и ягодиц. Упражнения способствуют жиросжиганию и формируют красивую форму тела.</p>\r\n', 'bums---trenirovka-na-agodicy', 'Bums - Тренировка на ягодицы', '', '', '2019-04-17 17:28:03', '2019-04-25 15:49:47'),
(16, 10, 160, 'Кикбоксинг для начинающих', '2019-04-01', 'Кикбоксинг - это симбиоз бокса, тайского бокса и карате', '', '<p>Здесь идет сочетание ударов ногами и руками, при этом захваты и удары локтями, коленями, головой запрещены. В кикбоксинге разрешено доводить соперника до нокаута, в отличие от некоторых других единоборств.</p>\r\n\r\n<p>Кикбоксинг имеет ряд положительных моментов:</p>\r\n\r\n<p>Он не перенапрягает мышцы, соответственно снижается шанс получения травм.</p>\r\n\r\n<p>Кикбоксинг не травмоопасен. При любительских занятиях в фитнес-клубе вам не грозят синяки под глазами и выбитые зубы.</p>\r\n\r\n<p>Кикбоксинг сильно повышает выносливость и силу. Вы тренируете сердце и дыхательную систему. Повышаете иммунитет и улучшаете координацию движений.</p>\r\n\r\n<p>Помогает в кратчайшие сроки получить красивую попу и пресс.</p>\r\n\r\n<p>При правильных занятиях с тренером формируется осанка и добавляется гибкость телу.</p>\r\n\r\n<p>За счет динамичности и интенсивности тренировок вы сжигаете большое количество жировых клеток</p>\r\n\r\n<p>Если вы решились заниматься этим видом единоборств, вам придется регулярно выполнять упражнения поддерживать физическую форму. Но самый важный момент это слушать тренера. Он научит вас основным техникам, правильному дыханию и будет управлять вашей нагрузкой.</p>\r\n\r\n<p>Кстати, кикбоксингом занимаются не только мужчины, но и девушки. Они стремятся защитить себя и иметь красивую фигуру. Ведь здесь можно быстро подкачать попу, ноги, а также получить плоский живот и красивый пресс!</p>\r\n', 'kikboksing-dla-nacinausih', 'Кикбоксинг для начинающих', '', '', '2019-04-25 15:42:43', '2019-04-25 15:42:43'),
(17, 10, 170, 'Мы открываем набор в новый проект по йоге', '2019-03-31', 'Проект называется «Здоровая спина»', '', '<p>Дорогие друзья! Мы открываем набор в новый проект по йоге &laquo;Здоровая спина&raquo; .</p>\r\n\r\n<p>Это комплекс тренировок,который поможет сформировать правильную осанку,раскрыть грудной отдел и укрепить мышцы,поддерживающих позвоночник.&nbsp;<br />\r\nПосле окончания курса вы почувствуете,как плечи расправляются, дыхание облегчается, боли в спине уходят.<br />\r\nОздоравливая спину, вы продлеваете свою молодость и красоту!<br />\r\nДля всех уровней подготовки.</p>\r\n\r\n<p>Набор идёт в утренние группы.Группы до 7 человек?индивидуальный подход к каждому!&nbsp;<br />\r\nПодробности по телефону 421-85-37&nbsp;<br />\r\nТренер Сорокина Екатерина +7 (951) 665-42-25&nbsp;<br />\r\nТк Питер СПб ,Типанова 21</p>\r\n', 'my-otkryvaem-nabor-v-novyj-proekt-po-joge', 'Мы открываем набор в новый проект по йоге', '', '', '2019-04-25 15:43:33', '2019-04-25 16:09:11'),
(18, 10, 180, 'Наш бассейн открыт после ремонта', '2019-03-30', 'Он стал еще лучше, ждем всех на тренировку!', '', '<p>.</p>\r\n', 'nas-bassejn-otkryt-posle-remonta', 'Наш бассейн открыт после ремонта', '', '', '2019-04-25 15:44:29', '2019-04-25 15:44:29'),
(19, 10, 190, 'Открыт набор в мини группу для женщин #BEAUTYFORM', '2019-03-29', 'Гарантированое похудение!', '', '<p>&nbsp;</p>\r\n\r\n<p>ТК Питер открыт набор в мини группу для женщин #BEAUTYFORM c 20.09</p>\r\n', 'otkryt-nabor-v-mini-gruppu-dla-zensin-beautyform', 'Открыт набор в мини группу для женщин #BEAUTYFORM', '', '', '2019-04-25 15:50:38', '2019-04-25 15:50:38'),
(20, 0, 200, 'ДНИ ОТКРЫТЫХ ДВЕРЕЙ В ФИТНЕС-КЛУБЕ EXTRASPORT!!!', '2019-04-25', 'С 1 по 11 Мая! Проводим БЕСПЛАТНЫЙ фитнес марафон! Запись в Отделе продаж! ', '', '<p>ДНИ ОТКРЫТЫХ ДВЕРЕЙ В ФИТНЕС-КЛУБЕ EXTRASPORT!!!</p>\r\n\r\n<p>Фитнес-клуб&nbsp;EXTRASPORT&nbsp;приглашает всех-всех на дни открытых дверей, которые пройдут в клубах с 1 по 11 Мая!!!</p>\r\n\r\n<p>Любой желающий&nbsp;может посетить&nbsp;БЕСПЛАТНЫЕ&nbsp;мастер классы!!!</p>\r\n\r\n<p>Следите за расписанием!&nbsp;</p>\r\n\r\n<p>Подробности и Запись в отделах продаж:</p>\r\n\r\n<p>ExtraSport ТК &quot;ПИТЕР&quot; - 335-69-69</p>\r\n\r\n<p>ExtraSport ТРК &quot;Июнь&quot; - 677-14-33</p>\r\n\r\n<p>ExtraSport ТРК &quot;Южный Полюс&quot; - 622-13-12</p>\r\n\r\n<p><img alt=\"\" src=\"http://extrasport.ru/uploads/image/ckeditor/1556356759_Y8B13bEabBQ.jpg\" style=\"height:960px; width:678px\" /></p>\r\n', 'dni-otkrytyh-dverej-v-fitnes-klube-extrasport', 'ДНИ ОТКРЫТЫХ ДВЕРЕЙ В ФИТНЕС-КЛУБЕ EXTRASPORT!!!', '', '', '2019-04-26 16:55:51', '2019-11-15 09:24:56'),
(21, 0, 210, 'В летний период Детская игровая комната закрыта!', '2019-05-31', 'С 1 июня 2019 года закрывается детская комната на летний период.\r\n', '', '<p><b>С 1 июня 2019 года закрывается детская комната на летний период.</b><br>\r\n<br>\r\nЖдём вас в сентябре!</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Чем ребенок может заняться в детской комнате:</p>\r\n\r\n<p>Заняться оригами, рисованием, лепкой, аппликацией.</p>\r\n\r\n<p>Построить дом из больших мягких модулей.</p>\r\n\r\n<p>Поиграть в настольные игры, собрать конструктор.</p>\r\n\r\n<p>Пообщаться с другими детьми.</p>\r\n\r\n<p>Поиграть в игрушки, машинки, куклы, забавные мячи.</p>\r\n\r\n<p>Подробности по телефону:335-69-69</p>\r\n', 'v-letnij-period-detskaa-igrovaa-komnata-zakryta', 'В летний период Детская игровая комната закрыта!', '', '', '2019-05-31 11:07:40', '2019-09-16 10:44:12'),
(22, 0, 220, 'ЗАКРЫТИЕ ГАРДЕРОБА НА ЛЕТНИЙ ПЕРИОД', '2019-05-31', 'С 15 мая гардероб нашего Фитнес-Клуба будет закрыт на летний период.', '', '<p>Уважаемые Гости, информируем Вас о том, что с 15&nbsp;мая гардероб нашего Фитнес-Клуба будет закрыт на летний период.</p>\r\n', 'zakrytie-garderoba-na-letnij-period', 'ЗАКРЫТИЕ ГАРДЕРОБА НА ЛЕТНИЙ ПЕРИОД', '', '', '2019-05-31 11:30:36', '2019-11-15 09:24:52'),
(23, 10, 230, 'Уважаемые посетители!!!', '2020-03-20', 'С 24 по 31 марта! ', '', '<p>Уважаемые посетители Extra Sport &quot;Матроса Железняка&quot;<br>\r\nС 24 по 31 марта<br>\r\n<b>Аэробный зал будет будет закрыт на монтаж петель для функционального тренинга!!!<br>\r\n1 апреля ждём Вас!</b></p>\r\n\r\n<p>Приносим свои извинения за доставленные неудобства!</p>\r\n\r\n<p>Спасибо за понимание!<br>\r\nС уважением,<br>\r\nАдминистрация Клуба.</p>\r\n\r\n<p><br>\r\n&nbsp;</p>\r\n', 'pereboi', 'Перебои с горячей водой в  ТК \"Питер\"', '', '', '2019-06-14 13:06:19', '2020-03-20 13:18:18'),
(24, 0, 240, 'Срочно требуется Администратор фитнес-клуба! ', '2019-07-11', 'Фитнес клуб ExtraSport Матроса Железника', '', '<p>Перед тем как откликнуться на вакансию, просим обратить Ваше внимание, что утренние смены начинаются с 7.00&nbsp;<br>\r\n<br>\r\nОбязанности:&nbsp;<br>\r\n<br>\r\nвстреча клиентов клуба,&nbsp;<br>\r\nраспределение входящих звонков,&nbsp;<br>\r\nпродажа дополнительных услуг (не продажи абонементов)&nbsp;<br>\r\nисходящие звонки&nbsp;<br>\r\nпрезентация фитнес-клуба&nbsp;<br>\r\nТребования:&nbsp;<br>\r\n<br>\r\nответственность, внимательность, коммуникабельность,&nbsp;<br>\r\nумение работать в команде,&nbsp;<br>\r\nвладение ПК на уровне уверенного пользователя,&nbsp;<br>\r\nжелательно знание кассовой дисциплины,&nbsp;<br>\r\nк рассмотрению принимаются резюме с фото.&nbsp;<br>\r\nУсловия:&nbsp;<br>\r\n<br>\r\nграфик 2/2, полный рабочий день,&nbsp;<br>\r\nработа в большой, сильной компании,&nbsp;<br>\r\nкарьерный рост&nbsp;<br>\r\nоформление по ТК РФ,&nbsp;<br>\r\nвозможность бесплатных занятий в спортивном клубе.<br>\r\n<br>\r\n&nbsp;</p>\r\n\r\n<p><b>По всем вопросам звоните:&nbsp;8(812)335-69-69&nbsp;</b></p>\r\n\r\n<p><br>\r\n<b>Почта: Hr.extrasport@yandex</b></p>\r\n', 'srocno-trebuetsa-administrator-fitnes-kluba', 'Срочно требуется Администратор фитнес-клуба! ', '', '', '2019-07-11 12:14:59', '2019-11-27 08:15:02'),
(25, 10, 250, 'ПРИСОЕДИНЯЙТEСЬ! ', '2020-01-31', 'ЗАВТРА В НОВОМ КЛУБЕ НА МАТРОСА ЖЕЛЕЗНЯКА ПРОЙДУТ ПЕРВЫЕ ТРЕНИРОВКИ CYCLE ‼', '', '<p>ЗАВТРА В НОВОМ КЛУБЕ НА МАТРОСА ЖЕЛЕЗНЯКА ПРОЙДУТ ПЕРВЫЕ ТРЕНИРОВКИ CYCLE!&nbsp;</p>\r\n\r\n<p>Динамичные и очень активные тренировки , которые позволяют сжечь за раз до 700 калорий !<br>\r\n<br>\r\n<b>&nbsp;в 12:00 и 16:00</b><br>\r\n<br>\r\nПредварительная запись по телефону или в в What&rsquo;s APP , клик на ссылку :<br>\r\nhttps://wa.me/+7 (812) 207-50-07<br>\r\n<br>\r\n&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash;&mdash; ExtraSport на Матроса Железняка<br>\r\n⠀⠀&nbsp;ул. Матроса Железняка, д. 57<br>\r\n⠀⠀&nbsp;8 (911) 092-55-55<br>\r\n⠀⠀&nbsp;Чёрная речка/ Пионерская&nbsp;</p>\r\n', 'prisoedinajtes', 'Тренировки по cycle в фитнес-клубе на Матроса Железняка', '', 'В новом клубе на Матроса Железняка пройдут первые тренировки по cycle! Динамичные и очень активные тренировки , которые позволяют сжечь за раз до 700 калорий !', '2020-01-31 20:29:04', '2020-08-10 10:25:09'),
(26, 10, 260, 'ВРЕМЕННОЕ ЗАКРЫТИЕ КЛУБОВ В СВЯЗИ С КОРОНАВИРУСОМ!', '2020-03-24', 'Уважаемые члены клуба!', '', '<p>Уважаемые члены клуба!<br>\r\nВ соответствии с постановлением Правительства Санкт-Петербурга, с четверга, 26 марта 2020 г., мы вынуждены временно прекратить доступ в наши клубы до 30 апреля 2020 г., если не будет особых указаний Правительства.<br>\r\nМы обязательно используем это время с пользой, что бы стать для вас ещё лучше!!!<br>\r\nМы гарантируем продление всех действующих контрактов до даты открытия клубов.<br>\r\nПожалуйста, берегите себя и своих близких!</p>\r\n\r\n<p>По всем вопросам вы можете обращаться по тел. +7 (812) 207-50-07</p>\r\n\r\n<p>С уважением, ваш Extra Sport.</p>\r\n', 'vremennoe-zakrytie-klubov-v-svazi-s-koronavirusom', 'ВРЕМЕННОЕ ЗАКРЫТИЕ КЛУБОВ В СВЯЗИ С КОРОНАВИРУСОМ!', '', '', '2020-03-24 15:07:58', '2020-08-10 10:25:00'),
(27, 10, 270, 'УВАЖАЕМЫЕ КЛИЕНТЫ И ГОСТИ КЛУБА!', '2020-03-25', 'Важная информация! ', '', '<p>К сожалению, по Постановлению Правительства г.Санкт-Петербурга, мы вынуждены приостановить работу наших фитнес-клубов с 26.03.2020 до особых указаний.</p>\r\n\r\n<p>Но! Если вы уже планируете свои грядущие фитнес свершения, то сейчас есть уникальная возможность приобрести абонементы по самым выгодным ценам -&nbsp;<b>ОНЛАЙН РАСПРОДАЖА на сайте.</b></p>\r\n\r\n<p>Наши менеджеры продолжают свою работу удалённо и готовы предложить вам Абонементы по самым выгодным ценам и с активацией в день отмены карантина!&nbsp;</p>\r\n\r\n<p>Оплатить Абонементы можно будет на карту:&nbsp;Тиньков, СПб, Сбербанк, Альфа -&nbsp;<b>Привязаны к номеру телефона:&nbsp;89310048044&nbsp;</b></p>\r\n\r\n<p>На период закрытия в наших клубах будет проведена полная генеральная уборка и произведены все необходимые ремонтные работы, чтобы быть готовыми к нашим новым встречам!</p>\r\n\r\n<p>Берегите себя и своих близких!<br>\r\nСоблюдайте меры предосторожности, тщательно мойте руки и воздержитесь от посещения общественных мест.<br>\r\nМы очень ждём нашей скорой встречи!<br>\r\n⠀<br>\r\nС заботой, ваш&nbsp;<b>Extra Sport</b></p>\r\n', 'uvazaemye-klienty-i-gosti-kluba', 'УВАЖАЕМЫЕ КЛИЕНТЫ И ГОСТИ КЛУБА!', '', '', '2020-03-25 14:18:22', '2020-03-25 14:29:03'),
(28, 10, 280, 'УВАЖАЕМЫЕ КЛИЕНТЫ И ГОСТИ КЛУБА, НОВОЕ ПОСТАНОВЛЕНИЕ!', '2020-04-30', 'Обновленная информация!', '', '<p>В связи с новым постановлением правительства клубы будут закрыты до <b>06.07</b>, следите за новостями на сайте!</p>\r\n\r\n<p>Но! Если вы уже планируете свои грядущие фитнес свершения, то сейчас есть уникальная возможность приобрести абонементы по самым выгодным ценам -&nbsp;ОНЛАЙН РАСПРОДАЖА на сайте.</p>\r\n\r\n<p>Наши менеджеры продолжают свою работу удалённо и готовы предложить вам Абонементы по самым выгодным ценам и с активацией в день отмены карантина!&nbsp;</p>\r\n\r\n<p>Оплатить Абонементы можно будет на карту:&nbsp;<b>Тиньков, СПб, Сбербанк, Альфа -&nbsp;Привязаны к номеру телефона:&nbsp;89310048044&nbsp;</b></p>\r\n\r\n<p>На период закрытия в наших клубах будет проведена полная генеральная уборка и произведены все необходимые ремонтные работы, чтобы быть готовыми к нашим новым встречам!</p>\r\n\r\n<p>Берегите себя и своих близких!<br>\r\nСоблюдайте меры предосторожности, тщательно мойте руки и воздержитесь от посещения общественных мест.<br>\r\nМы очень ждём нашей скорой встречи!<br>\r\n⠀<br>\r\nС заботой, ваш&nbsp;Extra Sport</p>\r\n', 'uvazaemye-klienty-i-gosti-kluba-novoe-postanovlenie', 'УВАЖАЕМЫЕ КЛИЕНТЫ И ГОСТИ КЛУБА, НОВОЕ ПОСТАНОВЛЕНИЕ!', '', '', '2020-04-30 09:17:09', '2020-07-01 16:25:30'),
(29, 10, 290, 'Уважаемые клиенты и гости клуба, хорошие новости! ', '2020-07-03', 'У нас отличные новости!', '', '<p>В связи с новым постановлением правительства от 30.06.2020&nbsp;фитнес клубы в Санкт-Петербурге возобновляют свою работу в течение следующей недели!</p>\r\n\r\n<p>Клубы на&nbsp;<b>Матроса Железняка 57а</b> и в <b>ТРК &quot;Южный Полюс&quot;</b> будут доступны для посещения уже с <b>6 июля</b>!!!</p>\r\n\r\n<p>Остальным клубам необходимо получить QR-код на соответсвие стандартам от Центра Развития и Поддержки предпренимателей.&nbsp;</p>\r\n\r\n<p>Мы подготовили клубы к работе с учётом всех требований безопасности и рекомендаций Роспотребнадзора и уже подали все необходимые документы на получения данного QR-кода.</p>\r\n\r\n<p>Как только мы получим всё необходимое для открытия обязательно сообщим вас в наших социальных сетях и в нашем приложении!&nbsp;</p>\r\n\r\n<p>Приносите собственные полотенца и бутылочки с водой, в целях безопасности кулеры с водой временно недоступны.</p>\r\n', 'uvazaemye-klienty-i-gosti-kluba-horosie-novosti', 'Уважаемые клиенты и гости клуба, хорошие новости! ', '', '', '2020-07-03 11:46:40', '2020-07-03 11:47:44'),
(30, 10, 300, 'Правила Профилактики', '2020-07-06', 'Новой Коронавирусной инфекции ', '', '<p><img alt=\"\" src=\"http://extrasport.ru/uploads/image/ckeditor/1594032047_200026400082_139315.jpg\" style=\"height:1280px; width:905px\"></p>\r\n', 'pravila-profilaktiki', 'Правила Профилактики', '', '', '2020-07-06 10:40:50', '2020-07-06 10:40:50'),
(31, 10, 310, 'С 3 АВГУСТА! ', '2020-07-31', 'НЕОБХОДИМА ЗАПИСЬ НА АЭРОБНЫЕ ЗАНЯТИЯ! ', '', '<p>НЕОБХОДИМА ЗАПИСЬ НА АЭРОБНЫЕ ЗАНЯТИЯ В EXTRA SPORT НА МАТРОСА ЖЕЛЕЗНЯКА !!!<br>\r\n<br>\r\nЗАПИСЬ ПО ТЕЛЕФОНУ:<b>+7 (812) 207-50-07</b></p>\r\n', 's-3-avgusta', 'С 3 АВГУСТА! ', '', '', '2020-07-31 20:45:07', '2020-08-10 10:23:53');
INSERT INTO `news` (`id`, `status`, `position`, `title`, `date`, `intro`, `img`, `content`, `alias`, `meta_title`, `meta_keywords`, `meta_description`, `created_at`, `updated_at`) VALUES
(32, 10, 320, 'ДЕНЬ ОТКРЫТЫХ ДВЕРЕЙ В EXTRASPORT!', '2020-08-28', 'Только 6 сентября! Весь день бесплатные тренировки от ведущих тренеров Extrasport! ', '', '<p>Дорогие друзья! Приглашаем <b>6 сентября на день открытых дверей</b> в фитнес-клуб&nbsp;EXTRASPORT на Матроса Железняка 57А!<br>\r\nВесь день, вас ждут бесплатные тренировки по актуальным направлениям 2020 года!&nbsp; Обязательна предварительная запись по телефону:&nbsp;<b>207-50-07</b></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2><b>10.00 - YOGA ХАТХА</b></h2>\r\n\r\n<p>Это практика, направленная на физическое развитие и поиск душевного равновесия. Помогает улучшить гибкость, растяжку ,чувство баланса и выносливость. Продолжительность: 90 минут;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2><b>12:00- ABL (Abdominal Buttocks Legs) </b></h2>\r\n\r\n<p>Силовой урок, направленный на укрепление мышц ног, ягодиц и живота. Рекомендуется для всех уровней подготовленности</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2><b>13:30- FLEX </b></h2>\r\n\r\n<p>Занятие для всех уровней подготовленности, направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2><b>18.00- CROSS TRAINING</b></h2>\r\n\r\n<p>Совмещает в себе чередование нагрузки. Развитие силовых показателей, взрывной силы. Результат данной программы &ndash;это гармонично развитое тело, укрепление сердечно сосудистой системы, поднятие общего тонуса. Программа адаптирована под любой уровень подготовки</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2><b>19.00- Cycle Endurance (Сайкл студия) </b></h2>\r\n\r\n<p>Тренировка на специальных тренажерах имитирующая велогонку, Направлена на развитие аэробной выносливости. Способствует сжиганию жирового компонента.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h2><b>20:00- TRX (тренинг с использованием тrх петль). </b></h2>\r\n\r\n<p>Тренировка направленная на укрепление мышц всего туловища. Задействуются основные мышечные группы, внутрен6ние мышцы , мышцы стабилизаторы .Это эффективный комплекс упражнений для стройного и подтянутого тела, без осевой нагрузки на позвоночник!</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Колличество мест ограничено! Успей попасть на бесплатные занятия от экспертов Extrasport! <b>Запись по телефону: 207-50-07</b></p>\r\n', 'den-otkrytyh-dverej-v-extrasport', 'ДЕНЬ ОТКРЫТЫХ ДВЕРЕЙ В EXTRASPORT!', '', '', '2020-08-28 10:06:35', '2020-08-28 10:13:38'),
(33, 0, 330, 'Технические неполадки!', '2020-09-01', 'Не можете дозвониться? Звоните по номеру: 8 (911) 092-55-55!', '', '<p>Дорогие клиенты и&nbsp;гости клуба Extrasport, по техническим причинам, у нас неполадки с интернетом и телефонией.</p>\r\n\r\n<p>До устранения неисправностей, все звонки принимаем по номеру:&nbsp;8 (911) 092-55-55!</p>\r\n\r\n<p>Мы приносим&nbsp;вам&nbsp;извинения&nbsp;за&nbsp;причиненные&nbsp;неудобства.</p>\r\n', 'tehniceskie-nepoladki', 'Технические неполадки!', '', '', '2020-09-01 11:36:42', '2020-09-02 07:50:10'),
(34, 10, 340, 'Новое групповое занятие- йогалатес!', '2020-10-15', 'уже с 18.10 .2020 \r\n\r\nПо воскресеньям с 18:00\r\n\r\nТренер Косьяненко Татьяна \r\n', '', '<p>Йогалатес&nbsp;&ndash; необычный симбиоз пилатеса и йоги, которые имеют между собой много общего и схожего.</p>\r\n\r\n<p>Основа обоих направлений &ndash; правильное дыхание, а также упражнения, направленные на развитие гибкости, растяжки и укрепление всего мышечного каркаса.<br>\r\n&nbsp;</p>\r\n\r\n<p>уже с 18.10 .2020&nbsp;</p>\r\n\r\n<p>По воскресеньям с 18:00</p>\r\n\r\n<p>Тренер Косьяненко Татьяна&nbsp;</p>\r\n', 'novoe-gruppovoe-zanatie-jogalates', 'Новое групповое занятие- йогалатес!', '', '', '2020-10-15 14:10:17', '2020-10-15 14:10:17'),
(35, 10, 350, 'ОТКРЫТЫЕ ЗАНЯТИЯ В EXTRA SPORT !', '2020-12-20', 'ОТКРЫТЫЕ ЗАНЯТИЯ БЕСПЛАТНО ДЛЯ ВСЕХ ЖЕЛАЮЩИХ!', '', '<p>New Year&nbsp; &nbsp;latina dance&nbsp;&nbsp;</p>\r\n\r\n<p>28.12.2020&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n\r\n<p>19:30</p>\r\n\r\n<p>Николаева Татьяна</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>New Year&#39;s&nbsp; &nbsp;Hard Round</p>\r\n\r\n<p>29.12.2020</p>\r\n\r\n<p>20:00</p>\r\n\r\n<p>Ольга Тулеева</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>New Year Dance mix</p>\r\n\r\n<p>30.12.2020</p>\r\n\r\n<p>20:30</p>\r\n\r\n<p>Канева Светлана</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Christmas Ball</p>\r\n\r\n<p>30.12.2020</p>\r\n\r\n<p>10:00</p>\r\n\r\n<p>Павлова Евгения</p>\r\n', 'otkrytye-zanatia-v-extra-sport', 'ОТКРЫТЫЕ ЗАНЯТИЯ В EXTRA SPORT !', '', '', '2020-12-19 23:47:21', '2020-12-19 23:47:21'),
(36, 10, 360, 'Марафон Mobility в EXTRA SPORT!', '2021-01-22', '10 Тренировок, чтобы стать лучше!', '', '<p>Марафон направлен на улучшение качества движения в повседневной жизни.<br>\r\nМы будем работать над мобильностью и стабильностью, эластичностью тканей и учиться дыханию.<br>\r\nПо понедельникам и средам будут мягкие тренировки и по субботам более интенсивные.<br>\r\n<br>\r\nВ стоимость марафона входят: МФР ролл длинною 33 &ndash; 45 см и 2 мягких шипованных мячика.<br>\r\n<br>\r\nДанный марафон подойдет тем, кто:<br>\r\nмного сидит в течении дня<br>\r\nхочет снова дышать полной грудью<br>\r\nжелает улучшить показатели эффективности тренировки<br>\r\nхочет повысить качество выполнения упражнений<br>\r\nдавно хочет сесть на шпагат, но не получается<br>\r\nхочет начать тренироваться<br>\r\n<br>\r\nСтоимость :<br>\r\n5500 руб . для клиентов клуба<br>\r\n7000 руб. , если Вы не являйтесь клиентом клуба</p>\r\n', 'marafon-mobility-v-extra-sport', 'Марафон Mobility в EXTRA SPORT!', '', '', '2021-01-22 10:05:20', '2021-01-22 10:05:20'),
(37, 10, 370, 'Приглашаем Вас на мастер-класс по ZUMBA!', '2021-01-27', 'мастер-класс по ZUMBA\r\nсостоится 04.02.2021\r\nВ 18.30.\r\n', '', '<p style=\"text-align:center\">Этот фитнес-танец никого не оставит равнодушным. Зажигательные ритмы включают в себя микс из элементов таких активных танцев, как самба, хип-хоп, сальса, меренге, бачата, кумбия, фламенко.</p>\r\n\r\n<p style=\"text-align:center\">Это заряд бодрости и хорошего настроения.</p>\r\n\r\n<p style=\"text-align:center\">&nbsp;Уроки способствуют похудению, ваше тело будет в тонусе!</p>\r\n\r\n<p>Тренер: Jay Fernando</p>\r\n', 'priglasaem-vas-na-master-klass-po-zumba', 'Приглашаем Вас на мастер-класс по ZUMBA!', '', '', '2021-01-27 13:40:00', '2021-01-27 13:40:00');
INSERT INTO `notifications` (`id`, `title`, `content`, `date`, `created_at`, `updated_at`) VALUES
(1, 'Перебои с горячей водой в  ТК \"Питер\"', '17.06-1.07 перебои с горячей водой! Приносим свои извинения!', '2019-06-14', '2019-06-14 13:32:21', '2019-06-14 13:32:21'),
