INSERT INTO `program_classes` (`id`, `status`, `position`, `title`, `duration`, `intro`, `content`, `group_programs_id`, `color`, `created_at`, `updated_at`) VALUES
(1, 10, 10, 'Непоседы', '50 минут', '<p>Комплексные занятия по 45 минут.</p>\r\n', NULL, 1, '#dddd6e', '2019-04-17 12:45:36', '2019-05-20 11:53:52'),
(2, 10, 20, 'Прыгуны', '50 минут', '<p>Надувные резиновые прыгуны помогают детям поддерживать здоровье</p>\r\n', NULL, 1, '#dddd6e', '2019-04-17 12:45:50', '2019-05-20 11:54:33'),
(3, 10, 30, 'FIT-BALL (7-10)', '50 минут', '<p>Занятия на фитболе для детей не только полезны, но и занимательны. В игровой форме можно укрепить мышцы крохи, научить его основным приемам, которые помогут ребенку в овладении новыми навыкам. ​</p>\r\n', NULL, 1, '#dddd6e', '2019-04-17 12:46:04', '2019-05-20 07:35:34'),
(4, 10, 40, 'Обучение плаванию для детей', '50 минут', '<p>Мы учим детей плавать, а не купаться. Обучение проводят профессиональные тренеры во взрослых бассейнах</p>\r\n', NULL, 2, '#dddd6e', '2019-04-17 12:46:52', '2019-05-20 11:56:31'),
(5, 10, 50, 'Step Аэробика 0', '55 минут', '<p>Групповые занятия степ аэробикой с использованием степ платформы. Рекомендуются после прохождения урока A-Intro. При регулярном посещении занятий вы сможете развить координационные способности, быстро овладеть базовыми шагами и научиться быстро запоминать связки и блоки любой сложности. Интенсивность соответствует цифре, указанной в расписании.</p>\r\n', NULL, 5, '#95bbc2', '2019-04-17 15:11:01', '2019-05-14 14:16:32'),
(6, 10, 60, 'Body Sculpt', '55 минут', '<p>Групповые силовые тренировки, сочетающие тренинг для всех мышечных групп с использованием оборудования и без него. Для всех уровней подготовленности.</p>\r\n', NULL, 6, '#d28d8a', '2019-04-17 15:11:33', '2019-04-17 15:15:23'),
(7, 10, 70, 'Upper Body', '55 минут', '<p>Силовой урок Upper Body направлен на развитие мышц верхней части тела: рук, плечевого пояса, спины и брюшного пресса. Для всех уровней подготовленности</p>\r\n', NULL, 6, '#d28d8a', '2019-04-17 15:11:48', '2019-04-17 15:15:19'),
(8, 10, 80, 'LowerBody (ABL)', '55 минут', '<p>Групповые силовые тренировки, направленные на укрепление мышц ног, ягодиц и живота. Рекомендуется для всех уровней подготовленности</p>\r\n', NULL, 6, '#d28d8a', '2019-04-17 15:12:15', '2019-04-17 15:15:14'),
(9, 10, 90, 'Pump it up', '55 минут', '<p>Современная версия силовой тренировки для всех мышечных групп с использованием специальной штанги. Для всех уровней подготовленности. 55 минут.</p>\r\n', NULL, 6, NULL, '2019-04-26 15:51:51', '2019-04-26 15:51:51'),
(10, 10, 100, 'BUMS и ABS', '30 минут', '<p>Тренировка для максимального воздействия на мышцы ягодиц. Занятие обеспечивает необходимой нагрузкой именно эту зону, позволяя быстро добиваться желаемых результатов. Для всех уровней подготовленности.</p>\r\n', NULL, 6, NULL, '2019-04-26 15:52:10', '2019-05-20 11:58:23'),
(11, 10, 110, 'Fit Ball', '55 минут', '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', NULL, 7, NULL, '2019-04-26 15:56:57', '2019-04-26 15:56:57'),
(12, 10, 120, 'Callanetics', '55 минут', '<p>Силовая статическая тренировка для всех групп мышц, направленная на улучшение пропорций тела. Для всех уровней подготовленности</p>\r\n', NULL, 7, NULL, '2019-04-26 15:57:15', '2019-04-26 15:57:15'),
(13, 10, 130, 'Pilates', '55 минут', '<p>Занятие по системе Пилатеса, подходит для любого возраста и уровня подготовки. Особенно полезен тем, кто имеет проблемы с позвоночником. Групповые занятия пилатесом способствуют укреплению и формированию внутренних глубоких мышц. 55 минут.</p>\r\n\r\n<p>Занятия пилатесом проводятся по следующим направлениям:</p>\r\n\r\n<p>Pilates Beginner<br />\r\nТренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n\r\n<p>Power Pilates<br />\r\nТренировка на основе системы Пилатеса с использованием дополнительного силового оборудования.</p>\r\n', NULL, 7, NULL, '2019-04-26 15:57:31', '2019-04-26 15:57:31'),
(14, 10, 140, 'Yoga 1,5', '', '<p>Индийская гимнастика Йога направлена на улучшение психоэмоционального состояния в целом, а также повышение силы и гибкости тела.&nbsp;<br />\r\nПрактика древних асан (поз Йоги) поможет укрепить мышцы спины и исправить осанку, обрести отличную форму, овладеть принципами правильного глубокого дыхания и укрепить иммунную систему.&nbsp;<br />\r\nРекомендовано для всех уровней подготовленности.</p>\r\n', NULL, 7, NULL, '2019-04-26 15:57:51', '2019-04-26 15:57:51'),
(15, 10, 150, 'Flex', '45 минут', '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', NULL, 7, NULL, '2019-04-26 15:58:15', '2020-02-12 13:31:08'),
(16, 10, 160, 'ABS', '30 минут', '<p>Тренировка для укрепления мышц брюшного пресса. Рекомендуется для всех уровней подготовленности</p>\r\n', NULL, 7, NULL, '2019-04-26 15:58:37', '2019-04-26 15:58:37'),
(17, 10, 170, 'Body Flex', '55 минут', '<p>Дыхательная гимнастика. Включает в себя комплекс физических упражнений и аэробное дыхание. Лучший способ похудеть независимо от возраста и диет. Для всех уровней подготовленности</p>\r\n', NULL, 7, NULL, '2019-04-26 15:59:56', '2019-04-26 15:59:56'),
(18, 10, 180, 'Belly Dance', '55 минут', '<p>Танцевальный урок, основанный на использовании элементов восточного &quot;танца живота&quot;</p>\r\n', NULL, 8, NULL, '2019-04-26 16:00:19', '2019-04-26 16:00:19'),
(19, 10, 190, 'Strip Dance', '55 минут', '<p>Стрип танец раскрепощения, страсти и чувственности, который завораживает не только ваши сердца, но и заставляет затаить дыхание случайных, а может и не очень случайных, наблюдателей. Двигаясь в режиме Non-stop, вы тренируете сердце и избавляетесь от лишних килограммов. Для всех уровней подготовленности</p>\r\n', NULL, 8, NULL, '2019-04-26 16:00:40', '2019-04-26 16:00:40'),
(20, 10, 200, 'Latina', '55 минут', '<p>Зажигательный урок танцев в стиле латиноамериканских танцев. Занятие танцевальной аэробикой для всех уровней подготовленности</p>\r\n', NULL, 8, NULL, '2019-04-26 16:00:55', '2019-04-26 16:00:55'),
(21, 10, 210, 'Zumba Dance', '55 минут', '<p>Это современное занятие танцевальной аэробикой, в котором смешалось множество стилей: афро и латиноамериканские танцы, элементы сальсы, самбы, меренги, фламенко, реггетона, хип-хопа, break-dance, go-go, клубная латина, ча-ча-ча, танец живота</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/4qaps9s1LUo\" width=\"640\"></iframe></p>\r\n', NULL, 8, NULL, '2019-04-26 16:01:11', '2021-08-17 11:18:36'),
(22, 10, 220, 'Танго', '55 минут', '<p>Танцевальный урок, направленный на развитие чувства ритма, координации, пластичности. На занятиях используются элементы аргентинского танго, которые сочетаются с элементами танго из европейской программы спортивных бальных танцев, что делает занятие уникальным</p>\r\n', NULL, 8, NULL, '2019-04-26 16:01:28', '2019-04-26 16:01:28'),
(23, 10, 230, 'Dance class', '55 минут', '<p>Занятие танцевальной аэробикой, которое включает в себя элементы танго, вальса, фокстрота. Для всех уровней подготовленности</p>\r\n', NULL, 8, NULL, '2019-04-26 16:02:00', '2019-04-26 16:02:00'),
(24, 10, 240, 'Jazz Modern', '55 минут', '<p>Стиль, являющийся воплощением красоты и грации. Урок танцевальной аэробики проходит и под безумные ритмы афро-джаза,и под произведения классики. Вы обретете красоту, легкость и грацию. Добьетесь отличной формы, гибкости и пластичности. Стилизация: эротика, этнический мотив, фолк, танец живота, фламенко, балет, уличные клубные танцы</p>\r\n', NULL, 8, NULL, '2019-04-26 16:02:15', '2019-04-26 16:02:15'),
(25, 10, 250, 'Functional training', '', '<p>Силовой урок для всех мышечных групп с использованием оборудования и без него.&nbsp;<br />\r\nВ отличие от других силовых занятий, здесь упражнения складываются в комбинацию, что делает это занятие не только эффективным, но и интересным.&nbsp;<br />\r\nВ процессе занятия тренируются взрывная сила, координация, ловкость, баланс.&nbsp;<br />\r\nВ упражнениях задействовано максимально возможное количество мышц-стабилизаторов. Рекомендуется тем, кто уже имеет опыт тренировок.</p>\r\n', NULL, 9, NULL, '2019-04-26 16:02:39', '2019-04-26 16:02:39'),
(26, 10, 260, 'Cycle', '55 минут', '<p>Cycle - групповой урок с использованием специальных тренажеров, имитирующий велосипедную гонку.<br>\r\nВелосипед, применяемый в фитнес-системе, хорошо приспособлен к закрытым помещениям.<br>\r\nТВ нашем клубе тренировка сопровождается видеорядом, что позволяет максимально погрузиться в условия реальной велопрогулки.<br>\r\nЭто прекрасный способ подтянуть мышцы и похудеть!<br>\r\nВыбирайте занятие, которое соответствует Вашему уровню подготовленности!</p>\r\n', NULL, 10, NULL, '2019-04-26 16:03:00', '2019-05-09 08:29:09'),
(27, 10, 270, 'Cycle Intro', '', '<p>Основа СYCLE. Сайкл тренировки для начинающих</p>\r\n', NULL, 10, NULL, '2019-04-26 16:03:12', '2019-04-26 16:03:12'),
(28, 10, 280, 'Cycle Endurance', '55 минут', '<p>Тренировка аэробной выносливости, максимальное сжигание жира.</p>\r\n', NULL, 10, NULL, '2019-04-26 16:03:38', '2019-05-09 08:36:09'),
(29, 10, 290, 'Cycle Strength', '55 минут', '<p>Тренировка сил и общей выносливости. Для всех уровней подготовленности</p>\r\n', NULL, 10, NULL, '2019-04-26 16:03:58', '2019-05-09 08:36:19'),
(30, 10, 300, 'Cycle Interval', '', '<p>Высокоинтенсивная тренировка СYCLE, дающая быстрый и ощутимый эффект. Проводится в интервальном режиме. Занятие СYCLE для подготовленных</p>\r\n', NULL, 10, NULL, '2019-04-26 16:04:16', '2019-04-26 16:04:16'),
(31, 10, 310, 'Cycle Race Day', '', '<p>Имитация скоростной велогонки, направлена на развитие сердечно-сосудистой системы. Высокая интенсивность. Занятие СYCLE для подготовленных.</p>\r\n', NULL, 10, NULL, '2019-04-26 16:04:28', '2019-04-26 16:04:28'),
(32, 10, 320, 'Step Interval', '55 минут', '<p>Тренировка с чередованием аэробных и силовых компонентов. Средняя интенсивность. Для всех уровней подготовленности</p>\r\n', NULL, 11, NULL, '2019-04-26 16:04:51', '2019-04-26 16:04:51'),
(33, 10, 330, 'Круговая тренировка', '55 минут', '<p>Тренировка, направленная на снижение избыточного веса и проработку основных мышечных групп, включает в себя как кардио нагрузки, так и силовые, также улучшает настроение и повышает мышечный тонус</p>\r\n', NULL, 11, NULL, '2019-04-26 16:05:05', '2019-04-26 16:05:05'),
(34, 10, 340, 'ТАБАТА', '45 минут', '<p>ТАБАТА &mdash; система интервальных тренировок, разработанная японским врачом Идзуми Табата. Суть ее состоит в повторении несложных упражнений в максимально быстром темпе. Результат &mdash; уменьшение жировой прослойки и укрепление мышц.&nbsp;</p>\r\n', NULL, 11, NULL, '2019-04-26 16:07:51', '2019-04-26 16:08:17'),
(35, 10, 350, 'ABS+FLEX', '', '<p>Занятие</p>\r\n', NULL, 11, NULL, '2019-04-29 11:56:10', '2019-04-29 11:56:10'),
(36, 10, 360, 'Fitness Dance', '', '<p>Тема здоровья, питания и активного образа жизни сегодня как никогда актуальна. А где здоровье &ndash; там движение и, конечно, спорт, фитнес и танцы.</p>\r\n', NULL, 8, NULL, '2019-04-29 11:58:16', '2019-05-20 12:21:35'),
(37, 10, 370, 'Step Аэробика 1', '', '<p>Групповые занятия степ аэробикой с использованием степ платформы. Рекомендуются после прохождения урока A-Intro. При регулярном посещении занятий вы сможете развить координационные способности, быстро овладеть базовыми шагами и научиться быстро запоминать связки и блоки любой сложности. Интенсивность соответствует цифре, указанной в расписании.</p>\r\n', NULL, 5, NULL, '2019-05-14 14:16:57', '2019-05-14 14:17:20'),
(38, 10, 380, 'Step Аэробика 2', '', '<p>Групповые занятия степ аэробикой с использованием степ платформы. Рекомендуются после прохождения урока A-Intro. При регулярном посещении занятий вы сможете развить координационные способности, быстро овладеть базовыми шагами и научиться быстро запоминать связки и блоки любой сложности. Интенсивность соответствует цифре, указанной в расписании.</p>\r\n', NULL, 5, NULL, '2019-05-14 14:17:07', '2019-05-14 14:17:25'),
(39, 10, 390, 'YOGA 1.5 \"XATХA\"', '', '<p>Yoga</p>\r\n', NULL, 7, NULL, '2019-05-15 13:27:26', '2019-05-20 12:18:07'),
(40, 10, 400, 'Step interval', '', '<p>Step interval &ndash; это аэробная тренировка с использованием степ-платформы.</p>\r\n', NULL, 5, NULL, '2019-05-15 13:29:39', '2019-05-20 11:57:09'),
(41, 10, 410, 'Junior йога', '', '<p>Изучение и совершенствование oсанки, а также развитие гибкости, координации движений, чувства равновесия; улучшение осанки.</p>\r\n', NULL, 1, NULL, '2019-05-15 13:34:07', '2019-08-10 15:04:45'),
(42, 10, 420, 'ВИИТ', '', '<p>Чередование интервалов высокой интенсивности и периодов отдыха. Так можно охарактеризовать ВИИТ. В данном тренировочном протоколе не принято считать повторения. Периоды отсчитываются секундами и минутами, а не целевыми повторениями выбранного движения.</p>\r\n', NULL, 7, NULL, '2019-05-15 13:37:09', '2019-05-15 13:37:09'),
(43, 10, 430, 'TOTAL STRETCH', '', '<p>Данная программа предназначена для тех, кто готов потратить на свое здоровье час своего времени. Не жалейте времени на растяжку! Тренировки по данной программе улучшают гибкость и подвижность суставов, способствуют снятию стресса и глубокому расслаблению.</p>\r\n', NULL, 7, NULL, '2019-05-15 13:40:22', '2019-05-15 13:40:22'),
(44, 10, 440, 'Танго SOLO', '', '<p>Танцевальный урок, направленный на развитие чувства ритма, координации, пластичности. На занятиях используются элементы аргентинского танго, которые сочетаются с элементами танго из европейской программы спортивных бальных танцев, что делает занятие уникальным</p>\r\n', NULL, 8, NULL, '2019-05-15 13:42:32', '2019-05-20 12:21:54'),
(45, 10, 450, 'Tae-bo', '', '<p>Тайбо &mdash; это фитнес-программа высокой интенсивности, которая включает в себя, движения из таких дисциплин, как бокс, каратэ и таэквондо, замиксованных с аэробными шагами и дополненных классическими силовыми упражнениями.</p>\r\n', NULL, 6, NULL, '2019-05-15 13:44:45', '2019-05-20 12:13:24'),
(46, 10, 460, 'Велогонка 9-14 лет (рост от 150)', '', '<p>Тренировка на стационарных велотренажерах, имитирующая велогонку</p>\r\n', NULL, 10, NULL, '2019-05-15 13:46:21', '2019-05-20 12:30:59'),
(47, 10, 470, 'Hard Raund (8-11 лет) ', '', '<p>Помогает закалить организм, подготовить его к более тяжелым нагрузкам</p>\r\n', NULL, 1, NULL, '2019-05-15 13:48:32', '2019-09-17 08:52:29'),
(48, 10, 480, 'Strong Bums', '', '<p>Это фитнес направление, в котором занятие представляет собой сочетание специальных нагрузок нижней части спины</p>\r\n', NULL, 6, NULL, '2019-05-15 13:51:27', '2019-05-20 12:15:07'),
(49, 10, 490, 'Круговая TRX', '', '<p>Круговая тренировка &ndash; отдельный тип занятий, который позволяет внести разнообразие в рабочий процесс, достигать поставленных целей более эффективно. Это один из самых популярных видов тренинга в мире.</p>\r\n', NULL, 11, NULL, '2019-05-15 13:56:59', '2019-05-15 13:56:59'),
(50, 10, 500, 'Cycle Power', '', '<p>Высокоинтенсивная кардиотренировка</p>\r\n', NULL, 10, NULL, '2019-05-15 13:58:32', '2019-05-15 13:58:32'),
(51, 10, 510, 'Baby Dance от 4 лет', '', '<p>Baby Dance - танцевальное направление для детей от 4-х лет, программа включает в себя гармоничное развитие физических и танцевальных, а также музыкальных данных юных танцоров.</p>\r\n', NULL, 1, NULL, '2019-05-15 14:03:13', '2019-05-15 14:03:13'),
(52, 10, 520, 'Здоровые спинки 5-8 лет', '', '<p>Комплекс упражнений &quot;Здоровые спинки&quot;&nbsp;это программа осуществляющая профилактику нарушения осанки у детей дошкольного возраста. Она предполагает достаточную двигательную активность ребенка, продолжительность статических и динамических нагрузок в пределах возрастной нормы.</p>\r\n', NULL, 1, NULL, '2019-05-15 14:04:19', '2019-09-08 20:38:49'),
(53, 10, 530, 'Contemporary Dance', '', '<p>Cовременный сценический танец, включающий в себя самые различные направления и техники.</p>\r\n', NULL, 8, NULL, '2019-05-15 14:07:01', '2019-05-20 12:22:12'),
(54, 10, 540, 'ZumDance', '', '<p>Это разновидность танцевального фитнеса, основанного на зажигательных мотивах и чувственных движениях клубной латины.</p>\r\n', NULL, 8, NULL, '2019-05-15 14:11:10', '2019-05-20 12:22:30'),
(55, 10, 550, 'Бокс', '', '<p>Кулачный бой в специальных перчатках по определённым правилам между двумя спортсменами.</p>\r\n', NULL, 6, NULL, '2019-05-15 14:11:43', '2019-05-15 14:11:43'),
(56, 10, 560, 'Кикбоксинг', '', '<p>Кикбоксинг включает в себя несколько видов восточных единоборств. Это и карате, и тхэквандо, и ушу, плюс бокс: тайский и английский. С английского кикбоксинг переводится как поединок руками и ногами, что и применяется в кикбоксинге. Здесь дерутся и руками, и ногами, как на средней, так и на дальней дистанции. Бить можно в полную силу в любые части тела. В кикбоксинге можно сражаться без обуви, это классический вариант, или в специальной обуви, французский вариант.</p>\r\n', NULL, 6, NULL, '2019-05-15 14:12:32', '2019-05-25 06:06:36'),
(57, 10, 570, 'Bums + FLEX', '', '<p>Система спортивной гимнастической тренировки, состоящая из двух блоков.</p>\r\n\r\n<p>Первую часть комплекса &ndash; bums: составляют силовые упражнения. Они рассчитаны в основном на укрепление мышц ягодичных. Вторую часть комплекса &ndash; flex: создают расслабляющие и растягивающие упражнения. Они рассчитаны на укрепление и поддержание в тонусе мышц тазобедренных.</p>\r\n', NULL, 6, NULL, '2019-05-15 14:25:24', '2019-05-20 12:53:20'),
(58, 10, 580, 'Form up', '', '<p>Занятие, разработанное специально для женщин. Направлено на проработку ягодиц, мышц внутренней и внешней поверхности бедра, а так же грудных мышц и задней поверхности рук.</p>\r\n', NULL, 7, NULL, '2019-05-16 15:47:46', '2019-05-20 12:19:34'),
(59, 10, 590, 'Dance mix', '', '<p>Смешанный танец &ndash; занятия на похудение, коррекцию фигуры и просто отлично проведенное свободное время. Занятия dance mix для всех и каждого</p>\r\n', NULL, 8, NULL, '2019-05-20 08:22:27', '2019-05-20 12:26:01'),
(60, 10, 600, 'Pilates Beginner', '', '<p>Тренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n', NULL, 7, NULL, '2019-06-19 07:51:46', '2019-06-19 07:51:46'),
(61, 10, 610, ' Yoga Advanced ', '', '<p>Можно назвать класс как уровень сложности - продвинутый. Добавляются сложные прогибы назад, стойки на руках и предплечьях, балансы на руках, вариации в ширшасане и сарвангасане, глубокие наклоны вперед, сложные скрутки, падмасана, лодочные позы, позы на раскрытие таза, отстройка стоячих асан, работа в парах и тройках, основы работы с концентрацией и медитация,йога нидра.</p>\r\n', NULL, 7, NULL, '2019-06-23 11:25:53', '2019-06-23 11:25:53'),
(62, 10, 620, 'Outdoor yoga ', '', '<p>1,5 часа</p>\r\n', NULL, 7, NULL, '2019-07-23 13:43:44', '2019-07-23 13:43:44'),
(63, 10, 630, 'Stretch', '', '<p>здоровая гибкая спина</p>\r\n', NULL, 7, NULL, '2019-07-23 13:44:15', '2019-07-23 13:44:15'),
(64, 10, 640, 'Disco Games 3-5 лет ', '', '<p>3-5 лет&nbsp;</p>\r\n', NULL, 1, NULL, '2019-09-08 20:30:28', '2019-09-08 20:30:28'),
(65, 10, 650, 'Велогонки 9-14 лет', '', '<p>&nbsp;(Рост от 150 см, 9-14 лет)</p>\r\n', NULL, 1, NULL, '2019-09-08 20:31:34', '2019-09-09 10:30:36'),
(66, 10, 660, 'Baby Fit (5-7лет)', '', '<p>BABY&nbsp;FIT&nbsp;приглашает на занятия самых маленьких спортсменов. Физическое развитие детей движется семимильными шагами</p>\r\n', NULL, 1, NULL, '2019-09-08 20:41:41', '2019-09-08 20:41:41'),
(67, 10, 670, 'Baby Fit (3-5лет)', '', '<p>BABY&nbsp;FIT&nbsp;приглашает на занятия самых маленьких спортсменов. Физическое развитие детей&nbsp;движется семимильными шагами</p>\r\n', NULL, 1, NULL, '2019-09-08 20:42:02', '2019-09-08 20:42:02'),
(68, 10, 680, 'Круговая тренировка (8-11)', '', '<p>Для детей!</p>\r\n', NULL, 1, NULL, '2019-09-08 20:42:22', '2019-09-08 20:42:22'),
(69, 10, 690, 'Бокс  (7-10 лет)                ', '', '<p>Для детей<br>\r\n<iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/xWmRH-sei-k\" width=\"640\"></iframe></p>\r\n', NULL, 1, NULL, '2019-09-08 20:47:14', '2021-08-17 11:22:59'),
(70, 10, 700, 'Кикбоксинг (4-7 лет)', '', '<p>Для детей!</p>\r\n', NULL, 1, NULL, '2019-09-08 20:47:26', '2019-09-08 20:47:26'),
(71, 10, 710, 'Junior йога от 8 лет ', '', '<p>Изучение и совершенствование oсанки, а также развитие гибкости, координации движений, чувства равновесия; улучшение осанки.</p>\r\n', NULL, 1, NULL, '2019-09-09 10:27:39', '2019-09-09 10:27:39'),
(72, 10, 720, 'Dance mix(8-11 лет) ', '', '<p>(8-11 лет)&nbsp;</p>\r\n', NULL, 1, NULL, '2019-09-17 08:59:59', '2019-09-17 08:59:59'),
(73, 10, 730, 'HARD RAUND (10-14 ЛЕТ)', '', '<p>10-14 ЛЕТ</p>\r\n', NULL, 1, NULL, '2019-09-17 09:00:58', '2019-09-17 09:00:58'),
(74, 10, 740, ' INTERVAL MIX ', '', '<p>Эффективная аэробно-силовая тренировка, направленная на максимальное жиросжигание и тонус всего тела, с использованием различного оборудования. Направлена на проработку основных мышечных групп с наибольшим акцентом на проблемные зоны. Способствует активному сжиганию лишнего жира, значительному ускорению обмена веществ, повышению выносливости. Нагрузка высокой и средней интенсивностей.</p>\r\n', NULL, 7, NULL, '2019-09-22 19:20:40', '2019-09-22 19:20:40'),
(75, 10, 750, 'Face Building Studio ', '', '<p>Фейсбилдинг это упражнения для сохранения нашей естественной красоты и молодости лица. Мы же занимаемся спортом для тела, мы хотим быть красивыми и здоровыми, так вот и для лица нужны упражнения и движение.</p>\r\n\r\n<p>Ведь на лице тоже есть мышцы и много! Мы об этом не задумываемся. Так что мышцам и лица и тела нужно движение. С этим ведь не поспоришь?</p>\r\n', NULL, 7, NULL, '2019-10-08 08:02:28', '2019-10-08 08:02:28'),
(76, 10, 760, 'ПроСушись30', '', '<p><b><em>В процессе требуется: </em></b></p>\r\n\r\n<p><b><em>- Замеры &laquo;до&raquo;/ &laquo;после&raquo;</em></b></p>\r\n\r\n<p><b><em>-Фото &laquo;до&raquo;/ &laquo;после&raquo;</em></b></p>\r\n\r\n<p><b><em>-Отчеты по домашнему заданию</em></b></p>\r\n\r\n<p><b><em>- Отчеты по питанию.</em></b></p>\r\n\r\n<p><b><em>Посещать тренировки в клубе 3 раза в неделю по расписанию марафона.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </em></b></p>\r\n\r\n<p><b><em>По окончанию проекта, победитель будет выбран жюри и с помощью голосования в соц сети). Победитель получит желаемый результат и супер приз - Абонемент. Все остальные участники получат отличный результат от участия в марафоне. Проигравших нет!</em></b></p>\r\n', NULL, 7, NULL, '2019-10-20 11:32:37', '2019-10-20 11:32:37'),
(77, 10, 770, 'Face Building', '', '<p>Это практика, направленная на тренировку мышц лица, шеи и декольте, в сочетании с их массажем. - В первую очередь гимнастика позволит: подтянуть овал лица; - избавиться от второго подбородка;- уменьшить носогубные складки и глубокие морщины на лбу.</p>\r\n', NULL, 7, NULL, '2019-10-20 11:33:06', '2019-10-20 11:33:42'),
(78, 10, 780, 'Открытый урок «Choreo»', '', '<p>На занятиях по Choreo будут такие направления как twerk, dancehall, heels. На занятиях мы будем учить небольшие хоряжки, учиться слышать музыку и импровизировать! На урок берём с собой самые любимые и удобные каблуки</p>\r\n', NULL, 8, NULL, '2019-10-20 11:34:14', '2019-10-20 11:34:14'),
(79, 10, 790, 'Super Sculpt', '', '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/hZabOEB_Gvg\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/RoLozEqpwag\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/-Sn8TIaN6v8\" width=\"640\"></iframe></p>\r\n', NULL, 7, NULL, '2020-02-12 13:27:55', '2021-08-17 11:22:20'),
(80, 10, 800, 'Cross Power', '', '<p>Это отличное дополнение к занятиям в тренажерном зале. Тренировка, направленная на развитие выносливости, взрывной силы, скорости, улучшает ваши силовые показатели. Кроме того &ndash; это отличный способ избавиться от лишней массы. Занятие включает в себя элементы из интервальных тренировок высокой интенсивности, тяжелой атлетики, легкой атлетики, пауэрлифтинга, гимнастики и других видов спорта.</p>\r\n', NULL, 6, NULL, '2020-02-12 13:36:31', '2020-02-12 13:36:31'),
(81, 10, 810, 'Dynamic Flow', '', '<p>Сочетание силовых упражнений, функциональных движений - 3D, элементов йоги и растяжки в одном уроке! Урок направлен на развитие силы мышц, гибкости , укрепляет глобокие мышцы , мышцы стабилизаторы .</p>\r\n', NULL, 7, NULL, '2020-02-12 13:37:51', '2020-02-12 13:37:51'),
(82, 10, 820, 'cross training', '', '<p>Это&nbsp;идеальное условие для всех желающих улучшить свои физические результаты и психологическую форму, а также укрепить общее состояние</p>\r\n', NULL, 7, NULL, '2020-07-05 17:16:13', '2020-07-05 17:16:13'),
(83, 10, 830, 'Core&stretching', '', '<p>новое направление в фитнесе, которое использует за основу статичные позы вместо привычных активных движений. Занятия направлены в основном на проработку мышц кора и пресса, а в дополнение &ndash; растяжка основных мышц.</p>\r\n', NULL, 7, NULL, '2020-07-05 17:17:58', '2020-07-05 17:17:58'),
(84, 10, 840, 'Combat', '', '<p>это&nbsp;фитнес-программа, основанная на сочетании элементов из боевых искусств, аэробики и танцев.</p>\r\n', NULL, 7, NULL, '2020-07-05 17:21:03', '2020-07-05 17:21:03'),
(85, 10, 850, 'TRX  Functional', '', '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', NULL, 7, NULL, '2020-07-24 11:09:02', '2020-07-24 11:09:02'),
(86, 10, 860, 'YOGA                 Мастер-класс     ', '', '<p>Мастер класс по йоге</p>\r\n', NULL, 7, NULL, '2020-07-24 11:09:53', '2020-07-24 11:09:53'),
(87, 10, 870, 'Мастер-класс     Functional core TRX', '', '<p>Мастер класс по TRX</p>\r\n', NULL, 7, NULL, '2020-07-24 11:10:37', '2020-07-24 11:10:37'),
(88, 10, 880, 'Мастер-класс                      CROSS TRAINING', '', '<p>Мастер класс по Cross Training</p>\r\n', NULL, 7, NULL, '2020-07-24 11:11:28', '2020-07-24 11:11:28'),
(89, 10, 890, 'Buttocks&Stretch', '', '<p>Новое занятие!&nbsp;</p>\r\n', NULL, 7, NULL, '2020-08-02 21:27:33', '2020-08-02 21:27:33'),
(90, 10, 900, 'Energy Zone', '', '<p>Мастер Класс!&nbsp;</p>\r\n', NULL, 7, NULL, '2020-08-02 21:28:59', '2020-08-02 21:28:59'),
(91, 10, 910, 'YOGA Power ', '', '<p>Мастер Класс!!!</p>\r\n', NULL, 7, NULL, '2020-08-02 21:42:08', '2020-08-02 21:42:08'),
(92, 10, 920, 'AERO*YOGA ', '55 минут', '<p>Аэройога ( антигравити йога ) &ndash; это занятия классической Хатха Йоги, перенесенные на гамак. Название от английского Aeroyoga in hammoc, воздушная йога в гамаках.</p>\r\n\r\n<p>В гамаке начинают работать мышцы, которые в повседневной жизни не работают. Упражнения запускают все действия в организме, иммунную систему, репродуктивную, нормализуется гормональный фон у женщин, сердечно-сосудистую систему, вестибулярный аппарат &ndash; это отмечается уже на 4-5 занятии. Перевернутые асаны запускают омолаживающий процесс в организме, улучшается цвет лица, мышцы становятся более упругими.</p>\r\n\r\n<p>При выполнении упражнений в гамаке, тренируются не только основные крупные группы мышц, но и стабилизирующие мышцы, создавая гармоничный мышечный каркас всего тела. При выполнении упражнений одновременно работают различные группы мышц, призванные сохранять равновесие в качающемся гамаке, поддерживать вес тела, и своевременно включиться при изменении положения тела. Важно, что нагрузка на мышечную систему всегда достаточна и ощутима, но не чрезмерна, т.к. ограничивается собственным весом.</p>\r\n\r\n<p>Всего 4 места!!<br>\r\n<br>\r\n<iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/faxaD-rksQY\" width=\"640\"></iframe></p>\r\n', NULL, 7, NULL, '2020-08-24 07:07:08', '2021-08-17 11:20:23'),
(93, 10, 930, 'Aero stretching', '55 минут', '<p>Единственная в&nbsp;своем роде методика растяжки мышечных групп и&nbsp;связок. Ее&nbsp;основное отличие от&nbsp;классических методов состоит в&nbsp;использовании специализированных гамаков.&nbsp; Является смесью йоги, растяжки и&nbsp;воздушной гимнастики.</p>\r\n\r\n<p>Занимаясь аэрострейчингом&nbsp;каждый может уделять внимание душе и телу в равной степени, или направлять больше усилий в ту сторону, которую считает менее развитой.</p>\r\n', NULL, 7, NULL, '2020-08-31 09:27:00', '2020-08-31 09:27:00'),
(94, 10, 940, 'Vinyasa Flow ', '', '<p>Виньяса-флоу йога &mdash; это направление, которое сохраняет в себе традиции Хатха-йоги, но с использованием динамичных связок.</p>\r\n\r\n<p>Важный момент йоги флоу &mdash; чередование расслабления и напряжения. Это происходит благодаря изменению ритма асан, соответственно, ритм дыхания становится более медленным. Во время перехода к выполнению следующей асаны, следует динамическая связка &mdash; виньяса.&nbsp;</p>\r\n', NULL, 7, NULL, '2020-09-07 08:09:36', '2020-09-07 08:09:36'),
(95, 10, 950, 'Йогалатес', '', '<p>Удивительное сочетание йоги и пилатеса.</p>\r\n', NULL, 14, NULL, '2020-10-16 12:40:59', '2020-10-16 12:40:59'),
(101, 10, 960, 'Женский бокс', '', '<p>Кто сказал, что бокс это исключительно мужской вид спорта?! Сегодня представительницы прекрасной половины человечества активно проявляют себя на ринге. Сочетаются ли бокс и женственность? Утверждаем однозначно: да!</p>\r\n', NULL, 6, NULL, '2020-11-16 06:46:43', '2020-11-16 06:46:43'),
