(116, 0, 1110, 'Бокс для новичков', '', '<p>Введение в технику бокса, постановка стоек,общая физ подготовка.</p>\r\n', NULL, 6, NULL, '2022-10-21 08:16:17', '2022-10-21 08:16:48'),
(117, 0, 1120, 'Реггетон', '', '<p>Реггетон &ndash; стиль танца, являющейся визитной карточкой латины. Свобода, сексуальность, откровенность &ndash; вот краткая характеристика танцевального направления. Его танцуют как девушки, так и парни, соло или же в паре. Хочешь сексуально самовыразиться и раскрепоститься? Начни освоение этого завораживающего и до ужаса простого танца. Несмотря на молодость танца, он обрел очень большую популярность во всем мире. Помимо этого его относят к танцевальным фитнес-направлениям из-за возможности в кратчайшие сроки сформировать фигуру и поддерживать форму без особых усилий.</p>\r\n', NULL, 8, NULL, '2023-03-05 19:07:35', '2023-03-07 11:34:53'),
(118, 10, 1130, 'ОФП (6-10 лет)', '', '<p>ОФП (6-10 лет)</p>\r\n', NULL, 1, NULL, '2023-04-17 00:47:37', '2023-04-17 00:47:37');
