(2908, 10, '2020-10-05', '21:30:00', 0, 1, 0, '<p>Занятие по системе Пилатеса, подходит для любого возраста и уровня подготовки. Особенно полезен тем, кто имеет проблемы с позвоночником. Групповые занятия пилатесом способствуют укреплению и формированию внутренних глубоких мышц. 55 минут.</p>\r\n\r\n<p>Занятия пилатесом проводятся по следующим направлениям:</p>\r\n\r\n<p>Pilates Beginner<br />\r\nТренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n\r\n<p>Power Pilates<br />\r\nТренировка на основе системы Пилатеса с использованием дополнительного силового оборудования.</p>\r\n', 13, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2909, 10, '2020-10-06', '09:30:00', 1, 1, 1, '<p>Виньяса-флоу йога &mdash; это направление, которое сохраняет в себе традиции Хатха-йоги, но с использованием динамичных связок.</p>\r\n\r\n<p>Важный момент йоги флоу &mdash; чередование расслабления и напряжения. Это происходит благодаря изменению ритма асан, соответственно, ритм дыхания становится более медленным. Во время перехода к выполнению следующей асаны, следует динамическая связка &mdash; виньяса.&nbsp;</p>\r\n', 94, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2910, 10, '2020-10-06', '11:00:00', 0, 1, 0, '<p>Групповые силовые тренировки, направленные на укрепление мышц ног, ягодиц и живота. Рекомендуется для всех уровней подготовленности</p>\r\n', 8, 0, 6, 1, 36, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2911, 10, '2020-10-06', '18:45:00', 0, 1, 0, '<p>Силовой урок Upper Body направлен на развитие мышц верхней части тела: рук, плечевого пояса, спины и брюшного пресса. Для всех уровней подготовленности</p>\r\n', 7, 0, 6, 1, 35, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2912, 10, '2020-10-06', '20:00:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n', 79, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2913, 10, '2020-10-06', '21:00:00', 0, 1, 1, '<p>Новое занятие!&nbsp;</p>\r\n', 89, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2914, 10, '2020-10-07', '10:00:00', 0, 1, 0, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10');
INSERT INTO `rasp` (`id`, `status`, `date`, `time`, `is_pay`, `is_preliminary`, `is_new`, `comment`, `program_classes_id`, `type_rasp_id`, `group_programs_id`, `rooms_id`, `trainer_id`, `last_trainer_id`, `created_at`, `updated_at`) VALUES
(2915, 10, '2020-10-07', '19:00:00', 1, 1, 1, '<p>Аэройога ( антигравити йога ) &ndash; это занятия классической Хатха Йоги, перенесенные на гамак. Название от английского Aeroyoga in hammoc, воздушная йога в гамаках.</p>\r\n\r\n<p>В гамаке начинают работать мышцы, которые в повседневной жизни не работают. Упражнения запускают все действия в организме, иммунную систему, репродуктивную, нормализуется гормональный фон у женщин, сердечно-сосудистую систему, вестибулярный аппарат &ndash; это отмечается уже на 4-5 занятии. Перевернутые асаны запускают омолаживающий процесс в организме, улучшается цвет лица, мышцы становятся более упругими.</p>\r\n\r\n<p>При выполнении упражнений в гамаке, тренируются не только основные крупные группы мышц, но и стабилизирующие мышцы, создавая гармоничный мышечный каркас всего тела. При выполнении упражнений одновременно работают различные группы мышц, призванные сохранять равновесие в качающемся гамаке, поддерживать вес тела, и своевременно включиться при изменении положения тела. Важно, что нагрузка на мышечную систему всегда достаточна и ощутима, но не чрезмерна, т.к. ограничивается собственным весом.</p>\r\n\r\n<p>Всего 4 места!!</p>\r\n', 92, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2916, 10, '2020-10-07', '20:30:00', 0, 1, 0, '<p>Занятие танцевальной аэробикой, которое включает в себя элементы танго, вальса, фокстрота. Для всех уровней подготовленности</p>\r\n', 23, 0, 8, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2917, 10, '2020-10-07', '21:30:00', 0, 1, 0, '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', 15, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2918, 10, '2020-10-08', '08:00:00', 1, 1, 1, '<p>Круговая тренировка &ndash; отдельный тип занятий, который позволяет внести разнообразие в рабочий процесс, достигать поставленных целей более эффективно. Это один из самых популярных видов тренинга в мире.</p>\r\n', 49, 0, 11, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2919, 10, '2020-10-08', '10:00:00', 0, 1, 0, '<p>Групповые силовые тренировки, сочетающие тренинг для всех мышечных групп с использованием оборудования и без него. Для всех уровней подготовленности.</p>\r\n', 6, 0, 6, 1, 36, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2920, 10, '2020-10-08', '19:45:00', 0, 1, 0, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2921, 10, '2020-10-08', '20:45:00', 0, 1, 0, '<p>Занятие по системе Пилатеса, подходит для любого возраста и уровня подготовки. Особенно полезен тем, кто имеет проблемы с позвоночником. Групповые занятия пилатесом способствуют укреплению и формированию внутренних глубоких мышц. 55 минут.</p>\r\n\r\n<p>Занятия пилатесом проводятся по следующим направлениям:</p>\r\n\r\n<p>Pilates Beginner<br />\r\nТренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n\r\n<p>Power Pilates<br />\r\nТренировка на основе системы Пилатеса с использованием дополнительного силового оборудования.</p>\r\n', 13, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
(2922, 10, '2020-10-08', '21:45:00', 0, 1, 0, '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', 15, 0, 7, 1, NULL, NULL, '2020-10-04 13:51:10', '2020-10-04 13:51:10'),
