(3037, 10, '2020-10-30', '20:00:00', 0, 1, 0, '<p>Тренировка аэробной выносливости, максимальное сжигание жира.</p>\r\n', 28, 0, 10, 6, 35, NULL, '2020-10-25 13:38:39', '2020-10-25 13:38:39'),
