(3391, 10, '2020-12-14', '10:00:00', 1, 1, 0, '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', 85, 0, 7, 1, NULL, NULL, '2020-12-13 13:05:43', '2020-12-13 13:05:43'),
