(3622, 10, '2021-01-19', '09:30:00', 1, 1, 1, '<p>Виньяса-флоу йога &mdash; это направление, которое сохраняет в себе традиции Хатха-йоги, но с использованием динамичных связок.</p>\r\n\r\n<p>Важный момент йоги флоу &mdash; чередование расслабления и напряжения. Это происходит благодаря изменению ритма асан, соответственно, ритм дыхания становится более медленным. Во время перехода к выполнению следующей асаны, следует динамическая связка &mdash; виньяса.&nbsp;</p>\r\n', 94, 0, 7, 1, NULL, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3623, 10, '2021-01-19', '11:00:00', 0, 1, 0, '<p>Групповые силовые тренировки, направленные на укрепление мышц ног, ягодиц и живота. Рекомендуется для всех уровней подготовленности</p>\r\n', 8, 0, 6, 1, NULL, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3624, 10, '2021-01-19', '19:00:00', 0, 1, 0, '<p>Силовой урок Upper Body направлен на развитие мышц верхней части тела: рук, плечевого пояса, спины и брюшного пресса. Для всех уровней подготовленности</p>\r\n', 7, 0, 6, 1, 35, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3625, 10, '2021-01-19', '20:00:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n', 79, 0, 7, 1, NULL, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3626, 10, '2021-01-19', '21:00:00', 0, 1, 1, '<p>Новое занятие!&nbsp;</p>\r\n', 89, 0, 7, 1, NULL, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3627, 10, '2021-01-20', '10:00:00', 0, 1, 0, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, NULL, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31');
INSERT INTO `rasp` (`id`, `status`, `date`, `time`, `is_pay`, `is_preliminary`, `is_new`, `comment`, `program_classes_id`, `type_rasp_id`, `group_programs_id`, `rooms_id`, `trainer_id`, `last_trainer_id`, `created_at`, `updated_at`) VALUES
(3628, 10, '2021-01-20', '19:00:00', 1, 1, 1, '<p>Аэройога ( антигравити йога ) &ndash; это занятия классической Хатха Йоги, перенесенные на гамак. Название от английского Aeroyoga in hammoc, воздушная йога в гамаках.</p>\r\n\r\n<p>В гамаке начинают работать мышцы, которые в повседневной жизни не работают. Упражнения запускают все действия в организме, иммунную систему, репродуктивную, нормализуется гормональный фон у женщин, сердечно-сосудистую систему, вестибулярный аппарат &ndash; это отмечается уже на 4-5 занятии. Перевернутые асаны запускают омолаживающий процесс в организме, улучшается цвет лица, мышцы становятся более упругими.</p>\r\n\r\n<p>При выполнении упражнений в гамаке, тренируются не только основные крупные группы мышц, но и стабилизирующие мышцы, создавая гармоничный мышечный каркас всего тела. При выполнении упражнений одновременно работают различные группы мышц, призванные сохранять равновесие в качающемся гамаке, поддерживать вес тела, и своевременно включиться при изменении положения тела. Важно, что нагрузка на мышечную систему всегда достаточна и ощутима, но не чрезмерна, т.к. ограничивается собственным весом.</p>\r\n\r\n<p>Всего 4 места!!</p>\r\n', 92, 0, 7, 1, NULL, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3631, 10, '2021-01-21', '08:00:00', 1, 1, 1, '<p>Круговая тренировка &ndash; отдельный тип занятий, который позволяет внести разнообразие в рабочий процесс, достигать поставленных целей более эффективно. Это один из самых популярных видов тренинга в мире.</p>\r\n', 49, 0, 11, 1, 40, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3632, 10, '2021-01-21', '10:00:00', 0, 1, 0, '<p>Групповые силовые тренировки, сочетающие тренинг для всех мышечных групп с использованием оборудования и без него. Для всех уровней подготовленности.</p>\r\n', 6, 0, 6, 1, NULL, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3633, 10, '2021-01-21', '19:45:00', 0, 1, 0, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, 39, NULL, '2021-01-17 17:43:31', '2021-01-17 17:48:49'),
(3634, 10, '2021-01-21', '20:45:00', 0, 1, 0, '<p>Занятие по системе Пилатеса, подходит для любого возраста и уровня подготовки. Особенно полезен тем, кто имеет проблемы с позвоночником. Групповые занятия пилатесом способствуют укреплению и формированию внутренних глубоких мышц. 55 минут.</p>\r\n\r\n<p>Занятия пилатесом проводятся по следующим направлениям:</p>\r\n\r\n<p>Pilates Beginner<br />\r\nТренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n\r\n<p>Power Pilates<br />\r\nТренировка на основе системы Пилатеса с использованием дополнительного силового оборудования.</p>\r\n', 13, 0, 7, 1, 39, NULL, '2021-01-17 17:43:31', '2021-01-17 17:48:58'),
(3635, 10, '2021-01-21', '21:45:00', 0, 1, 1, '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', 15, 0, 7, 1, 39, NULL, '2021-01-17 17:43:31', '2021-01-17 17:49:08'),
(3637, 10, '2021-01-22', '19:00:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n', 79, 0, 7, 1, 35, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
(3638, 10, '2021-01-22', '20:00:00', 0, 1, 0, '<p>Тренировка аэробной выносливости, максимальное сжигание жира.</p>\r\n', 28, 0, 10, 6, 35, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
