(3650, 10, '2021-01-18', '10:00:00', 1, 1, 0, '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', 85, 0, 7, 1, NULL, NULL, '2021-01-17 17:43:31', '2021-01-17 17:43:31'),
