(3826, 10, '2021-02-18', '09:00:00', 0, 1, 0, '<p>Основа СYCLE. Сайкл тренировки для начинающих</p>\r\n', 27, 0, 10, 6, 40, NULL, '2021-02-14 13:08:19', '2021-02-14 13:08:19'),
