(3913, 10, '2021-03-01', '10:00:00', 1, 1, 0, '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', 85, 0, 7, 1, NULL, NULL, '2021-02-28 18:23:22', '2021-02-28 18:23:22'),
