(4416, 10, '2021-05-24', '12:00:00', 1, 1, 0, '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', 85, 0, 7, 1, NULL, NULL, '2021-05-22 20:08:06', '2021-05-22 20:08:06'),
