(5936, 10, '2022-02-06', '13:00:00', 0, 1, 0, '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', 15, 0, 7, 1, NULL, NULL, '2022-01-27 20:31:13', '2022-01-27 20:31:13'),
(5937, 10, '2022-02-06', '19:00:00', 0, 1, 0, '<p>Удивительное сочетание йоги и пилатеса.</p>\r\n', 95, 0, 14, 1, 51, NULL, '2022-01-27 20:31:13', '2022-02-06 11:08:01'),
(5938, 10, '2022-01-31', '12:00:00', 1, 1, 0, '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', 85, 0, 7, 1, NULL, NULL, '2022-01-27 20:31:13', '2022-01-27 20:31:13'),
(5939, 10, '2022-02-05', '17:30:00', 1, 1, 0, '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', 85, 0, 7, 1, 36, NULL, '2022-01-27 20:31:13', '2022-01-27 20:31:13'),
(5940, 10, '2022-02-03', '11:00:00', 0, 1, 0, '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', 15, 0, 7, 1, 36, NULL, '2022-01-27 20:31:13', '2022-01-27 20:31:13'),
(5941, 10, '2022-02-06', '20:00:00', 1, 1, 0, '<p>Единственная в&nbsp;своем роде методика растяжки мышечных групп и&nbsp;связок. Ее&nbsp;основное отличие от&nbsp;классических методов состоит в&nbsp;использовании специализированных гамаков.&nbsp; Является смесью йоги, растяжки и&nbsp;воздушной гимнастики.</p>\r\n\r\n<p>Занимаясь аэрострейчингом&nbsp;каждый может уделять внимание душе и телу в равной степени, или направлять больше усилий в ту сторону, которую считает менее развитой.</p>\r\n', 93, 0, 7, 1, NULL, NULL, '2022-01-27 20:31:13', '2022-01-27 20:31:13'),
(5942, 0, '2022-01-31', '20:30:00', 0, 1, 0, '<p>Занятие по системе Пилатеса, подходит для любого возраста и уровня подготовки. Особенно полезен тем, кто имеет проблемы с позвоночником. Групповые занятия пилатесом способствуют укреплению и формированию внутренних глубоких мышц. 55 минут.</p>\r\n\r\n<p>Занятия пилатесом проводятся по следующим направлениям:</p>\r\n\r\n<p>Pilates Beginner<br />\r\nТренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n\r\n<p>Power Pilates<br />\r\nТренировка на основе системы Пилатеса с использованием дополнительного силового оборудования.</p>\r\n', 13, 0, 7, 1, 39, NULL, '2022-01-27 20:31:13', '2022-01-30 16:52:41'),
(5943, 10, '2022-02-05', '13:00:00', 1, 1, 1, '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', 85, 0, 7, 1, 36, NULL, '2022-01-27 20:31:13', '2022-01-27 20:31:13');
INSERT INTO `rasp` (`id`, `status`, `date`, `time`, `is_pay`, `is_preliminary`, `is_new`, `comment`, `program_classes_id`, `type_rasp_id`, `group_programs_id`, `rooms_id`, `trainer_id`, `last_trainer_id`, `created_at`, `updated_at`) VALUES
(5944, 10, '2022-02-05', '09:30:00', 1, 1, 1, '<p>Аэройога ( антигравити йога ) &ndash; это занятия классической Хатха Йоги, перенесенные на гамак. Название от английского Aeroyoga in hammoc, воздушная йога в гамаках.</p>\r\n\r\n<p>В гамаке начинают работать мышцы, которые в повседневной жизни не работают. Упражнения запускают все действия в организме, иммунную систему, репродуктивную, нормализуется гормональный фон у женщин, сердечно-сосудистую систему, вестибулярный аппарат &ndash; это отмечается уже на 4-5 занятии. Перевернутые асаны запускают омолаживающий процесс в организме, улучшается цвет лица, мышцы становятся более упругими.</p>\r\n\r\n<p>При выполнении упражнений в гамаке, тренируются не только основные крупные группы мышц, но и стабилизирующие мышцы, создавая гармоничный мышечный каркас всего тела. При выполнении упражнений одновременно работают различные группы мышц, призванные сохранять равновесие в качающемся гамаке, поддерживать вес тела, и своевременно включиться при изменении положения тела. Важно, что нагрузка на мышечную систему всегда достаточна и ощутима, но не чрезмерна, т.к. ограничивается собственным весом.</p>\r\n\r\n<p>Всего 4 места!!</p>\r\n', 92, 0, 7, 1, NULL, NULL, '2022-01-27 20:31:13', '2022-01-27 20:31:13'),
(5945, 10, '2022-02-03', '17:30:00', 1, 1, 1, '<p>Для детей<br>\r\n<iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/xWmRH-sei-k\" width=\"640\"></iframe></p>\r\n', 69, 0, 1, 1, 52, NULL, '2022-01-27 20:31:13', '2022-01-31 13:12:34'),
(5946, 10, '2022-02-03', '18:30:00', 1, 1, 1, '<p>Кулачный бой в специальных перчатках по определённым правилам между двумя спортсменами.</p>\r\n', 55, 0, 6, 1, 52, NULL, '2022-01-27 20:31:13', '2022-01-31 13:12:44'),
(5947, 10, '2022-02-01', '18:00:00', 1, 1, 1, '<p>Кулачный бой в специальных перчатках по определённым правилам между двумя спортсменами.</p>\r\n', 55, 0, 6, 1, 52, NULL, '2022-01-27 20:31:13', '2022-01-31 13:12:22'),
(5948, 10, '2022-02-01', '17:00:00', 1, 1, 0, '<p>Кулачный бой в специальных перчатках по определённым правилам между двумя спортсменами.</p>\r\n', 55, 0, 6, 5, 52, NULL, '2022-01-27 20:31:13', '2022-01-31 13:12:05'),
(5949, 10, '2022-02-04', '20:00:00', 0, 1, 1, '<p>Это современное занятие танцевальной аэробикой, в котором смешалось множество стилей: афро и латиноамериканские танцы, элементы сальсы, самбы, меренги, фламенко, реггетона, хип-хопа, break-dance, go-go, клубная латина, ча-ча-ча, танец живота</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/4qaps9s1LUo\" width=\"640\"></iframe></p>\r\n', 21, 0, 8, 1, 53, NULL, '2022-01-27 20:31:13', '2022-01-31 13:13:08'),
(5950, 10, '2022-02-02', '18:00:00', 0, 1, 1, '<p>Индийская гимнастика Йога направлена на улучшение психоэмоционального состояния в целом, а также повышение силы и гибкости тела.&nbsp;<br />\r\nПрактика древних асан (поз Йоги) поможет укрепить мышцы спины и исправить осанку, обрести отличную форму, овладеть принципами правильного глубокого дыхания и укрепить иммунную систему.&nbsp;<br />\r\nРекомендовано для всех уровней подготовленности.</p>\r\n', 14, 0, 7, 1, 51, NULL, '2022-01-27 20:38:35', '2022-02-02 11:33:01'),
(5951, 10, '2022-02-07', '11:00:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n', 79, 0, 7, 1, NULL, NULL, '2022-02-04 22:07:39', '2022-02-04 22:07:39'),
(5952, 10, '2022-02-07', '18:30:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/hZabOEB_Gvg\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/RoLozEqpwag\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/-Sn8TIaN6v8\" width=\"640\"></iframe></p>\r\n', 79, 0, 7, 1, 39, 39, '2022-02-04 22:07:39', '2022-02-04 22:09:44'),
(5953, 10, '2022-02-07', '19:30:00', 0, 1, 0, '<p>Данная программа предназначена для тех, кто готов потратить на свое здоровье час своего времени. Не жалейте времени на растяжку! Тренировки по данной программе улучшают гибкость и подвижность суставов, способствуют снятию стресса и глубокому расслаблению.</p>\r\n', 43, 0, 7, 1, 39, NULL, '2022-02-04 22:07:39', '2022-02-04 22:09:55'),
(5954, 10, '2022-02-08', '11:00:00', 0, 1, 0, '<p>Групповые силовые тренировки, направленные на укрепление мышц ног, ягодиц и живота. Рекомендуется для всех уровней подготовленности</p>\r\n', 8, 0, 6, 1, NULL, NULL, '2022-02-04 22:07:39', '2022-02-04 22:07:39'),
(5955, 10, '2022-02-08', '19:00:00', 0, 1, 0, '<p>Силовой урок Upper Body направлен на развитие мышц верхней части тела: рук, плечевого пояса, спины и брюшного пресса. Для всех уровней подготовленности</p>\r\n', 7, 0, 6, 1, 35, NULL, '2022-02-04 22:07:39', '2022-02-04 22:07:39'),
