(6055, 10, '2022-02-24', '11:00:00', 0, 1, 0, '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', 15, 0, 7, 1, 36, NULL, '2022-02-18 13:31:41', '2022-02-18 13:31:41'),
(6056, 10, '2022-02-27', '20:00:00', 1, 1, 0, '<p>Единственная в&nbsp;своем роде методика растяжки мышечных групп и&nbsp;связок. Ее&nbsp;основное отличие от&nbsp;классических методов состоит в&nbsp;использовании специализированных гамаков.&nbsp; Является смесью йоги, растяжки и&nbsp;воздушной гимнастики.</p>\r\n\r\n<p>Занимаясь аэрострейчингом&nbsp;каждый может уделять внимание душе и телу в равной степени, или направлять больше усилий в ту сторону, которую считает менее развитой.</p>\r\n', 93, 0, 7, 1, NULL, NULL, '2022-02-18 13:31:41', '2022-02-18 13:31:41'),
(6057, 10, '2022-02-21', '20:30:00', 0, 1, 0, '<p>Занятие по системе Пилатеса, подходит для любого возраста и уровня подготовки. Особенно полезен тем, кто имеет проблемы с позвоночником. Групповые занятия пилатесом способствуют укреплению и формированию внутренних глубоких мышц. 55 минут.</p>\r\n\r\n<p>Занятия пилатесом проводятся по следующим направлениям:</p>\r\n\r\n<p>Pilates Beginner<br />\r\nТренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n\r\n<p>Power Pilates<br />\r\nТренировка на основе системы Пилатеса с использованием дополнительного силового оборудования.</p>\r\n', 13, 0, 7, 1, 39, NULL, '2022-02-18 13:31:41', '2022-02-18 13:31:41'),
(6058, 10, '2022-02-26', '13:00:00', 1, 1, 1, '<p>это&nbsp;силовая тренировка с собственным весом или дополнительным оборудованием</p>\r\n', 85, 0, 7, 1, 36, NULL, '2022-02-18 13:31:41', '2022-02-18 13:31:41');
INSERT INTO `rasp` (`id`, `status`, `date`, `time`, `is_pay`, `is_preliminary`, `is_new`, `comment`, `program_classes_id`, `type_rasp_id`, `group_programs_id`, `rooms_id`, `trainer_id`, `last_trainer_id`, `created_at`, `updated_at`) VALUES
(6059, 10, '2022-02-26', '09:30:00', 1, 1, 1, '<p>Аэройога ( антигравити йога ) &ndash; это занятия классической Хатха Йоги, перенесенные на гамак. Название от английского Aeroyoga in hammoc, воздушная йога в гамаках.</p>\r\n\r\n<p>В гамаке начинают работать мышцы, которые в повседневной жизни не работают. Упражнения запускают все действия в организме, иммунную систему, репродуктивную, нормализуется гормональный фон у женщин, сердечно-сосудистую систему, вестибулярный аппарат &ndash; это отмечается уже на 4-5 занятии. Перевернутые асаны запускают омолаживающий процесс в организме, улучшается цвет лица, мышцы становятся более упругими.</p>\r\n\r\n<p>При выполнении упражнений в гамаке, тренируются не только основные крупные группы мышц, но и стабилизирующие мышцы, создавая гармоничный мышечный каркас всего тела. При выполнении упражнений одновременно работают различные группы мышц, призванные сохранять равновесие в качающемся гамаке, поддерживать вес тела, и своевременно включиться при изменении положения тела. Важно, что нагрузка на мышечную систему всегда достаточна и ощутима, но не чрезмерна, т.к. ограничивается собственным весом.</p>\r\n\r\n<p>Всего 4 места!!</p>\r\n', 92, 0, 7, 1, NULL, NULL, '2022-02-18 13:31:41', '2022-02-18 13:31:41'),
(6060, 10, '2022-02-24', '17:30:00', 1, 1, 1, '<p>Для детей<br>\r\n<iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/xWmRH-sei-k\" width=\"640\"></iframe></p>\r\n', 69, 0, 1, 1, 52, NULL, '2022-02-18 13:31:41', '2022-02-18 13:31:41'),
(6061, 10, '2022-02-24', '18:30:00', 1, 1, 1, '<p>Кулачный бой в специальных перчатках по определённым правилам между двумя спортсменами.</p>\r\n', 55, 0, 6, 1, 52, NULL, '2022-02-18 13:31:41', '2022-02-18 13:31:41'),
