INSERT INTO `rasp` (`id`, `status`, `date`, `time`, `is_pay`, `is_preliminary`, `is_new`, `comment`, `program_classes_id`, `type_rasp_id`, `group_programs_id`, `rooms_id`, `trainer_id`, `last_trainer_id`, `created_at`, `updated_at`) VALUES
(6410, 10, '2022-04-29', '20:00:00', 0, 1, 1, '<p>Это современное занятие танцевальной аэробикой, в котором смешалось множество стилей: афро и латиноамериканские танцы, элементы сальсы, самбы, меренги, фламенко, реггетона, хип-хопа, break-dance, go-go, клубная латина, ча-ча-ча, танец живота</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/4qaps9s1LUo\" width=\"640\"></iframe></p>\r\n', 21, 0, 8, 1, 53, NULL, '2022-04-20 19:53:04', '2022-04-20 19:53:04'),
(6411, 10, '2022-04-27', '18:00:00', 0, 1, 1, '<p>Индийская гимнастика Йога направлена на улучшение психоэмоционального состояния в целом, а также повышение силы и гибкости тела.&nbsp;<br />\r\nПрактика древних асан (поз Йоги) поможет укрепить мышцы спины и исправить осанку, обрести отличную форму, овладеть принципами правильного глубокого дыхания и укрепить иммунную систему.&nbsp;<br />\r\nРекомендовано для всех уровней подготовленности.</p>\r\n', 14, 0, 7, 1, 51, NULL, '2022-04-20 19:53:04', '2022-04-20 19:53:04'),
(6412, 10, '2022-04-30', '10:30:00', 1, 1, 1, '<p>Индийская гимнастика Йога направлена на улучшение психоэмоционального состояния в целом, а также повышение силы и гибкости тела.&nbsp;<br />\r\nПрактика древних асан (поз Йоги) поможет укрепить мышцы спины и исправить осанку, обрести отличную форму, овладеть принципами правильного глубокого дыхания и укрепить иммунную систему.&nbsp;<br />\r\nРекомендовано для всех уровней подготовленности.</p>\r\n', 14, 0, 7, 1, 51, NULL, '2022-04-20 19:53:04', '2022-04-20 19:53:04'),
(6413, 10, '2022-04-29', '18:00:00', 1, 1, 1, '<p>Аэройога ( антигравити йога ) &ndash; это занятия классической Хатха Йоги, перенесенные на гамак. Название от английского Aeroyoga in hammoc, воздушная йога в гамаках.</p>\r\n\r\n<p>В гамаке начинают работать мышцы, которые в повседневной жизни не работают. Упражнения запускают все действия в организме, иммунную систему, репродуктивную, нормализуется гормональный фон у женщин, сердечно-сосудистую систему, вестибулярный аппарат &ndash; это отмечается уже на 4-5 занятии. Перевернутые асаны запускают омолаживающий процесс в организме, улучшается цвет лица, мышцы становятся более упругими.</p>\r\n\r\n<p>При выполнении упражнений в гамаке, тренируются не только основные крупные группы мышц, но и стабилизирующие мышцы, создавая гармоничный мышечный каркас всего тела. При выполнении упражнений одновременно работают различные группы мышц, призванные сохранять равновесие в качающемся гамаке, поддерживать вес тела, и своевременно включиться при изменении положения тела. Важно, что нагрузка на мышечную систему всегда достаточна и ощутима, но не чрезмерна, т.к. ограничивается собственным весом.</p>\r\n\r\n<p>Всего 4 места!!<br>\r\n<br>\r\n<iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/faxaD-rksQY\" width=\"640\"></iframe></p>\r\n', 92, 0, 7, 1, NULL, NULL, '2022-04-20 19:53:04', '2022-04-20 19:53:04'),
(6605, 10, '2022-05-02', '11:00:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n', 79, 0, 7, 1, NULL, NULL, '2022-05-01 11:46:32', '2022-05-01 11:46:32'),
(6606, 10, '2022-05-02', '17:30:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/hZabOEB_Gvg\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/RoLozEqpwag\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/-Sn8TIaN6v8\" width=\"640\"></iframe></p>\r\n', 79, 0, 7, 1, 39, 39, '2022-05-01 11:46:32', '2022-05-01 11:46:44'),
(6607, 10, '2022-05-02', '18:30:00', 0, 1, 0, '<p>Данная программа предназначена для тех, кто готов потратить на свое здоровье час своего времени. Не жалейте времени на растяжку! Тренировки по данной программе улучшают гибкость и подвижность суставов, способствуют снятию стресса и глубокому расслаблению.</p>\r\n', 43, 0, 7, 1, 39, NULL, '2022-05-01 11:46:32', '2022-05-01 11:46:54'),
(6608, 10, '2022-05-03', '11:00:00', 0, 1, 0, '<p>Групповые силовые тренировки, направленные на укрепление мышц ног, ягодиц и живота. Рекомендуется для всех уровней подготовленности</p>\r\n', 8, 0, 6, 1, NULL, NULL, '2022-05-01 11:46:32', '2022-05-01 11:46:32'),
(6609, 10, '2022-05-03', '18:00:00', 0, 1, 0, '<p>Силовой урок Upper Body направлен на развитие мышц верхней части тела: рук, плечевого пояса, спины и брюшного пресса. Для всех уровней подготовленности</p>\r\n', 7, 0, 6, 1, 35, NULL, '2022-05-01 11:46:32', '2022-05-01 11:47:38'),
(6610, 10, '2022-05-03', '19:00:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/hZabOEB_Gvg\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/RoLozEqpwag\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/-Sn8TIaN6v8\" width=\"640\"></iframe></p>\r\n', 79, 0, 7, 1, 35, NULL, '2022-05-01 11:46:32', '2022-05-01 11:47:48'),
(6611, 10, '2022-05-03', '20:00:00', 0, 1, 1, '<p>Новое занятие!&nbsp;</p>\r\n', 89, 0, 7, 1, 35, NULL, '2022-05-01 11:46:32', '2022-05-01 11:47:56'),
(6612, 10, '2022-05-04', '10:00:00', 0, 1, 0, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, NULL, NULL, '2022-05-01 11:46:32', '2022-05-01 11:46:32'),
(6613, 10, '2022-05-04', '19:30:00', 0, 1, 0, '<p>Занятие танцевальной аэробикой, которое включает в себя элементы танго, вальса, фокстрота. Для всех уровней подготовленности</p>\r\n', 23, 0, 8, 1, 54, NULL, '2022-05-01 11:46:32', '2022-05-01 11:52:15'),
(6614, 10, '2022-05-04', '20:30:00', 0, 1, 0, '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', 15, 0, 7, 1, 54, NULL, '2022-05-01 11:46:32', '2022-05-01 11:52:24'),
(6615, 10, '2022-05-05', '10:00:00', 0, 1, 0, '<p>Силовой урок для всех мышечных групп с использованием оборудования и без него.&nbsp;<br />\r\nВ отличие от других силовых занятий, здесь упражнения складываются в комбинацию, что делает это занятие не только эффективным, но и интересным.&nbsp;<br />\r\nВ процессе занятия тренируются взрывная сила, координация, ловкость, баланс.&nbsp;<br />\r\nВ упражнениях задействовано максимально возможное количество мышц-стабилизаторов. Рекомендуется тем, кто уже имеет опыт тренировок.</p>\r\n', 25, 0, 9, 1, 36, NULL, '2022-05-01 11:46:32', '2022-05-01 11:46:32'),
(6616, 10, '2022-05-05', '19:45:00', 0, 1, 0, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, 39, NULL, '2022-05-01 11:46:32', '2022-05-01 11:46:32'),
(6617, 10, '2022-05-05', '20:45:00', 0, 1, 0, '<p>Занятие по системе Пилатеса, подходит для любого возраста и уровня подготовки. Особенно полезен тем, кто имеет проблемы с позвоночником. Групповые занятия пилатесом способствуют укреплению и формированию внутренних глубоких мышц. 55 минут.</p>\r\n\r\n<p>Занятия пилатесом проводятся по следующим направлениям:</p>\r\n\r\n<p>Pilates Beginner<br />\r\nТренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n\r\n<p>Power Pilates<br />\r\nТренировка на основе системы Пилатеса с использованием дополнительного силового оборудования.</p>\r\n', 13, 0, 7, 1, 39, NULL, '2022-05-01 11:46:32', '2022-05-01 11:46:32'),
