(8399, 10, '2023-02-11', '10:00:00', 0, 1, 0, '<p>Это современное занятие танцевальной аэробикой, в котором смешалось множество стилей: афро и латиноамериканские танцы, элементы сальсы, самбы, меренги, фламенко, реггетона, хип-хопа, break-dance, go-go, клубная латина, ча-ча-ча, танец живота</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/4qaps9s1LUo\" width=\"640\"></iframe></p>\r\n', 21, 0, 8, 1, 53, NULL, '2023-02-04 08:23:03', '2023-02-04 08:23:03'),
(8400, 10, '2023-02-11', '17:00:00', 0, 1, 1, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, 63, NULL, '2023-02-04 08:23:03', '2023-02-04 08:23:03'),
(8401, 10, '2023-02-10', '20:00:00', 0, 1, 1, '<p>Индийская гимнастика Йога направлена на улучшение психоэмоционального состояния в целом, а также повышение силы и гибкости тела.&nbsp;<br />\r\nПрактика древних асан (поз Йоги) поможет укрепить мышцы спины и исправить осанку, обрести отличную форму, овладеть принципами правильного глубокого дыхания и укрепить иммунную систему.&nbsp;<br />\r\nРекомендовано для всех уровней подготовленности.</p>\r\n', 14, 0, 7, 1, NULL, NULL, '2023-02-04 08:23:03', '2023-02-04 08:23:03');
INSERT INTO `rasp` (`id`, `status`, `date`, `time`, `is_pay`, `is_preliminary`, `is_new`, `comment`, `program_classes_id`, `type_rasp_id`, `group_programs_id`, `rooms_id`, `trainer_id`, `last_trainer_id`, `created_at`, `updated_at`) VALUES
(8402, 10, '2023-02-13', '11:00:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/hZabOEB_Gvg\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/RoLozEqpwag\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/-Sn8TIaN6v8\" width=\"640\"></iframe></p>\r\n', 79, 0, 7, 1, 61, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8403, 10, '2023-02-13', '19:45:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/hZabOEB_Gvg\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/RoLozEqpwag\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/-Sn8TIaN6v8\" width=\"640\"></iframe></p>\r\n', 79, 0, 7, 1, 39, 39, '2023-02-10 23:10:49', '2023-02-10 23:11:45'),
(8404, 10, '2023-02-13', '21:45:00', 0, 1, 0, '<p>Занятие по системе Пилатеса, подходит для любого возраста и уровня подготовки. Особенно полезен тем, кто имеет проблемы с позвоночником. Групповые занятия пилатесом способствуют укреплению и формированию внутренних глубоких мышц. 55 минут.</p>\r\n\r\n<p>Занятия пилатесом проводятся по следующим направлениям:</p>\r\n\r\n<p>Pilates Beginner<br />\r\nТренировка для тех, кто только начинает осваивать технику упражнений.</p>\r\n\r\n<p>Power Pilates<br />\r\nТренировка на основе системы Пилатеса с использованием дополнительного силового оборудования.</p>\r\n', 13, 0, 7, 1, 39, NULL, '2023-02-10 23:10:49', '2023-02-10 23:12:03'),
(8405, 10, '2023-02-14', '11:00:00', 0, 1, 0, '<p>Групповые силовые тренировки, направленные на укрепление мышц ног, ягодиц и живота. Рекомендуется для всех уровней подготовленности</p>\r\n', 8, 0, 6, 1, 61, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8406, 10, '2023-02-14', '19:00:00', 0, 1, 0, '<p>Силовой урок Upper Body направлен на развитие мышц верхней части тела: рук, плечевого пояса, спины и брюшного пресса. Для всех уровней подготовленности</p>\r\n', 7, 0, 6, 1, 35, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8407, 10, '2023-02-14', '20:00:00', 0, 1, 0, '<p>Как получить тело своей мечты? Вы можете сами как трудолюбивый скульптор вылепить его с помощью тренировок &laquo;Super Sculpt&raquo;. Это новый вид аэробики высокой интенсивности с большими физическими нагрузками.</p>\r\n\r\n<p>Этот вид аэробики, воздействуя на все группы мышц, словно скульптор лепит ваше тело, совершенствуя его. &laquo;Super Sculpt&raquo; выбирают как мужчины, так и женщины.</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/hZabOEB_Gvg\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/RoLozEqpwag\" width=\"640\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><iframe allowfullscreen=\"\" frameborder=\"0\" height=\"360\" src=\"https://www.youtube.com/embed/-Sn8TIaN6v8\" width=\"640\"></iframe></p>\r\n', 79, 0, 7, 1, 35, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8408, 10, '2023-02-14', '21:00:00', 0, 1, 1, '<p>Новое занятие!&nbsp;</p>\r\n', 89, 0, 7, 1, 35, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8409, 10, '2023-02-15', '10:00:00', 0, 1, 0, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, 61, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8410, 10, '2023-02-15', '20:00:00', 0, 1, 0, '<p>Занятие танцевальной аэробикой, которое включает в себя элементы танго, вальса, фокстрота. Для всех уровней подготовленности</p>\r\n', 23, 0, 8, 1, 54, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8411, 10, '2023-02-15', '21:00:00', 0, 1, 0, '<p>Занятие для всех уровней подготовленности. Направлено на растягивание и расслабление мышц, развитие гибкости, подвижности суставов и эластичности связок.</p>\r\n', 15, 0, 7, 1, 54, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8412, 10, '2023-02-16', '10:00:00', 0, 1, 0, '<p>Силовой урок для всех мышечных групп с использованием оборудования и без него.&nbsp;<br />\r\nВ отличие от других силовых занятий, здесь упражнения складываются в комбинацию, что делает это занятие не только эффективным, но и интересным.&nbsp;<br />\r\nВ процессе занятия тренируются взрывная сила, координация, ловкость, баланс.&nbsp;<br />\r\nВ упражнениях задействовано максимально возможное количество мышц-стабилизаторов. Рекомендуется тем, кто уже имеет опыт тренировок.</p>\r\n', 25, 0, 9, 1, 67, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
(8413, 10, '2023-02-16', '19:45:00', 0, 1, 0, '<p>Силовой урок с использованием большого гимнастического мяча. Позволяет укреплять мышечный корсет, исключая нагрузку на позвоночник и суставы. Рекомендуется для всех уровней подготовленности.</p>\r\n\r\n<p><strong>Требуется предварительная запись!</strong></p>\r\n', 11, 0, 7, 1, 39, NULL, '2023-02-10 23:10:49', '2023-02-10 23:10:49'),
