INSERT INTO `services` (`id`, `status`, `position`, `title`, `img`, `content`, `alias`, `meta_title`, `meta_keywords`, `meta_description`, `created_at`, `updated_at`) VALUES
(1, 10, 10, 'Персональный тренинг', 'personal-1556300113.jpg', '<p>Индивидуальные занятия с инструктором, особенно на начальном этапе, позволят Вам быстрее адаптироваться в Клубе, познакомиться с оборудованием, почувствовать атмосферу Клуба.<br>\r\nПри проведении персональных тренировок инструктор максимально учитывает индивидуальные особенности Вашего организма, а также контролирует технику выполнения упражнений, правильное дыхание при выполнении упражнений, объясняет, над какой группой мышц Вы работаете в данный момент. Инструктор помогает сконцентрироваться на тренировке и физической работе, что ускорит достижение результата.</p>\r\n', 'personal_training', 'Персональные тренировки в фитнес-клубе Extra Sport на Матроса Железняка', 'Персональные тренировки', 'Индивидуальные занятия с инструктором, особенно на начальном этапе, позволят Вам быстрее адаптироваться в Клубе, познакомиться с оборудованием, почувствовать атмосферу Клуба.', '2019-04-08 07:47:59', '2020-02-20 08:22:48'),
(2, 0, 30, 'Бассейн', 'pool-1556300318.jpg', '<p>Занятия плаванием важны как для детей так и для взрослых</p>\r\n', 'bassejn', 'Бассейн', '', '', '2019-04-08 07:47:59', '2019-11-15 09:38:37'),
(3, 10, 40, 'Детский Клуб', 'kids-1556300362.jpg', '<p>Детский фитнес позволяет направить активность ребёнка в нужное русло</p>\r\n', 'detskij-klub', 'Детский Клуб', '', '', '2019-04-08 07:47:59', '2019-04-26 17:39:22'),
(4, 10, 20, 'Групповые программы', 'group_prog-1556300170.jpg', '<p>Популярность занятий фитнесом не случайна &mdash; они помогают решить целый комплекс задач. Не всем от природы дана идеальная фигура и железное здоровье. Однако стоит приложить определенные усилия.<br />\r\n<br />\r\nЕдинственным и гарантированным способом, позволяющим изменить форму и объемы своего тела и, главное, закрепить полученный результат являются регулярные занятия фитнесом, подкрепленные правильным режимом питания и психологическим настроем. Регулярное движение активизирует обмен веществ, помогает снизить вес, вырабатывает выносливость, повышает мышечный тонус.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Огромный выбор занятий;</p>\r\n\r\n<p>профессиональные тренеры;</p>\r\n\r\n<p>групповые и индивидуальные программы;</p>\r\n\r\n<p>дружеская атмосфера;</p>\r\n\r\n<p>индивидуальный подход к каждому.</p>\r\n\r\n<p><br />\r\nРегулярные занятия фитнесом являются лучшей профилактикой многих заболеваний. Они заставляют сердце и сосуды постоянно работать, адаптируясь к возрастающим нагрузкам. Поэтому сердечно-сосудистая система тренированного человека работает слаженно и эффективно, обеспечивая кислородом все органы и ткани организма.<br />\r\n<br />\r\nСтарение нельзя предотвратить, но замедлить этот процесс вполне возможно, и в этом Вам помогут занятия фитнесом. Тренируйте ваше сердце, развивайте силу, гибкость, выносливость &mdash; тогда Вы всегда будете выглядеть и чувствовать себя гораздо моложе.<br />\r\n<br />\r\nГрупповые программы в нашем клубе &mdash; это красота, здоровье, семья, отдых, друзья и общение. Занимаясь фитнесом, Вы получаете радость, удовольствие, ведете активный образ жизни.</p>\r\n', 'programs', 'Групповые программы', '', '', '2019-04-08 07:47:59', '2019-04-26 17:36:10'),
(5, 10, 50, 'Боевые искусства', 'fight-1556300447.jpg', '<p>Боевые искусства пользуются весьма большим спросом и&nbsp;предполагают, что участники состязаются вдвоем, один на один, без применения какого либо&nbsp;оружия.</p>\r\n', 'boevye-iskusstva', 'Боевые искусства в фитнес-клубе Extra Sport', 'Боевые искусства', 'Тренировки по боевым искусствам для взрослых и детей в фитнес-клубе Extra Sport на Матроса Железняка. Тренировки проводят профессиональные тренера по боевым видам спорта. Запись по телефону! ', '2019-04-26 17:40:47', '2020-02-20 08:31:16'),
(6, 0, 60, 'Игровой зал', 'game-1556300535.jpg', '<p>Настольный теннис&nbsp;&ndash; отличный способ интересно провести время, укрепить здоровье и найти новых друзей! Эта увлекательная игра позволяет:</p>\r\n\r\n<p>поддерживать мышцы в тонусе,</p>\r\n\r\n<p>удовлетворить соревновательные потребности,</p>\r\n\r\n<p>дать организму гармоничную нагрузку,</p>\r\n\r\n<p>активно отдыхать, отвлекаясь от повседневных проблем.</p>\r\n\r\n<p>Настольный теннис, или пинг-понг, увлекает динамикой и азартом, равными возможностями для людей разного достатка и социального статуса. Недаром у настольного тенниса есть поклонники разного возраста, сферы деятельности и пола.</p>\r\n\r\n<p>Сеть фитнес клубов Extra Sport предлагает своим посетителям без каких-либо ограничений играть в настольный теннис! Пользование столом и ракетками входит в стоимость абонемента на посещение зала, поэтому доплачивать вам не придется! Наш фитнес клуб дарит бесплатное удовольствие всем своим посетителям.</p>\r\n\r\n<p>Играть не только интересно, но и полезно&nbsp;&nbsp; &nbsp;</p>\r\n\r\n<p>Партию в настольный теннис можно рассматривать, как полноценную спортивную тренировку. Игра:</p>\r\n\r\n<p>требует отличной реакции,</p>\r\n\r\n<p>помогает отточить мышечную работу,</p>\r\n\r\n<p>улучшает координацию.</p>\r\n\r\n<p>В результате отслеживания полета теннисного меча &ndash; полезной гимнастики для глаз и парирования шарика на сторону противника организм получает полезную нагрузку. Помимо общеукрепляющего эффекта игра дарит положительные эмоции, так как там, где царит азарт, не остается места для негативных мыслей. Пинг-понг практически не имеет &nbsp;противопоказаний, так как требует несложных движений, разнообразных по силе.</p>\r\n\r\n<p>Немного медицинских фактов:</p>\r\n\r\n<p>Игра тренирует подвижность кистей, развивает моторику рук.</p>\r\n\r\n<p>Эта игра развивает внимание и реакцию, тренирует мышцы рук, ног, спины, живота.</p>\r\n\r\n<p>Во время несложных локтевые и коленные суставы получают необходимую нагрузку, чтобы без риска травматизма &laquo;разрабатываться&raquo;.</p>\r\n\r\n<p>Во время игры развивается дыхательная системы, укрепляется сердечная мышца и сосудистая система.</p>\r\n\r\n<p>У людей, регулярно играющих в настольный теннис, наблюдается нормализация артериального давления.</p>\r\n\r\n<p>Поклонники игры реже страдают от депрессий и устойчивы к стрессам.</p>\r\n\r\n<p>Ежедневные непродолжительные занятия пинг-понгом рекомендованы для людей любого возраста и уровня спортивной подготовки, а регулярные тренировки позволяют повысить навыки мастерства, проявить которые можно во время турниров, проводимых нашим фитнес клубом. А победители таких соревнований получают призы и абонемент на посещение спортивного зала! Сеть фитнес-клубов Extrasport ждет поклонников настольного тенниса. До встречи за столом!</p>\r\n', 'igrovoj-zal', 'Игровой зал', '', '', '2019-04-26 17:42:15', '2020-02-20 08:21:58'),
(7, 0, 70, 'Студия йоги ', NULL, '<p>Yoga power YOGA Power &nbsp;базируется на практике - Аштанга йога (также известная как Аштанга Виньяса йога)&nbsp;<br>\r\nЭто мощная система, основанная на синхронизации дыхания с движением, с возрастающей сложностью асан (поз) и движениями-переходами, целью которой в итоге является достижение медитативного состояния - медитация в движении.<br>\r\nYOGA Power&nbsp;- настолько динамичный и красивый стиль, что покоряет любого, кто ищет способ быстрого достижения отличной физической и ментальной формы.<br>\r\n<br>\r\n✅хатка йога<br>\r\nОсновная идея хатха-йоги &ndash; развитие гибкости. Каждая асана воздействует на конкретные органы. Пребывая в той или иной асане, необходимо ощутить расслабление, чем достигается просветление ума. Упражнения хатха-йоги способствуют решению проблем с позвоночником и суставами, а также множество других недугов, так как каждая асана имеет всеобъемлющее действие. Не пытайтесь достичь всего сразу &ndash; получайте удовольствие, постепенно улучшайте результат, постигайте древнюю философию (при желании). Со временем вы заметите, что стали чувствовать себя лучше, обрели собранность, дисциплинировали ум, стабилизировали эмоциональное состояние.<br>\r\n<br>\r\n✅Aero yoga<br>\r\nАнтигравити йога &nbsp;&ndash; это занятия классической Хатха Йоги, перенесенные на гамак. Название от английского Aeroyoga in hammoc, воздушная йога в гамаках. В гамаке начинают работать мышцы, которые в повседневной жизни не работают. Упражнения запускают все действия в организме, иммунную систему, репродуктивную, нормализуется гормональный фон у женщин, сердечно-сосудистую систему, вестибулярный аппарат &ndash; это отмечается уже на 4-5 занятии. Перевернутые асаны запускают омолаживающий процесс в организме, улучшается цвет лица, мышцы становятся более упругими.</p>\r\n', 'studia-jogi', 'Студия йоги ', '', '', '2020-09-25 07:59:19', '2020-09-25 08:00:04');
