(31, 0, 220, 0, 'Марафон летних скидок! ', 'До 21 июля  ', '', '+6 месяцев в подарок!', 'rasprodaz,-kopia,-kopia,-kopia,-kopia-(1)-1654858944.jpg', '<p>Количество абонементов ограничено!!!</p><p>Подробности и бронь в отделе продаж и по телефону: +7 (812) 207-50-07</p><p>&nbsp;</p><p>Что вы получаете:</p><p>Полный доступ во все зоны клуба (силовая, кардио, cycle-студия)</p><p>Просторный и современный тренажёрный зал</p><p>Турецкий хаммам</p><p>Тренерскую поддержку и возможность персональных занятий.</p><p>Фитнес-бар</p><p>Детская комната, в которой вы сможете оставить ребёнка на время посещения фитнес клуба!</p>', NULL, 'kosmos', 'Марафон летних скидок! ', '', '', '2020-10-27 05:07:38', '2022-07-18 15:02:58'),
(33, 10, 330, 0, 'Набор мужчин и женщин на занятия Боксом!', 'Групповые занятия', '', 'Бокс- отличный способ развить тело и дух!', '14d38b32-1605520957.jpg', '<p>Проходит набор мужчин и женщин на групповые занятия боксом.</p><p>Записывайтесь на занятия по телефону: +7 (812) 207-50-07<br><a href=\"https://youtu.be/hvf9p-iySEI\"><strong>Видео презентация</strong></a><strong>&nbsp;</strong><br>&nbsp;</p>', NULL, 'nabor-muzcin-i-zensin-na-zanatia-boksom', 'Набор мужчин и женщин на занятия Боксом!', '', '', '2020-11-16 10:02:37', '2023-04-21 09:15:53'),
