(51, 10, 410, 1, 'Дарим Бесплатный Абонемент +Тренировка с Тренером!', 'До 2 июля', '', 'Хороший старт!', 'sport-fitness-1647264395.jpg', '<p>Количество абонементов ограничено!!!</p><p>Подробности в отделе продаж!&nbsp;</p><p>Подробности и бронь в отделе продаж и по телефону: +7 (812) 207-50-07</p><p>&nbsp;</p><p>Что вы получаете:</p><p>Полный доступ во все зоны клуба (силовая, кардио, cycle-студия)</p><p>Просторный и современный тренажёрный зал</p><p>Турецкий хаммам</p><p>Тренерскую поддержку и возможность персональных занятий.</p><p>Фитнес-бар</p><p>Детская комната, в которой вы сможете оставить ребёнка на время посещения фитнес клуба!</p>', NULL, 'darim-besplatnyj-abonement-trenirovka-s-trenerom', 'Дарим Бесплатный Абонемент +Тренировка с Тренером!', '', '', '2022-03-14 13:26:35', '2023-06-27 11:29:52'),
