INSERT INTO `share_params` (`id`, `text`, `meta_title`, `meta_keywords`, `meta_description`) VALUES
(1, '', 'Акции фитнес клуба Exrta Sport на Матроса Железняка', 'акции в фитнес-клубе ', 'Годовой абонемент в фитнес клуб со скидкой до 50%. Предложение ограничено, запись по телефону. Приглашаем всех в наш фитнес клуб.');
INSERT INTO `trainers` (`id`, `status`, `position`, `title`, `post`, `img`, `content`, `alias`, `meta_title`, `meta_keywords`, `meta_description`, `created_at`, `updated_at`) VALUES
(35, 10, 30, 'КУЛАКОВ ВИКТОР', 'ТРЕНЕР ГРУППОВЫХ ЗАНЯТИЙ', 'photo1649856899-1649925063.png', '<p>Тренер групповых программ<br>\r\n<br>\r\nЗаслуги и достижения:<br>\r\nЛичный стаж: с 2009 года Стаж работы: с 2012 года<br>\r\n<br>\r\nОбразование:<br>\r\n*Студия FSC<br>\r\n*Академия фитнеса<br>\r\n<br>\r\nПрограммы и направления:<br>\r\n*Cycle<br>\r\n*Силовые классы аэробики</p>\r\n', 'kulakov-viktor', 'КУЛАКОВ ВИКТОР', '', '', '2020-08-12 13:36:32', '2022-04-14 08:31:04'),
(36, 10, 40, 'ПАХОМОВ ДМИТРИЙ', 'ТРЕНЕР ГРУППОВЫХ ПРОГРАММ', 'WhatsApp-Image-2022-04-18-at-12.30.09-1650275669.png', '<p>Подразделение :аэробный ,тренажёрный зал.<br>\r\nФитнес форматы:силовые классы,растяжка,функциональные классы,сайкл.<br>\r\nПерсональные тренировки:тренажёрный зал, круговые тренировки ,работа над снижением веса ,набором мышечной массы,работа на общее укрепление мышц и развитие двигательных навыков.</p>\r\n\r\n<p>Образование:высшее(университет им .Лесгафта)<br>\r\nФитнес образование(университет фитнеса )</p>\r\n\r\n<p>Достижения :<br>\r\nкмс по дзюдо и самбо<br>\r\nПобедитель и финалист турнира &ldquo;IFO&rdquo; по фитнесу в подразделении (функциональный класс,степ аэробика)<br>\r\nУчастник финала Mioff конвенции в г.Москва .</p>\r\n', 'pahomov-dmitrij', 'ПАХОМОВ ДМИТРИЙ', '', '', '2020-08-12 14:00:52', '2022-04-18 09:55:25'),
(38, 0, 60, 'Николаева Татьяна', 'Тренер групповых программ', 'WhatsApp-Image-2020-10-06-at-13.30.55-1601989603.png', '<p>Николаева Татьяна&nbsp;<br>\r\nТренер по бальным танцам (класс А , прошла семинары ведущих танцоров России и мира( К. Пшеничных, С.Рюпин, Е.Хворова, И.Данилов).</p>\r\n\r\n<p>Сертифицированный тренер mind body (пилатес, стретчинг ), обучалась в Fitness Profi.</p>\r\n\r\n<p>Инструктор групповых программ ( обучение в Анатомия)<br>\r\nДоп. обучения:<br>\r\nЗдоровая спина в бассейне,&nbsp;<br>\r\nTrx ( обучение в spf_n1)<br>\r\nКонвенция myfitlab (семинары Е.Волкова, Amy &nbsp;Taylor)<br>\r\nСеминары в vp fitness consulting: коррекция осанки, тренировки для беременных, диагностика опорно-двигательного аппарата. Реабилитология: заболевания позвоночника.<br>\r\nПрошла обучение - фундаментальные знания о проблемах набора и снижения веса ( школа фитнеса и бодибилдинга Павла Ершова)</p>\r\n', 'nikolaeva-tatana', 'Николаева Татьяна', '', '', '2020-10-06 13:06:43', '2022-04-18 10:08:52'),
(39, 10, 70, 'Степанова Элла', 'Тренер групповых прграмм', 'WhatsApp-Image-2022-04-18-at-12.40.32-1650276463.png', '<p>Тренер групповых программ<br>\r\nПерсональный тренер</p>\r\n\r\n<p>▪️Мастер спорта по художественной гимнастике</p>\r\n\r\n<p>▪️Образование:<br>\r\nСертифицированный тренер &quot;Pilates Institute&quot; г. Москва&nbsp;</p>\r\n\r\n<p>Университет Фитнес Технологий UFT г. Санкт-Петербург&nbsp;</p>\r\n\r\n<p>Международный центр профессионального образования Fitness - Profi. Тренер по фитнесу международного класса</p>\r\n\r\n<p>Семинары и курсы студии &quot;Анатомия&quot;&nbsp;<br>\r\nг. Москва&nbsp;</p>\r\n\r\n<p>&nbsp;Групповые тренировки по направлениям Pilates, силовые классы, Step, Flex, TRX</p>\r\n', 'stepanova-ella', 'Степанова Элла', '', '', '2020-10-06 13:11:17', '2022-04-18 10:07:44'),
(40, 0, 80, 'Мария Онищенко', 'Тренер групповых прграмм', 'Masa-Onisenko-Iun-2-1556294864-1601990245.jpg', '<p>Высшее образование: Российский государственный педагогический университет им. А.И. Герцена, специальность маркетинг в сфере услуг&nbsp;</p>\r\n\r\n<p>Курсы: УНИВЕРСИТЕТ ФИТНЕС-ТЕХНОЛОГИЙ НА БАЗЕ ССК &quot;OLYMP&raquo; - Инструктор групповых программ по направлениям аэро и степ 1-3 уровней, силовые интервальные классы, пилатес, функциональный тренинг, сайкл, растяжка&nbsp;</p>\r\n\r\n<p>&nbsp;С 01.2018 г. Инструктор проекта &laquo;гонка героев&raquo;</p>\r\n\r\n<p>2018 - чемпион кубка стран Балтии &laquo;пауэрлифтинг без экипировки&raquo; (WPC/AWPC)</p>\r\n\r\n<p>2018 - чемпион Европы &laquo;пауэрлифтинг без экипировки&raquo; (GPA/IPO)</p>\r\n\r\n<p>2017- чемпион Восточной Европы &laquo;силовое двоеборье без экипировки&raquo;(IPL)</p>\r\n\r\n<p>2016г. спортсмен в номинации фитнес-бикини&nbsp;</p>\r\n\r\n<p>Призер 2014г. : Санкт-Петербургский открытый танцевальный фестиваль современной хореографии START DANCE&nbsp;</p>\r\n\r\n<p>Призер 2014 г.: International dance competitioms Aphrodiziac&nbsp;</p>\r\n\r\n<p>Призер 2014г.: Всероссийский конкурс &laquo;CRYSTAL SHOW&raquo;&nbsp;</p>\r\n\r\n<p>Призер 2014г.: Drive Dance fest&nbsp;</p>\r\n\r\n<p><b>&nbsp;Стаж преподавания в спорте: с 2014 (растяжка), с июня 2015 инструктор групповых программ&nbsp;</b></p>\r\n\r\n<p>&nbsp;Сила в движении: не взирая ни на что и ни на кого, действуй, ведь цель намного ближе, чем ты думаешь.</p>\r\n', 'maria-onisenko', 'Мария Онищенко', '', '', '2020-10-06 13:17:25', '2022-04-18 10:08:38'),
(51, 10, 190, 'Бухарина Валерия', 'Тренер групповых программ', 'WhatsApp-Image-2022-04-18-at-12.39.52-1650275885.png', '<p>Тренер групповых программ Йога</p>\r\n\r\n<p>Заслуги и достижения:<br>\r\nЛичная практика йоги с 2017 года.&nbsp;</p>\r\n\r\n<p>Успешно прошла:<br>\r\n-курс Хатха йога Федерации йоги России 200 часов -2020 год</p>\r\n\r\n<p>&nbsp;-две ступени курса Универсальная Йога А.В Лаппа, 200 часов- 2021 год.</p>\r\n', 'buharina-valeria', 'Бухарина Валерия', '', '', '2022-01-30 22:42:38', '2022-04-18 09:58:06'),
(52, 10, 200, 'Епифанов Денис', 'Тренер групповых программ', 'photo1649856916-1649925096.png', '<p>Епифанов Денис Николаевич<br>\r\nОбразование высшее<br>\r\n&quot;НАЦИОНАЛЬНЫЙ ГОСУДАРСТВЕННЫЙ УНИВЕРСИТЕТ ФИЗИЧЕСКОЙ КУЛЬТУРЫ, СПОРТА И ЗДОРОВЬЯ ИМЕНИ П.Ф.ЛЕСГАФТА&quot;<br>\r\nТренерско-педагогический стаж 10 лет<br>\r\nКМС по боксу</p>\r\n', 'epifanov-denis', 'Епифанов Денис', '', '', '2022-01-30 22:43:20', '2022-04-14 08:31:37'),
(53, 10, 210, 'Гулина Ксения', 'Тренер групповых программ', 'photo1649856938-1649925129.png', '<p>Инструктор групповых программ<br>\r\n<br>\r\nЛичный стаж: с 2014 года<br>\r\nСтаж работы: с 2018 года<br>\r\n<br>\r\nОбразование и курсы:<br>\r\n- Zumba &nbsp;Fitness LLC:<br>\r\nZumba, Zumba Kids, Aqua Zumba, Strong Nation<br>\r\nЧОУ ДПО &quot;Национальный университет фитнеса&quot;:<br>\r\nИнструктор-универсал групповых программ<br>\r\nСеминары:<br>\r\nPower training, Functional training, Cycle<br>\r\nЦДПО &quot;Продвижение&quot;:<br>\r\nСпециалист по движению<br>\r\n<br>\r\nНаправления:<br>\r\nZumba<br>\r\nZumba Kids<br>\r\nAqua Zumba<br>\r\nStrong Nation<br>\r\nАквафитнес<br>\r\nСиловой тренинг<br>\r\nStretching</p>\r\n', 'gulina-ksenia', 'Гулина Ксения', '', '', '2022-01-30 22:44:12', '2022-04-14 08:32:10'),
(54, 10, 220, 'Баранова Екатерина', 'Тренер групповых программ', '', '<p>Тренер групповых программ</p>\r\n', 'baranova-ekaterina', 'Баранова Екатерина', '', '', '2022-01-30 22:44:53', '2022-01-30 22:44:53'),
(55, 10, 230, 'Иванова Татьяна', 'Тренер групповых программм', 'photo1649856966-(1)-1649925257.png', '<p>Тренер групповых программ<br>\r\n<br>\r\nЗаслуги и достижения:<br>\r\nЛичная практика с 1997 года;<br>\r\nСтаж работы тренером с 2006 года.<br>\r\nОбразование: Российский Государственный Педагогический Университет им. А. И. Герцена; Санкт-Петербургский Педагогический Колледж Фитнесса; Институт Исследования Кундалини.<br>\r\n<br>\r\nПрограммы и направления:<br>\r\nPilates,<br>\r\nStretching, aerostretching,<br>\r\nBelly dance,<br>\r\nYoga, aeroyoga.</p>\r\n', 'ivanova-tatana', 'Иванова Татьяна', '', '', '2022-04-14 08:15:38', '2022-04-14 08:34:18'),
(56, 10, 240, 'Сыртланова Алина', 'Тренер тренажерного зала', 'IMG_9363-1649944839.png', '<p>Работаю с женщинами и девушками любого возраста, здоровых или у которых есть ограничения (грыжи, протрузии, травма коленей, диастаз, варикозное расширение вен). У которых есть нарушение осанки, нарушения желудочно- кишечного тракта, повышенное или пониженное давление.</p>\r\n', 'syrtlanova-alina', 'Сыртланова Алина', '', '', '2022-04-14 14:00:39', '2022-04-14 14:00:39'),
(57, 10, 250, 'Мелехина Екатерина', 'Тренер тренажерного зала', 'IMG_9323-1649944987.jpg', '<p><br>\r\n<br>\r\nСпортивный стаж с 2009 г<br>\r\n<br>\r\nЗаслуги и достижения :<br>\r\n<br>\r\nЧемпионка Европы по Powerlifting Federation WPS/AWPC - 2015г.<br>\r\nПризёр кубка Носорог Pro в категории фитнес-бикини мастера ( 3е место ) - 2019г<br>\r\nПризёр кубка Носорог Pro в категории фитнес-бикини 169+ ( 3е место ) 2019г<br>\r\nЧемпионка зимнего турнира D&rsquo;Athletics в категории фитнес-бикини мастера ( 1е место ) 2019г<br>\r\nD&rsquo;Athletics в категории фитнес-бикини 169+ ( 1е место ) 2019г<br>\r\nПризёр Кубка Ленинградской области 2021 в категории фитнес-бикини мастера<br>\r\n<br>\r\nНаправления :<br>\r\nСнижение веса<br>\r\nСиловой тренинг<br>\r\nФункциональный тренинг<br>\r\nСоставление тренировочных программ<br>\r\nПодготовка к соревнованиям в категории фитнес-бикини<br>\r\nСоставление плана питания<br>\r\nРабота с детьми<br>\r\nКоррекция фигуры<br>\r\n<br>\r\nОбразование :<br>\r\nСанкт-Петербургский государственный университет физической культуры имени П.Ф. Лесгафта<br>\r\nСпециалист по физической культуре и спорту по специальности &laquo;физическая культура и спорт&raquo; 22 июня 2010<br>\r\n<br>\r\nЦентр подготовки тренеров &laquo;Анатомия&raquo;<br>\r\n&laquo;Персональный тренер&raquo;<br>\r\n&laquo;Консультант по спортивному питанию&raquo;</p>\r\n', 'melehina-ekaterina', 'Мелехина Екатерина', '', '', '2022-04-14 14:03:08', '2022-04-14 14:03:08'),
(58, 0, 260, 'Старосотникова Алина', 'Тренер тренажерного зала', 'IMG_9322-1649945064.jpg', '<p>&nbsp;</p>\r\n\r\n<p><br>\r\n<br>\r\nБронзовый призер Чемпионата Лен.области по фитнесу и бодибилдингу &lsquo;2019<br>\r\n<br>\r\nСпециализация:<br>\r\n-развитие силовых способностей и увеличение мышечной массы<br>\r\n-функциональный тренинг<br>\r\n-снижение массы тела за счет жирового компонента<br>\r\n-составление дневника питания<br>\r\n-составление индивидуальных программ тренировок<br>\r\n-работа с нарушениями опорно-двигательного аппарата<br>\r\n-тренировки во время беременности<br>\r\n-коррекция осанки<br>\r\n-миофасциальный релиз в фитнесе<br>\r\n-стретчинг<br>\r\n<br>\r\nСтаж тренировок с 2013 года<br>\r\nСтаж тренерской работы с 2019 года</p>\r\n', 'starosotnikova-alina', 'Старосотникова Алина', '', '', '2022-04-14 14:04:11', '2023-02-16 14:33:43'),
(59, 10, 270, 'Прокопов Александр', 'Тренер тренажерного зала', 'IMG_9447-1649945175.jpg', '<p><br>\r\nСтаж работы тренером 6 лет<br>\r\nАлтайский педагогический университет ( повышение квалификации) многократный участник фитнес конвенций<br>\r\nИмею множество сертификатов по направлениям:<br>\r\nДиетология<br>\r\nРеабилитация<br>\r\nМФР<br>\r\nРабота с детьми от 9 лет<br>\r\nНабор мышечной массы<br>\r\nСнижение жировой массы<br>\r\n<br>\r\nКМС по пауэрлифтингу( чемпион России) победитель Алтайского края по пауэрлифтингу<br>\r\n2 взрослый разряд по легкой атлетике</p>\r\n', 'prokopov-aleksandr', 'Прокопов Александр', '', '', '2022-04-14 14:06:16', '2022-04-14 14:06:16'),
(60, 10, 280, 'Кирилов Павел ', 'Тренер тренажерного зала', 'IMG_9416-1649945278.jpg', '<p><br>\r\n<br>\r\nРаботаю по направлению:<br>\r\nНабор мышечной массы<br>\r\nПохудение<br>\r\nРеабилитация после травм<br>\r\nРеабилитация после пластики<br>\r\nКоррекция осанки<br>\r\nРабота с подростками до 18 лет<br>\r\nРабота по функциональному тренингу</p>\r\n', 'kirilov-pavel', 'Кирилов Павел ', '', '', '2022-04-14 14:07:58', '2022-04-14 14:07:58'),
(61, 10, 290, 'Павлова Евгения', 'Тренер групповых программ', 'photo1649856983-(1)-1650277010.png', '<p>Инструктор групповых программ, персональный тренер тренажёрного зала.<br>\r\n<br>\r\nОбразование:<br>\r\n- высшее РАНХиГС, социология<br>\r\n- Колледж фитнеса и бодибилдинга имени Бена Вейдера<br>\r\n- Университет фитнес технологий г. Санкт-Петербур<br>\r\n- VP Fitness Consulting<br>\r\n<br>\r\nСпециализация , групповые программы: Cycle, PUMP, UPPER/LOWER body, HIIT, Tabata, круговые тренировки, TRX, Fitball, Bosu, Tae Bo, Stretching<br>\r\n<br>\r\nСпециализация, тренажёрный зал:<br>\r\n- тренировки на снижении жирового компонента;<br>\r\n- тренировки направленные на коррекцию тела;<br>\r\n- тренировки на развитие гибкости и эластичности мышц;<br>\r\n- консультации по питанию</p>\r\n', 'pavlova-evgenia', 'Павлова Евгения', '', '', '2022-04-18 10:16:51', '2022-04-18 10:16:51'),
(62, 10, 300, 'Иванов Александр', 'Тренер тренажерного зала', 'IMG_9426-(2)-1650289713.png', '<p>Образование Fitness Profi<br>\r\nСтаж работы 7 лет&nbsp;<br>\r\nСпециализация:&nbsp;<br>\r\nСиловой тренинг для женщин&nbsp;<br>\r\nСнижение веса за счёт жирового компонента&nbsp;<br>\r\nНабор мышечной массы</p>\r\n', 'ivanov-aleksandr', 'Иванов Александр', '', '', '2022-04-18 13:48:34', '2022-04-18 13:48:34'),
(63, 10, 310, 'Канева Светлана', 'Тренер', '', '<p>Канева Светлана</p>\r\n', 'kaneva-svetlana', 'Канева Светлана', '', '', '2022-07-27 08:44:35', '2022-07-27 08:44:35'),
(64, 10, 320, 'Шторм Анна', 'Тренер', '', '<p>Тренер</p>\r\n', 'storm-anna', 'Шторм Анна', '', '', '2022-11-06 21:47:12', '2022-11-06 21:47:12'),
(65, 10, 330, 'Яковишина Елена ', 'Тренер', '', '<p>Тренер<br>\r\n&nbsp;</p>\r\n', 'akovisina-elena', 'Яковишина Елена ', '', '', '2022-11-06 21:47:55', '2022-11-06 21:47:55'),
(66, 10, 340, 'Климкина Олеся ', 'Тренер', '', '<p>тренер</p>\r\n', 'klimkina-olesa', 'Климкина Олеся ', '', '', '2022-11-06 21:48:11', '2022-11-06 21:48:11'),
(67, 10, 350, 'Богданова Юлия', 'Тренер', '', '<p>тренер</p>\r\n', 'bogdanova-ulia', 'Богданова Юлия', '', '', '2022-11-06 21:48:33', '2022-11-06 21:48:33'),
(68, 10, 360, 'Александр Никитин', 'Тренер тренажерного зала', '', '<p>Александр Никитин</p>\r\n', 'aleksandr-nikitin', 'Александр Никитин', '', '', '2023-02-08 10:51:08', '2023-02-08 10:51:08'),
(69, 10, 370, 'Выступов Даниил', 'Тренер тренажерного зала', 'photo1669901414-(1)-1676559110.jpg', '<p>Выступов Даниил<br>\r\n<br>\r\nОбразование:<br>\r\n- Школа фитнеса &quot;Анатомия&quot;.<br>\r\n- Академия Реабилитации ЛФК.<br>\r\n- Курс от Алексея Мирко &laquo;Профессионал по биомеханике&raquo;:<br>\r\n1. Оценка подвижности суставов<br>\r\n2. Обследование компенсаций движения<br>\r\n3. Обнаружение и устранение дисфункций<br>\r\n<br>\r\nТренерский стаж с 2020гг.<br>\r\n<br>\r\nРазработка сплит-программ, основанных на классическом бодибилдинге.<br>\r\n<br>\r\nСнижение веса, коррекция фигуры, силовой тренинг набор массы.<br>\r\n<br>\r\nГТО подготовка и вывод на соревнования.<br>\r\n<br>\r\nТренинг подростков и людей с ограничениями по здоровью (протрузии, грыжи, разрыв менисков, сколиоз, кифоз, гипертония)<br>\r\n<br>\r\nИндивидуальное составление плана питания</p>\r\n', 'vystupov-daniil', 'Выступов Даниил', '', '', '2023-02-16 14:51:50', '2023-02-16 14:51:50'),
(70, 10, 380, 'Рогаткина Владлена', 'Тренер тренажерного зала', 'Bez-nazvania-(2)-(1)-1676559282.png', '<p>Рогаткина Владлена<br>\r\n<br>\r\nОбразование:<br>\r\nСибирский государственный университет физической культуры и спорта: тренер спортсменов высокой квалификации, тренер инструктор.<br>\r\n<br>\r\nТренировочный стаж 14 лет<br>\r\n<br>\r\nСпортивные регалии:<br>\r\nМастер спорта по конькобежному спорту<br>\r\nЧемпионка мира<br>\r\nМногократная чемпионка и призерка России<br>\r\n<br>\r\nКвалификация: персональный тренер тренажерного зала<br>\r\nСпециализация:<br>\r\nКоррекция веса<br>\r\nНабор мышечной массы<br>\r\nФункциональный и силовой тренинг</p>\r\n', 'rogatkina-vladlena', 'Рогаткина Владлена', '', '', '2023-02-16 14:54:42', '2023-02-16 14:54:42'),
(71, 10, 390, 'Зверев Павел', 'Тренер тренажерного зала', 'photo1673351375-(1)-1676559381.jpg', '<p>Зверев Павел<br>\r\n<br>\r\n-снижение веса<br>\r\n-набор мышечной массы<br>\r\n-развитие силовых показателей<br>\r\n-коррекция пропорций<br>\r\n-составление плана питания и тренировок<br>\r\n<br>\r\nКМС по пауэрлифтингу<br>\r\nДействующий спортсмен по бодибилдингу<br>\r\nПризёр соревнований в классическом бодибилдинге<br>\r\n<br>\r\nСтаж работы 6 лет</p>\r\n', 'zverev-pavel', 'Зверев Павел', '', '', '2023-02-16 14:56:21', '2023-02-16 14:56:21'),
(72, 10, 400, 'Александра Никитина', 'Тренер групповых программ', '', '<p>Тренер групповых программ</p>\r\n', 'aleksandra-nikitina', 'Александра Никитина', '', '', '2023-02-28 11:25:59', '2023-02-28 11:25:59'),
(73, 10, 410, 'Устинова София', 'Тренер групповых программ', '', '<p>Тренер групповых программ</p>\r\n', 'ustinova-sofia', 'Устинова София', '', '', '2023-03-05 19:06:37', '2023-03-05 19:06:37'),
(74, 10, 420, 'Дарья Ефимова', 'Тренер групповых программм', '', '<p>Тренер групповых программм</p>\r\n', 'dara-efimova', 'Дарья Ефимова', '', '', '2023-05-15 10:34:27', '2023-05-15 10:34:27');
